{
  "name": "QUILTA - Qualitative Research App",
  "description": "A tablet-native qualitative research tool for students, featuring sentence-level coding, transcript management, and academic reporting.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export interface Profile {
  id: string;
  email: string;
  full_name: string;
}

export interface Project {
  id: string;
  title: string;
  description: string;
  owner_id: string;
  created_at: string;
}

export interface Interview {
  id: string;
  project_id: string;
  title: string;
  transcript: string; // Raw text or JSON segments
  audio_url?: string;
  duration?: string;
  created_at: string;
  sentences: string[]; // Processed for coding
}

export interface Code {
  id: string;
  project_id: string;
  label: string;
  color: string;
  created_by: string;
}

export interface CodedSegment {
  id: string;
  interview_id: string;
  code_id: string;
  segment_text: string;
  sentence_index: number;
}

export type AppView = 
  | 'AUTH' 
  | 'PROJECTS' 
  | 'CREATE_PROJECT' 
  | 'PROJECT_DETAIL' 
  | 'RECORD_INTERVIEW' 
  | 'INTERVIEW_DETAIL' 
  | 'CODING' 
  | 'EXPORT';

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const transcribeText = async (rawInput: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Break the following qualitative interview transcript into a clean list of individual sentences. Keep the exact meaning. Remove stutters like "um" or "uh" to make it research-ready. Output as a JSON array of strings.

      Transcript:
      ${rawInput}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const jsonStr = response.text || '[]';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    // Fallback to basic splitting if API fails
    return rawInput.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: string[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => `Code: ${c.label}\nQuotes:\n- ${c.segments.join('\n- ')}`).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a qualitative research assistant. Based on the following coded segments for the project "${projectTitle}", write a high-level summary report identifying key themes and patterns. Use academic but accessible language.

      Data:
      ${context}`,
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

import { Project, Interview, Code, CodedSegment, Profile } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: string[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.join(' '),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    // Check for existing coding on same sentence/code to avoid duplicates
    const filtered = segments.filter((s: CodedSegment) => 
      !(s.interview_id === segment.interview_id && 
        s.code_id === segment.code_id && 
        s.sentence_index === segment.sentence_index)
    );
    set(STORAGE_KEYS.CODED_SEGMENTS, [...filtered, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

