          </div>
          <div>
            <label className="block text-lg font-bold mb-3 text-slate">Paste Raw Transcript</label>
            <p className="text-sm text-charcoal/40 mb-3">QUILTA will use AI to clean and segment your transcript for sentence-level coding.</p>
            <textarea 
              value={rawText}
              onChange={e => setRawText(e.target.value)}
              rows={10} 
              placeholder="Paste the raw interview text here..." 
              className="w-full p-6 rounded-2xl border-2 border-slate/10 focus:border-terracotta outline-none text-lg resize-none" 
            />
          </div>
          <button 
            onClick={handleProcess}
            disabled={isProcessing}
            className={`w-full h-14 bg-terracotta text-white rounded-2xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 ${isProcessing ? 'opacity-50 cursor-not-allowed' : 'btn-bounce'}`}
