import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const transcribeText = async (rawInput: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Break the following qualitative interview transcript into a clean list of individual sentences. Keep the exact meaning. Remove stutters like "um" or "uh" to make it research-ready. Output as a JSON array of strings.

      Transcript:
      ${rawInput}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const jsonStr = response.text || '[]';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    return rawInput.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  }
};

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      contents: [
        {
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        },
        {
          text: "Please provide a high-quality transcription of this interview. Once transcribed, break it into a JSON array of clean, research-ready sentences. Remove filler words."
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const jsonStr = response.text || '[]';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return ["Error transcribing audio. Please ensure the file is a valid audio format."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: string[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => `Code: ${c.label}\nQuotes:\n- ${c.segments.join('\n- ')}`).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a qualitative research assistant. Based on the following coded segments for the project "${projectTitle}", write a high-level summary report identifying key themes and patterns. Use academic but accessible language.

      Data:
      ${context}`,
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

