        }
      >
        <div className="space-y-8">
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1">
              <h2 className="text-3xl font-bold text-slate mb-6">Interviews ({interviews.length})</h2>
              {interviews.length === 0 ? (
                <div className="bg-white/50 border-2 border-dashed border-slate/10 rounded-3xl p-12 text-center text-slate/40">
                  <p className="text-lg">No interviews added yet.</p>
                  <button onClick={() => setView('RECORD_INTERVIEW')} className="mt-4 text-terracotta font-bold underline">Add your first interview</button>
                </div>
              ) : (
                <div className="space-y-4">
                  {interviews.map(i => (
                    <div 
                      key={i.id} 
                      onClick={() => openInterview(i)}
                      className="bg-white p-5 rounded-2xl flex items-center justify-between border-2 border-transparent hover:border-sage shadow-sm hover:shadow-md transition-all cursor-pointer group"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-sage/10 rounded-lg flex items-center justify-center text-sage">
                          <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                        </div>
                        <div>
                          <h4 className="font-bold text-slate">{i.title}</h4>
                          <p className="text-xs text-charcoal/40">{new Date(i.created_at).toLocaleDateString()}</p>
                        </div>
                      </div>
                      <svg className="w-5 h-5 text-slate/20 group-hover:text-sage transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="w-full md:w-80">
              <h2 className="text-3xl font-bold text-slate mb-6">Codebook</h2>
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate/10 space-y-4">
                {codes.length === 0 && <p className="text-slate/40 text-sm italic">Codes will appear here as you start analyzing.</p>}
                {codes.map(c => (
                  <div key={c.id} className="flex items-center gap-3">
                    <div className="w-4 h-4 rounded-full" style={{ backgroundColor: c.color }} />
                    <span className="font-semibold text-slate">{c.label}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </Layout>
    );
  }

  if (view === 'RECORD_INTERVIEW' && currentProject) {
    const [title, setTitle] = useState('');
    const [rawText, setRawText] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);
    const [uploadMode, setUploadMode] = useState<'text' | 'audio'>('text');
    const [audioFile, setAudioFile] = useState<File | null>(null);

    const handleProcess = async () => {
      if (!title) return;
      setIsProcessing(true);

      let sentences: string[] = [];
      if (uploadMode === 'text') {
        if (!rawText) return;
        sentences = await transcribeText(rawText);
      } else {
        if (!audioFile) return;
        const reader = new FileReader();
        reader.readAsDataURL(audioFile);
        const base64Promise = new Promise<string>((resolve) => {
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
        });
        const base64 = await base64Promise;
        sentences = await transcribeAudio(base64, audioFile.type);
      }

      const interview = dbService.createInterview(currentProject.id, title, sentences);
      setInterviews([...interviews, interview]);
      openInterview(interview);
      setIsProcessing(false);
    };

    return (
      <Layout title="Add Interview" onBack={() => setView('PROJECT_DETAIL')}>
        <div className="bg-white p-10 rounded-3xl shadow-lg border border-terracotta/10 space-y-8">
          <div>
            <label className="block text-lg font-bold mb-3 text-slate">Interviewee / Title</label>
            <input 
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="e.g., Respondent 01 - John Doe" 
              className="w-full h-14 px-6 rounded-2xl border-2 border-slate/10 focus:border-terracotta outline-none text-xl" 
            />
          </div>

          <div className="flex bg-slate/5 p-1 rounded-2xl">
            <button 
              onClick={() => setUploadMode('text')}
              className={`flex-1 py-3 rounded-xl font-bold transition-all ${uploadMode === 'text' ? 'bg-white shadow-sm text-terracotta' : 'text-slate/40'}`}
            >
              Paste Transcript
            </button>
            <button 
              onClick={() => setUploadMode('audio')}
              className={`flex-1 py-3 rounded-xl font-bold transition-all ${uploadMode === 'audio' ? 'bg-white shadow-sm text-terracotta' : 'text-slate/40'}`}
            >
              Upload Audio (ASR)
            </button>
          </div>

          {uploadMode === 'text' ? (
            <div>
              <label className="block text-lg font-bold mb-3 text-slate">Paste Raw Transcript</label>
              <textarea 
                value={rawText}
                onChange={e => setRawText(e.target.value)}
                rows={10} 
                placeholder="Paste text here..." 
                className="w-full p-6 rounded-2xl border-2 border-slate/10 focus:border-terracotta outline-none text-lg resize-none" 
              />
            </div>
          ) : (
            <div className="border-4 border-dashed border-slate/10 rounded-3xl p-12 text-center">
              <input 
                type="file" 
                accept="audio/*" 
                id="audio-upload" 
                className="hidden" 
                onChange={e => setAudioFile(e.target.files?.[0] || null)}
              />
              <label htmlFor="audio-upload" className="cursor-pointer group">
                <div className="w-20 h-20 bg-slate/5 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:bg-terracotta/10 transition-colors">
                  <svg className="w-10 h-10 text-slate/30 group-hover:text-terracotta" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                </div>
                <p className="text-lg font-bold text-slate/60">{audioFile ? audioFile.name : 'Click to select audio file'}</p>
                <p className="text-sm text-slate/30 mt-1">MP3, WAV, or AAC supported</p>
              </label>
            </div>
          )}

          <button 
            onClick={handleProcess}
            disabled={isProcessing || (!rawText && !audioFile)}
            className={`w-full h-14 bg-terracotta text-white rounded-2xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 ${isProcessing ? 'opacity-50 cursor-not-allowed' : 'btn-bounce'}`}
          >
            {isProcessing ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                {uploadMode === 'audio' ? 'Transcribing with Gemini AI...' : 'Cleaning Transcript...'}
              </>
            ) : (
              'Save and Prepare for Coding'
            )}
          </button>
        </div>
      </Layout>
    );
  }

  if (view === 'INTERVIEW_DETAIL' && currentInterview) {
    return (
      <Layout title={currentInterview.title} onBack={() => setView('PROJECT_DETAIL')}>
        <div className="bg-white rounded-3xl shadow-lg border border-slate/10 overflow-hidden flex flex-col h-[70vh]">
          <div className="flex-1 overflow-y-auto p-10 space-y-6">
            {currentInterview.sentences.map((s, idx) => (
              <p key={idx} className="text-lg leading-relaxed text-charcoal/80 border-l-2 border-terracotta/10 pl-4">{s}</p>
            ))}
          </div>
          <div className="p-6 bg-cream/50 border-t border-slate/10 flex justify-center">
            <button 
              onClick={startCoding}
              className="h-14 px-12 bg-terracotta text-white rounded-2xl font-bold text-lg btn-bounce shadow-xl"
            >
              Start Coding Session
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  if (view === 'CODING' && currentInterview && currentProject) {
    const [selectedSentenceIndex, setSelectedSentenceIndex] = useState<number | null>(null);
    const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(currentInterview.id));
    const [showNewCodeInput, setShowNewCodeInput] = useState(false);
    const [newCodeLabel, setNewCodeLabel] = useState('');

    const handleApplyCode = (code: Code) => {
      if (selectedSentenceIndex === null) return;
      const segment: Omit<CodedSegment, 'id'> = {
        interview_id: currentInterview.id,
        code_id: code.id,
        segment_text: currentInterview.sentences[selectedSentenceIndex],
        sentence_index: selectedSentenceIndex
      };
      dbService.saveCodedSegment(segment);
      setActiveCodedSegments(dbService.getCodedSegments(currentInterview.id));
      setSelectedSentenceIndex(null);
    };

    const handleCreateCode = () => {
      if (!newCodeLabel) return;
      const color = CODE_COLORS[codes.length % CODE_COLORS.length];
      const newCode = dbService.createCode(currentProject.id, newCodeLabel, color);
      setCodes([...codes, newCode]);
      setNewCodeLabel('');
      setShowNewCodeInput(false);
      handleApplyCode(newCode);
    };

    const getCodesForSentence = (idx: number) => {
      return activeCodedSegments.filter(s => s.sentence_index === idx).map(s => codes.find(c => c.id === s.code_id));
    };

    return (
      <div className="h-screen flex flex-col bg-cream text-charcoal">
        <header className="bg-white/90 border-b px-6 py-4 flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-4">
            <button onClick={() => setView('INTERVIEW_DETAIL')} className="p-2 -ml-2 hover:bg-terracotta/10 rounded-full transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-terracotta" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <h1 className="text-xl font-bold text-slate">Coding: {currentInterview.title}</h1>
          </div>
          <button onClick={() => setView('PROJECT_DETAIL')} className="px-6 py-2 bg-slate text-white rounded-xl font-bold">Finish Session</button>
        </header>

        <div className="flex-1 flex overflow-hidden">
          {/* Transcript Panel */}
          <div className="flex-1 overflow-y-auto p-8 space-y-4">
            {currentInterview.sentences.map((sentence, idx) => {
              const sentenceCodes = getCodesForSentence(idx);
              const isSelected = selectedSentenceIndex === idx;
              return (
                <div 
                  key={idx}
                  onClick={() => setSelectedSentenceIndex(idx)}
                  className={`relative p-4 rounded-2xl transition-all cursor-pointer group ${isSelected ? 'bg-terracotta/10 ring-2 ring-terracotta shadow-md' : 'hover:bg-white/50'}`}
                >
                  <div className="flex gap-2 mb-1">
                    {sentenceCodes.map(c => c && (
                      <div key={c.id} className="h-1.5 w-8 rounded-full" style={{ backgroundColor: c.color }} />
                    ))}
                  </div>
                  <p className={`text-xl leading-relaxed ${isSelected ? 'text-charcoal font-medium' : 'text-charcoal/70'}`}>{sentence}</p>
                </div>
              );
            })}
          </div>

          {/* Codes Sidebar */}
          <div className="w-96 bg-white border-l border-slate/10 p-6 flex flex-col">
            <h2 className="text-2xl font-bold text-slate mb-6">Apply Code</h2>

            {selectedSentenceIndex === null ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center p-8 text-slate/40 border-2 border-dashed border-slate/10 rounded-3xl">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 15l-2 5L9 9l11 4-5 2zm0 0l5 5M7.188 2.239l.777 2.897M5.136 7.965l-2.898-.777M13.95 4.05l-2.122 2.122m-5.657 5.656l-2.12 2.122"></path></svg>
                <p className="text-lg font-medium">Tap a sentence in the transcript to code it</p>
              </div>
            ) : (
              <div className="flex-1 flex flex-col">
                <div className="bg-terracotta/5 p-4 rounded-2xl mb-6 border border-terracotta/10">
                  <p className="text-sm font-bold text-terracotta uppercase tracking-wider mb-2">Selected Segment</p>
                  <p className="text-charcoal italic line-clamp-3">"{currentInterview.sentences[selectedSentenceIndex]}"</p>
                </div>

                <div className="space-y-3 flex-1 overflow-y-auto pr-2">
                  {codes.map(c => (
                    <button 
                      key={c.id} 
                      onClick={() => handleApplyCode(c)}
                      className="w-full flex items-center justify-between p-4 bg-cream/50 hover:bg-cream border border-slate/10 rounded-2xl group transition-all"
                    >
                      <div className="flex items-center gap-3">
                        <div className="w-6 h-6 rounded-lg" style={{ backgroundColor: c.color }} />
                        <span className="font-bold text-slate">{c.label}</span>
                      </div>
                      <svg className="w-5 h-5 text-slate/20 group-hover:text-terracotta" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                    </button>
                  ))}

                  {showNewCodeInput ? (
                    <div className="space-y-3 p-4 bg-terracotta/5 rounded-2xl border-2 border-terracotta/20 animate-in fade-in zoom-in duration-200">
                      <input 
                        autoFocus
                        value={newCodeLabel}
                        onChange={e => setNewCodeLabel(e.target.value)}
                        placeholder="Enter code name..."
                        className="w-full h-12 px-4 rounded-xl border-2 border-slate/10 focus:border-terracotta outline-none font-bold"
                        onKeyDown={e => e.key === 'Enter' && handleCreateCode()}
                      />
                      <div className="flex gap-2">
                        <button onClick={() => setShowNewCodeInput(false)} className="flex-1 h-10 bg-slate/10 rounded-lg text-sm font-bold">Cancel</button>
                        <button onClick={handleCreateCode} className="flex-1 h-10 bg-terracotta text-white rounded-lg text-sm font-bold">Create & Apply</button>
                      </div>
                    </div>
                  ) : (
                    <button 
                      onClick={() => setShowNewCodeInput(true)}
                      className="w-full p-4 border-2 border-dashed border-slate/20 rounded-2xl text-slate/40 font-bold hover:text-terracotta hover:border-terracotta/30 transition-all flex items-center justify-center gap-2"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                      Create New Code
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'EXPORT' && currentProject) {
    const [report, setReport] = useState<string>('');
    const [generating, setGenerating] = useState(false);
    const [wordFreq, setWordFreq] = useState<{ word: string, count: number }[]>([]);

    useEffect(() => {
      const allText = interviews.flatMap(i => dbService.getCodedSegments(i.id).map(s => s.segment_text)).join(' ');
      setWordFreq(getWordFrequency(allText));
    }, [interviews]);

    const generateAIMenuReport = async () => {
      setGenerating(true);
      const projectCodes = dbService.getCodes(currentProject.id);
      const allInterviews = dbService.getInterviews(currentProject.id);

      const codedData = projectCodes.map(c => {
        const segments = allInterviews.flatMap(i => 
          dbService.getCodedSegments(i.id)
            .filter(s => s.code_id === c.id)
            .map(s => s.segment_text)
        );
        return { label: c.label, segments };
      });

      const result = await generateReport(currentProject.title, codedData);
      setReport(result);
      setGenerating(false);
    };

    const downloadCSV = () => {
      const projectInterviews = dbService.getInterviews(currentProject.id);
      const rows = [['Interview', 'Code', 'Segment', 'Date']];

      projectInterviews.forEach(int => {
        const segments = dbService.getCodedSegments(int.id);
        segments.forEach(seg => {
          const code = codes.find(c => c.id === seg.code_id);
          rows.push([
            int.title,
            code?.label || 'Unknown',
            `"${seg.segment_text.replace(/"/g, '""')}"`,
            new Date(int.created_at).toLocaleDateString()
          ]);
        });
      });

      const csvContent = "data:text/csv;charset=utf-8," + rows.map(e => e.join(",")).join("\n");
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `${currentProject.title}_export.csv`);
      document.body.appendChild(link);
      link.click();
    };

    const handlePrint = () => {
      window.print();
    };

    return (
      <Layout title="Export & Analysis" onBack={() => setView('PROJECT_DETAIL')}>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8 print:hidden">
          <div className="bg-white p-8 rounded-3xl shadow-md flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-sand/20 rounded-2xl flex items-center justify-center text-sand mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
            </div>
            <h3 className="font-bold text-xl mb-2">CSV Matrix</h3>
            <p className="text-charcoal/50 text-sm mb-6">Matrix of all coded segments and codes for Excel/SPSS.</p>
            <button onClick={downloadCSV} className="w-full py-3 bg-sand text-white rounded-xl font-bold shadow-md shadow-sand/30">Download CSV</button>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-md flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-sage/20 rounded-2xl flex items-center justify-center text-sage mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
            </div>
            <h3 className="font-bold text-xl mb-2">Academic Report</h3>
            <p className="text-charcoal/50 text-sm mb-6">A high-quality printable summary of codes, frequencies and data.</p>
            <button onClick={handlePrint} className="w-full py-3 bg-sage text-white rounded-xl font-bold shadow-md shadow-sage/30">Print to PDF</button>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-md flex flex-col items-center text-center border-2 border-terracotta/20">
            <div className="w-16 h-16 bg-terracotta/20 rounded-2xl flex items-center justify-center text-terracotta mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
            </div>
            <h3 className="font-bold text-xl mb-2">AI Summary</h3>
            <p className="text-charcoal/50 text-sm mb-6">Gemini analyzes your themes and provides a synthesis of key findings.</p>
            <button 
              onClick={generateAIMenuReport}
              disabled={generating}
              className={`w-full py-3 bg-terracotta text-white rounded-xl font-bold shadow-md shadow-terracotta/30 ${generating ? 'opacity-50' : ''}`}
            >
              {generating ? 'Synthesizing...' : 'Generate with Gemini'}
            </button>
          </div>
        </div>

        <div className="space-y-12">
          {wordFreq.length > 0 && (
            <section>
              <h2 className="text-3xl font-bold text-slate mb-6 flex items-center gap-3">
                <svg className="w-8 h-8 text-terracotta" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z"></path></svg>
                Thematic Word Cloud
              </h2>
              <WordCloud data={wordFreq} />
            </section>
          )}

          <section id="printable-report" className="bg-white p-12 rounded-3xl shadow-lg border border-slate/10 space-y-8 print:shadow-none print:border-none print:p-0">
            <div className="border-b-2 border-slate/5 pb-8 mb-8 text-center">
              <h1 className="text-4xl font-bold text-slate uppercase tracking-widest mb-2">Project Synthesis</h1>
              <p className="text-charcoal/40 text-lg">{currentProject.title} • {new Date().toLocaleDateString()}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div>
                <h3 className="text-2xl font-bold text-slate mb-4 border-l-4 border-sage pl-4">Code Frequency</h3>
                <div className="space-y-3">
                  {codes.map(c => {
                    const count = interviews.flatMap(i => dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)).length;
                    return (
                      <div key={c.id} className="flex items-center justify-between p-3 bg-cream/30 rounded-xl">
                        <div className="flex items-center gap-3">
                          <div className="w-3 h-3 rounded-full" style={{ backgroundColor: c.color }} />
                          <span className="font-bold text-slate">{c.label}</span>
                        </div>
                        <span className="bg-white px-3 py-1 rounded-lg font-bold text-sage border border-sage/10 shadow-sm">{count} segments</span>
                      </div>
                    );
                  })}
                </div>
              </div>

              <div>
                <h3 className="text-2xl font-bold text-slate mb-4 border-l-4 border-sand pl-4">Interviews Analyzed</h3>
                <div className="space-y-3">
                  {interviews.map(i => (
                    <div key={i.id} className="flex items-center justify-between p-3 bg-cream/30 rounded-xl">
                      <span className="font-bold text-slate">{i.title}</span>
                      <span className="text-charcoal/40 text-sm">{dbService.getCodedSegments(i.id).length} codes</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {report && (
              <div className="pt-8 border-t-2 border-slate/5 animate-in slide-in-from-bottom duration-500">
                <h3 className="text-2xl font-bold text-slate mb-6 border-l-4 border-terracotta pl-4">Qualitative Analysis Summary</h3>
                <div className="prose prose-lg max-w-none text-charcoal/80 leading-relaxed space-y-4 font-serif">
                  {report.split('\n').map((para, i) => para.trim() ? <p key={i}>{para}</p> : null)}
                </div>
              </div>
            )}

            <div className="pt-8 border-t-2 border-slate/5">
              <h3 className="text-2xl font-bold text-slate mb-6 border-l-4 border-slate pl-4">Sample Coded Segments</h3>
              <div className="space-y-6">
                {codes.slice(0, 3).map(c => {
                  const sample = interviews.flatMap(i => dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)).slice(0, 1)[0];
                  if (!sample) return null;
                  return (
                    <div key={c.id} className="p-6 bg-slate/5 rounded-2xl border-l-8" style={{ borderColor: c.color }}>
                      <p className="text-xs font-bold text-slate/40 uppercase mb-2">Illustrative Quote for "{c.label}"</p>
                      <blockquote className="text-lg italic font-serif">"{sample.segment_text}"</blockquote>
                    </div>
                  );
                })}
              </div>
            </div>
          </section>
        </div>
      </Layout>
    );
  }

  return <div>Fallback: View {view} not implemented.</div>;
};

