const WordCloud: React.FC<{ data: { word: string, count: number }[] }> = ({ data }) => {
  if (data.length === 0) return null;
  const max = data[0].count;
  return (
    <div className="flex flex-wrap justify-center gap-4 p-8 bg-white rounded-3xl border border-slate/10 min-h-[200px] items-center">
      {data.map((item, i) => {
        const size = 1 + (item.count / max) * 2;
        const opacity = 0.4 + (item.count / max) * 0.6;
        return (
          <span 
            key={i} 
            style={{ 
              fontSize: `${size}rem`, 
              opacity,
              color: CODE_COLORS[i % CODE_COLORS.length]
            }} 
            className="font-bold transition-all hover:scale-110 cursor-default"
          >
            {item.word}
          </span>
        );
      })}
    </div>
  );
};

