            <input name="email" type="email" required placeholder="Email Address" className="w-full h-14 px-4 rounded-xl border-2 border-slate/10 focus:border-terracotta outline-none transition-all text-lg bg-white/80" />
            <input name="password" type="password" required placeholder="Password" className="w-full h-14 px-4 rounded-xl border-2 border-slate/10 focus:border-terracotta outline-none transition-all text-lg bg-white/80" />
            <button type="submit" className="w-full h-16 bg-slate text-white rounded-2xl font-bold text-xl btn-bounce shadow-xl">Sign In</button>
          </form>
        </div>
      </div>
    );
  }

  if (view === 'PROJECTS') {
    return (
      <Layout title="Projects" actions={<button onClick={handleLogout} className="text-sm font-bold text-slate/40 hover:text-terracotta uppercase tracking-widest">Logout</button>}>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {projects.map(p => (
            <div key={p.id} onClick={() => openProject(p)} className="bg-white p-6 rounded-3xl border-2 border-transparent hover:border-terracotta shadow-md transition-all cursor-pointer group relative overflow-hidden">
               <div className="absolute -top-4 -right-4 opacity-5 group-hover:opacity-10 transition-opacity">
                <LogoIcon className="w-32 h-32 rotate-12" />
              </div>
              <h3 className="text-xl font-bold text-slate mb-2">{p.title}</h3>
              <p className="text-charcoal/60 text-sm line-clamp-2">{p.description}</p>
            </div>
          ))}
          <button onClick={() => setView('CREATE_PROJECT')} className="border-4 border-dashed border-slate/10 p-6 rounded-3xl flex flex-col items-center justify-center text-slate/30 hover:text-terracotta hover:border-terracotta/30 transition-all">
            <div className="w-16 h-16 bg-slate/5 rounded-full flex items-center justify-center mb-4"><svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></div>
            <span className="font-bold text-lg">New Project</span>
          </button>
        </div>
      </Layout>
    );
  }

  if (view === 'CREATE_PROJECT') {
    return (
      <Layout title="New Project" onBack={() => setView('PROJECTS')}>
        <div className="max-w-2xl bg-white p-10 rounded-3xl shadow-lg">
          <form className="space-y-8" onSubmit={(e) => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const p = dbService.createProject(fd.get('title') as string, fd.get('desc') as string);
            setProjects([...projects, p]);
            openProject(p);
          }}>
            <input name="title" required placeholder="Project Title" className="w-full h-14 px-6 rounded-2xl border-2 border-slate/10 outline-none text-xl" />
            <textarea name="desc" rows={4} placeholder="Description" className="w-full p-6 rounded-2xl border-2 border-slate/10 outline-none text-lg resize-none" />
            <button type="submit" className="w-full h-14 bg-terracotta text-white rounded-2xl font-bold text-lg">Create Project</button>
          </form>
        </div>
      </Layout>
    );
  }

  if (view === 'PROJECT_DETAIL' && currentProject) {
    return (
      <Layout title={currentProject.title} onBack={() => setView('PROJECTS')} actions={
        <div className="flex gap-2">
          <button onClick={() => setView('EXPORT')} className="px-4 py-2 bg-sage text-white rounded-xl font-bold text-sm">Export</button>
          <button onClick={() => setView('RECORD_INTERVIEW')} className="px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm">Add Interview</button>
        </div>
      }>
        <div className="space-y-8">
          <h2 className="text-3xl font-bold text-slate mb-6">Interviews ({interviews.length})</h2>
          <div className="space-y-4">
            {interviews.map(i => (
              <div key={i.id} onClick={() => openInterview(i)} className="bg-white p-5 rounded-2xl flex items-center justify-between shadow-sm cursor-pointer hover:shadow-md transition-all">
                <h4 className="font-bold text-slate">{i.title}</h4>
                <svg className="w-5 h-5 text-slate/20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
              </div>
            ))}
          </div>
        </div>
      </Layout>
    );
  }

  if (view === 'RECORD_INTERVIEW' && currentProject) {
    const [isProcessing, setIsProcessing] = useState(false);
    const [audioFile, setAudioFile] = useState<File | null>(null);

    const handleProcess = async () => {
      if (!audioFile) return;
      setIsProcessing(true);
      const reader = new FileReader();
      reader.readAsDataURL(audioFile);
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
      });
      const base64 = await base64Promise;
      const sentences = await transcribeAudio(base64, audioFile.type);
      const interview = dbService.createInterview(currentProject.id, audioFile.name.split('.')[0], sentences);
      setInterviews([...interviews, interview]);
      openInterview(interview);
      setIsProcessing(false);
    };

    return (
      <Layout title="Add Interview" onBack={() => setView('PROJECT_DETAIL')}>
        <div className="bg-white p-10 rounded-3xl shadow-lg space-y-8 text-center">
           <input type="file" accept="audio/*" id="audio-upload" className="hidden" onChange={e => setAudioFile(e.target.files?.[0] || null)} />
           <label htmlFor="audio-upload" className="cursor-pointer group flex flex-col items-center p-20 border-4 border-dashed border-slate/10 rounded-3xl">
              <div className="w-20 h-20 bg-slate/5 rounded-full flex items-center justify-center mb-4"><svg className="w-10 h-10 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg></div>
              <p className="text-xl font-bold text-slate/60">{audioFile ? audioFile.name : 'Drop interview audio here'}</p>
           </label>
           <button onClick={handleProcess} disabled={isProcessing || !audioFile} className="w-full h-16 bg-terracotta text-white rounded-2xl font-bold text-xl">{isProcessing ? 'Transcribing with Gemini...' : 'Start Transcription'}</button>
        </div>
      </Layout>
    );
  }

  if (view === 'INTERVIEW_DETAIL' && currentInterview) {
    return (
      <Layout title={currentInterview.title} onBack={() => setView('PROJECT_DETAIL')}>
        <div className="bg-white rounded-3xl shadow-lg p-10 space-y-6">
          {currentInterview.sentences.map((s, idx) => (
            <p key={idx} className="text-xl leading-relaxed text-charcoal/80 border-l-4 border-slate/5 pl-6">{s}</p>
          ))}
          <button onClick={() => setView('CODING')} className="w-full h-16 bg-terracotta text-white rounded-2xl font-bold text-xl mt-8 shadow-lg">Start Coding Session</button>
        </div>
      </Layout>
    );
  }

  if (view === 'CODING' && currentInterview && currentProject) {
    const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
    const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(currentInterview.id));
    const [showNewCodeInput, setShowNewCodeInput] = useState(false);
    const [newCodeLabel, setNewCodeLabel] = useState('');
    const [newCodeDesc, setNewCodeDesc] = useState('');

    const handleApplyCode = (code: Code) => {
      if (selectedIdx === null) return;
      dbService.saveCodedSegment({ interview_id: currentInterview.id, code_id: code.id, segment_text: currentInterview.sentences[selectedIdx], sentence_index: selectedIdx });
      setActiveCodedSegments(dbService.getCodedSegments(currentInterview.id));
      setSelectedIdx(null);
    };

    return (
      <div className="h-screen flex flex-col bg-cream">
        <header className="bg-white border-b px-6 py-4 flex items-center justify-between">
          <h1 className="text-xl font-bold text-slate">Coding: {currentInterview.title}</h1>
          <button onClick={() => setView('PROJECT_DETAIL')} className="px-6 py-2 bg-slate text-white rounded-xl font-bold">Finish Session</button>
        </header>
        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 overflow-y-auto p-12 space-y-4">
            {currentInterview.sentences.map((s, idx) => {
              const sentenceCodes = activeCodedSegments.filter(seg => seg.sentence_index === idx).map(seg => codes.find(c => c.id === seg.code_id));
              return (
                <div key={idx} onClick={() => setSelectedIdx(idx)} className={`p-6 rounded-2xl cursor-pointer transition-all ${selectedIdx === idx ? 'bg-terracotta/10 ring-2 ring-terracotta' : 'hover:bg-white/50'}`}>
                  <div className="flex gap-2 mb-2">{sentenceCodes.map((c, ci) => c && <div key={ci} className="h-2 w-8 rounded-full" style={{ backgroundColor: c.color }} />)}</div>
                  <p className="text-2xl leading-relaxed">{s}</p>
                </div>
              );
            })}
          </div>
          <div className="w-96 bg-white border-l p-8 flex flex-col overflow-y-auto">
            <h2 className="text-2xl font-bold text-slate mb-6">Select Code</h2>
            {selectedIdx !== null ? (
              <div className="space-y-3">
                {codes.map(c => <button key={c.id} onClick={() => handleApplyCode(c)} className="w-full p-4 bg-slate/5 rounded-2xl flex flex-col items-start gap-1 font-bold group hover:bg-slate/10 transition-colors">
                  <div className="flex items-center gap-2">
                    <div className="w-4 h-4 rounded-full" style={{backgroundColor: c.color}} />
                    <span>{c.label}</span>
                  </div>
                  {c.description && <span className="text-xs font-normal text-slate/50 line-clamp-2">{c.description}</span>}
                </button>)}

                <button onClick={() => setShowNewCodeInput(true)} className="w-full p-4 border-2 border-dashed border-slate/10 rounded-2xl text-slate/40 font-bold hover:text-terracotta hover:border-terracotta/20 transition-all">+ New Code</button>

                {showNewCodeInput && (
                  <div className="p-4 bg-terracotta/5 rounded-2xl mt-4 space-y-3">
                    <input autoFocus value={newCodeLabel} onChange={e => setNewCodeLabel(e.target.value)} placeholder="Code label..." className="w-full h-12 px-4 rounded-xl border-2 border-slate/10 outline-none focus:border-terracotta transition-colors font-bold" />
                    <textarea value={newCodeDesc} onChange={e => setNewCodeDesc(e.target.value)} placeholder="Short description (optional)..." className="w-full p-4 rounded-xl border-2 border-slate/10 outline-none focus:border-terracotta transition-colors text-sm resize-none" rows={3} />
                    <div className="flex gap-2">
                       <button onClick={() => setShowNewCodeInput(false)} className="flex-1 py-2 bg-slate/10 rounded-lg font-bold text-slate/60">Cancel</button>
                       <button onClick={() => { if(newCodeLabel) { const c = dbService.createCode(currentProject.id, newCodeLabel, CODE_COLORS[codes.length%8], newCodeDesc); setCodes([...codes, c]); handleApplyCode(c); setNewCodeLabel(''); setNewCodeDesc(''); setShowNewCodeInput(false); } }} className="flex-1 py-2 bg-terracotta text-white rounded-lg font-bold">Create</button>
                    </div>
                  </div>
                )}
              </div>
            ) : <p className="text-slate/30 text-center mt-20 font-medium">Select a segment to apply codes</p>}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'EXPORT' && currentProject) {
    const handlePrintCodebook = () => {
      // Logic for codebook specific printing could be here, or just let global print handle it
      window.print();
    };

    return (
      <Layout title="Export Findings" onBack={() => setView('PROJECT_DETAIL')}>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          {/* Dashboard Section */}
          <div className="space-y-12">
            <div className="bg-white p-12 rounded-3xl shadow-lg space-y-8">
              <h2 className="text-3xl font-bold">Word Frequency</h2>
              <WordCloud data={getWordFrequency(interviews.flatMap(i => dbService.getCodedSegments(i.id).map(s => s.segment_text)).join(' '))} />
            </div>

            <div className="bg-white p-8 rounded-3xl shadow-lg">
              <h2 className="text-2xl font-bold mb-6">Quick Actions</h2>
              <div className="grid grid-cols-2 gap-4">
                <button onClick={() => window.print()} className="p-6 bg-slate text-white rounded-2xl font-bold flex flex-col items-center gap-3 hover:bg-slate/90 transition-colors">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" /></svg>
                  Full Report
                </button>
                <button onClick={handlePrintCodebook} className="p-6 bg-sage text-white rounded-2xl font-bold flex flex-col items-center gap-3 hover:bg-sage/90 transition-colors">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
                  Codebook Only
                </button>
              </div>
            </div>
          </div>

          {/* Codebook and Stats Section */}
          <div className="bg-white p-12 rounded-3xl shadow-lg space-y-12">
            <section id="printable-codebook">
              <div className="flex justify-between items-baseline mb-8">
                <h2 className="text-3xl font-bold">Codebook</h2>
                <span className="text-slate/30 font-medium uppercase tracking-widest text-xs">{codes.length} active codes</span>
              </div>
              <div className="space-y-6">
                {codes.length > 0 ? codes.map(c => {
                   const count = interviews.flatMap(i => dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)).length;
                   return (
                    <div key={c.id} className="border-b border-slate/5 pb-6 last:border-0">
                      <div className="flex justify-between items-center mb-2">
                        <div className="flex items-center gap-3">
                          <div className="w-4 h-4 rounded-full" style={{ backgroundColor: c.color }} />
                          <h4 className="text-xl font-bold text-slate">{c.label}</h4>
                        </div>
                        <span className="text-sage font-bold text-sm bg-sage/5 px-3 py-1 rounded-full">{count} occurrences</span>
                      </div>
                      {c.description ? (
                        <p className="text-charcoal/60 leading-relaxed italic">"{c.description}"</p>
                      ) : (
                        <p className="text-slate/20 text-sm italic">No description provided for this code.</p>
                      )}
                    </div>
                   );
                }) : (
                  <p className="text-slate/30 text-center py-20 italic">No codes have been defined for this project yet.</p>
                )}
              </div>
            </section>
          </div>
        </div>

        {/* Print specific styling hide/show logic is handled by browser @media print typically, 
            but for this demo layout we can rely on standard print which will catch everything on the scrollable page. */}
      </Layout>
    );
  }

  return <div>Loading...</div>;
};

export default App;

import React, { useState, useEffect } from 'react';
import { AppView, Project, Interview, Code, CodedSegment, Profile } from './types';
import { dbService } from './services/dbService';
import { transcribeAudio, getWordFrequency } from './services/geminiService';
import Layout from './components/Layout';
import { CODE_COLORS } from './constants';

// --- Shared Components ---

