      <path d="M-20,-20 C-35,-10 -30,20 -2,30 C28,40 40,10 30,-20 C20,-50 -5,-45 -20,-20" stroke="#E07A5F" strokeWidth="1.5" strokeLinecap="round" opacity="0.6" />
      <path d="M-15,-25 C-35,-20 -40,10 -20,30 C0,50 35,35 40,5 C45,-25 15,-45 -15,-25" stroke="#81B29A" strokeWidth="2.5" strokeLinecap="round" opacity="0.8" />
      <path d="M-10,-30 C-30,-25 -35,5 -15,25 C5,45 30,30 35,0 C40,-30 10,-50 -10,-30" stroke="#81B29A" strokeWidth="1.5" strokeLinecap="round" opacity="0.5" />
