      <path d="M10,-30 C-20,-30 -40,5 -20,20 C0,45 35,35 40,5 C45,-25 30,-30 10,-30" stroke="#3D405B" strokeWidth="1.5" strokeLinecap="round" opacity="0.6" />
      <path d="M15,20 C25,20 45,40 45,50" stroke="#3D405B" strokeWidth="4" strokeLinecap="round" />
      <path d="M10,25 C20,25 40,45 40,55" stroke="#E07A5F" strokeWidth="3" strokeLinecap="round" />
      <path d="M5,30 C15,30 35,50 35,60" stroke="#81B29A" strokeWidth="2" strokeLinecap="round" />
    </g>
  </svg>
);

const FullLogo: React.FC = () => (
  <div className="flex flex-col items-center">
    <LogoIcon className="w-48 h-48" />
    <h1 className="text-6xl font-bold text-slate tracking-tight -mt-6 font-sans">Quilta</h1>
    <p className="text-sage font-medium tracking-widest text-xl uppercase mt-1 font-sans">QDA for Students</p>
  </div>
);

const WordCloud: React.FC<{ data: { word: string, count: number }[] }> = ({ data }) => {
  if (data.length === 0) return null;
  const max = data[0].count;
  return (
    <div className="flex flex-wrap justify-center gap-4 p-8 bg-white rounded-3xl border border-slate/10 min-h-[200px] items-center">
      {data.map((item, i) => {
        const size = 1 + (item.count / max) * 2;
        const opacity = 0.4 + (item.count / max) * 0.6;
        return (
          <span 
            key={i} 
            style={{ 
              fontSize: `${size}rem`, 
              opacity,
              color: CODE_COLORS[i % CODE_COLORS.length]
            }} 
            className="font-bold transition-all hover:scale-110 cursor-default"
          >
            {item.word}
          </span>
        );
      })}
    </div>
  );
};

// --- View Components ---

