const ProjectDetailView: React.FC<{ project: Project, interviews: Interview[], onBack: () => void, onOpenInterview: (i: Interview) => void, onAddInterview: () => void, onExport: () => void }> = ({ project, interviews, onBack, onOpenInterview, onAddInterview, onExport }) => (
  <Layout title={project.title} onBack={onBack} actions={
    <div className="flex gap-2">
      <button onClick={onExport} className="px-4 py-2 bg-sage text-white rounded-xl font-bold text-sm">Export</button>
      <button onClick={onAddInterview} className="px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm">Add Interview</button>
    </div>
  }>
    <div className="space-y-8">
      <h2 className="text-3xl font-bold text-slate mb-6">Interviews ({interviews.length})</h2>
      <div className="space-y-4">
        {interviews.map(i => (
          <div key={i.id} onClick={() => onOpenInterview(i)} className="bg-white p-5 rounded-2xl flex items-center justify-between shadow-sm cursor-pointer hover:shadow-md transition-all">
            <h4 className="font-bold text-slate">{i.title}</h4>
