const SignupView: React.FC<{ onSignup: (email: string, fullName: string) => void, onGoToLogin: () => void }> = ({ onSignup, onGoToLogin }) => {
  const [errors, setErrors] = useState<Record<string, string>>({});

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const fullName = formData.get('fullName') as string;
    const email = formData.get('email') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;

    const newErrors: Record<string, string> = {};

    if (!fullName) newErrors.fullName = "Full Name is required";
    if (!email || !/\S+@\S+\.\S+/.test(email)) newErrors.email = "Valid email is required";
    if (!password || password.length < 8) newErrors.password = "Password must be at least 8 characters";
    if (password !== confirmPassword) newErrors.confirmPassword = "Passwords do not match";

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    onSignup(email, fullName);
  };

  const inputStyle = (fieldName: string) => `w-full h-14 px-12 rounded-lg border-2 bg-white/80 outline-none transition-all text-lg ${errors[fieldName] ? 'border-red-500' : 'border-slate/10 focus:border-terracotta'}`;

