        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="relative">
            <span className="absolute left-4 top-4 text-slate/40">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
            </span>
            <input name="fullName" type="text" placeholder="Full Name" className={inputStyle('fullName')} />
            {errors.fullName && <p className="text-red-500 text-xs mt-1 ml-2 font-medium">{errors.fullName}</p>}
