const CodingView: React.FC<{ interview: Interview, project: Project, codes: Code[], onFinish: () => void, onCodeCreated: (c: Code) => void }> = ({ interview, project, codes, onFinish, onCodeCreated }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(interview.id));
  const [showNewCodeInput, setShowNewCodeInput] = useState(false);
  const [newCodeLabel, setNewCodeLabel] = useState('');
  const [newCodeDesc, setNewCodeDesc] = useState('');

  const handleApplyCode = (code: Code) => {
    if (selectedIdx === null) return;
    dbService.saveCodedSegment({ interview_id: interview.id, code_id: code.id, segment_text: interview.sentences[selectedIdx], sentence_index: selectedIdx });
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
    setSelectedIdx(null);
  };

  const handleCreateCode = () => {
    if(newCodeLabel) {
      const c = dbService.createCode(project.id, newCodeLabel, CODE_COLORS[codes.length % 8], newCodeDesc);
      onCodeCreated(c);
      handleApplyCode(c);
      setNewCodeLabel('');
      setNewCodeDesc('');
      setShowNewCodeInput(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-cream">
      <header className="bg-white border-b px-6 py-4 flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate">Coding: {interview.title}</h1>
        <button onClick={onFinish} className="px-6 py-2 bg-slate text-white rounded-xl font-bold">Finish Session</button>
      </header>
      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1 overflow-y-auto p-12 space-y-4">
          {interview.sentences.map((s, idx) => {
            const sentenceCodes = activeCodedSegments.filter(seg => seg.sentence_index === idx).map(seg => codes.find(c => c.id === seg.code_id));
            return (
              <div key={idx} onClick={() => setSelectedIdx(idx)} className={`p-6 rounded-2xl cursor-pointer transition-all ${selectedIdx === idx ? 'bg-terracotta/10 ring-2 ring-terracotta' : 'hover:bg-white/50'}`}>
                <div className="flex gap-2 mb-2">{sentenceCodes.map((c, ci) => c && <div key={ci} className="h-2 w-8 rounded-full" style={{ backgroundColor: c.color }} />)}</div>
                <p className="text-2xl leading-relaxed">{s}</p>
              </div>
            );
          })}
        </div>
        <div className="w-96 bg-white border-l p-8 flex flex-col overflow-y-auto">
          <h2 className="text-2xl font-bold text-slate mb-6">Select Code</h2>
          {selectedIdx !== null ? (
            <div className="space-y-3">
              {codes.map(c => <button key={c.id} onClick={() => handleApplyCode(c)} className="w-full p-4 bg-slate/5 rounded-2xl flex flex-col items-start gap-1 font-bold group hover:bg-slate/10 transition-colors text-left">
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded-full" style={{backgroundColor: c.color}} />
                  <span>{c.label}</span>
                </div>
                {c.description && <span className="text-xs font-normal text-slate/50 line-clamp-2">{c.description}</span>}
              </button>)}

              <button onClick={() => setShowNewCodeInput(true)} className="w-full p-4 border-2 border-dashed border-slate/10 rounded-2xl text-slate/40 font-bold hover:text-terracotta hover:border-terracotta/20 transition-all">+ New Code</button>

              {showNewCodeInput && (
                <div className="p-4 bg-terracotta/5 rounded-2xl mt-4 space-y-3">
                  <input autoFocus value={newCodeLabel} onChange={e => setNewCodeLabel(e.target.value)} placeholder="Code label..." className="w-full h-12 px-4 rounded-xl border-2 border-slate/10 outline-none focus:border-terracotta transition-colors font-bold" />
                  <textarea value={newCodeDesc} onChange={e => setNewCodeDesc(e.target.value)} placeholder="Short description (optional)..." className="w-full p-4 rounded-xl border-2 border-slate/10 outline-none focus:border-terracotta transition-colors text-sm resize-none" rows={3} />
                  <div className="flex gap-2">
                     <button onClick={() => setShowNewCodeInput(false)} className="flex-1 py-2 bg-slate/10 rounded-lg font-bold text-slate/60">Cancel</button>
                     <button onClick={handleCreateCode} className="flex-1 py-2 bg-terracotta text-white rounded-lg font-bold">Create</button>
                  </div>
                </div>
              )}
            </div>
          ) : <p className="text-slate/30 text-center mt-20 font-medium">Select a segment to apply codes</p>}
        </div>
      </div>
    </div>
  );
};

