                    </div>
                    <span className="text-sage font-bold text-sm bg-sage/5 px-3 py-1 rounded-full">{count} occurrences</span>
                  </div>
                  {c.description ? (
                    <p className="text-charcoal/60 leading-relaxed italic">"{c.description}"</p>
                  ) : (
                    <p className="text-slate/20 text-sm italic">No description provided for this code.</p>
                  )}
                </div>
               );
            }) : (
              <p className="text-slate/30 text-center py-20 italic">No codes have been defined for this project yet.</p>
            )}
          </div>
        </section>
      </div>
    </div>
  </Layout>
);

// --- Main App Component ---

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);

  useEffect(() => {
    if (user) {
      setProjects(dbService.getProjects());
      setView('PROJECTS');
    }
  }, [user]);

  const handleLogin = (email: string) => {
    const profile = dbService.login(email);
    setUser(profile);
  };

  const handleLogout = () => {
    dbService.logout();
    setUser(null);
    setView('AUTH');
  };

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const openInterview = (i: Interview) => {
    setCurrentInterview(i);
    setView('INTERVIEW_DETAIL');
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH':
        return <AuthView onLogin={handleLogin} />;
      case 'PROJECTS':
        return <ProjectsView projects={projects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={handleLogout} />;
      case 'CREATE_PROJECT':
        return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'PROJECT_DETAIL':
        return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onOpenInterview={openInterview} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW':
        return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); openInterview(i); }} /> : null;
      case 'INTERVIEW_DETAIL':
        return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING':
        return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('PROJECT_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT':
        return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default:
        return <div>Loading...</div>;
    }
  };

  return renderView();
};

export default App;

