const RecordInterviewView: React.FC<{ project: Project, onBack: () => void, onInterviewCreated: (i: Interview) => void }> = ({ project, onBack, onInterviewCreated }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [audioFile, setAudioFile] = useState<File | null>(null);

  const handleProcess = async () => {
    if (!audioFile) return;
    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(audioFile);
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
      });
      const base64 = await base64Promise;
      const sentences = await transcribeAudio(base64, audioFile.type);
      const interview = dbService.createInterview(project.id, audioFile.name.replace(/\.[^/.]+$/, ""), sentences);
      onInterviewCreated(interview);
    } catch (err) {
      console.error(err);
      alert("Failed to transcribe audio. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout title="Upload Interview" onBack={onBack}>
      <div className="max-w-3xl mx-auto bg-white p-12 rounded-3xl shadow-lg space-y-8 text-center">
         <div className="space-y-4">
           <h2 className="text-3xl font-bold text-slate">Import Transcription</h2>
           <p className="text-slate/50 text-lg">Upload an audio recording (.mp3, .wav, .m4a). Quilta will automatically transcribe and segment it for research coding.</p>
         </div>

         <input type="file" accept="audio/*" id="audio-upload" className="hidden" onChange={e => setAudioFile(e.target.files?.[0] || null)} />
         <label htmlFor="audio-upload" className="cursor-pointer group flex flex-col items-center p-24 border-4 border-dashed border-slate/10 hover:border-terracotta/30 transition-all rounded-3xl bg-slate/5">
            <div className={`w-24 h-24 rounded-full flex items-center justify-center mb-6 transition-all shadow-sm ${audioFile ? 'bg-sage text-white' : 'bg-white text-slate/20'}`}>
              <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path>
              </svg>
            </div>
            <p className="text-2xl font-bold text-slate">
              {audioFile ? audioFile.name : 'Select Audio File'}
            </p>
            {!audioFile && <p className="text-slate/40 mt-2">Maximum file size: 50MB</p>}
         </label>

         <button 
           onClick={handleProcess} 
           disabled={isProcessing || !audioFile} 
           className="w-full h-20 bg-terracotta text-white rounded-2xl font-bold text-2xl shadow-lg disabled:opacity-50 transition-all flex items-center justify-center gap-4"
         >
           {isProcessing ? (
             <>
               <svg className="animate-spin h-8 w-8 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                 <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                 <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
               </svg>
               Transcribing with Gemini...
             </>
           ) : 'Start Intelligent Transcription'}
         </button>
      </div>
    </Layout>
  );
};

