const CodingView: React.FC<{ interview: Interview, project: Project, codes: Code[], onFinish: () => void, onCodeCreated: (c: Code) => void }> = ({ interview, project, codes, onFinish, onCodeCreated }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(interview.id));
  const [showNewCodeInput, setShowNewCodeInput] = useState(false);
  const [newCodeLabel, setNewCodeLabel] = useState('');
  const [newCodeDesc, setNewCodeDesc] = useState('');

  const handleApplyCode = (code: Code) => {
    if (selectedIdx === null) return;
    dbService.saveCodedSegment({ 
      interview_id: interview.id, 
      code_id: code.id, 
      segment_text: interview.sentences[selectedIdx], 
      sentence_index: selectedIdx 
    });
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
    setSelectedIdx(null);
  };

  const handleDeleteSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
  };

  const handleCreateCode = () => {
    if(newCodeLabel) {
      const c = dbService.createCode(project.id, newCodeLabel, CODE_COLORS[codes.length % CODE_COLORS.length], newCodeDesc);
      onCodeCreated(c);
      handleApplyCode(c);
      setNewCodeLabel('');
      setNewCodeDesc('');
      setShowNewCodeInput(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-terracotta/10 rounded-full flex items-center justify-center text-terracotta">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate leading-tight">Coding Studio</h1>
            <p className="text-xs text-slate/40 uppercase tracking-widest">{interview.title}</p>
          </div>
        </div>
        <button onClick={onFinish} className="px-8 py-3 bg-slate text-white rounded-xl font-bold hover:bg-slate/90 transition-all shadow-md">Complete Analysis</button>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Left Side: Transcript */}
        <div className="flex-1 overflow-y-auto p-12 space-y-6">
          {interview.sentences.map((s, idx) => {
            const sentenceCodes = activeCodedSegments
              .filter(seg => seg.sentence_index === idx)
              .map(seg => ({ segmentId: seg.id, code: codes.find(c => c.id === seg.code_id) }));

            return (
              <div 
                key={idx} 
                onClick={() => setSelectedIdx(idx)} 
                className={`group p-8 rounded-[20px] cursor-pointer transition-all ${selectedIdx === idx ? 'bg-white shadow-xl ring-2 ring-terracotta' : 'hover:bg-white/50 border border-transparent'}`}
              >
                <div className="flex flex-wrap gap-2 mb-4 h-2">
                  {sentenceCodes.map((sc, ci) => sc.code && (
                    <div 
                      key={ci} 
                      className="h-2 px-6 rounded-full group/chip relative" 
                      style={{ backgroundColor: sc.code.color }}
                      title={sc.code.label}
                    >
                       <button 
                        onClick={(e) => { e.stopPropagation(); handleDeleteSegment(sc.segmentId); }}
                        className="absolute -top-2 -right-2 bg-charcoal text-white w-4 h-4 rounded-full text-[10px] flex items-center justify-center opacity-0 group-hover/chip:opacity-100 transition-opacity"
                       >
                         ×
                       </button>
                    </div>
                  ))}
                </div>
                <p className="text-2xl leading-relaxed text-charcoal/90 font-serif">{s}</p>
              </div>
            );
          })}
        </div>

        {/* Right Side: Coding Panel */}
        <div className="w-[420px] bg-white border-l p-10 flex flex-col overflow-y-auto shadow-2xl z-40">
          <div className="mb-10">
            <h2 className="text-2xl font-bold text-slate mb-2">Code Repository</h2>
            <p className="text-slate/40 text-sm">Select a segment to apply or create codes.</p>
          </div>

          {selectedIdx !== null ? (
            <div className="space-y-4">
              <div className="p-4 bg-terracotta/5 rounded-2xl border border-terracotta/10 mb-8">
                <span className="text-[10px] font-bold text-terracotta uppercase tracking-widest block mb-1">Selected Sentence</span>
                <p className="text-charcoal italic line-clamp-3">"{interview.sentences[selectedIdx]}"</p>
              </div>

              <div className="space-y-3">
                {codes.map(c => (
                  <button 
                    key={c.id} 
                    onClick={() => handleApplyCode(c)} 
                    className="w-full p-6 bg-slate/5 rounded-2xl border border-transparent hover:border-terracotta/30 flex items-center gap-4 group transition-all text-left"
                  >
                    <div className="w-6 h-6 rounded-full flex-shrink-0 shadow-sm" style={{backgroundColor: c.color}} />
                    <div className="flex-1">
                      <div className="font-bold text-slate group-hover:text-terracotta transition-colors">{c.label}</div>
                      {c.description && <div className="text-xs text-slate/50 leading-tight mt-1">{c.description}</div>}
                    </div>
                    <svg className="w-5 h-5 text-slate/20 opacity-0 group-hover:opacity-100 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                  </button>
                ))}
              </div>

              {!showNewCodeInput ? (
                <button 
                  onClick={() => setShowNewCodeInput(true)} 
                  className="w-full py-6 border-2 border-dashed border-slate/10 rounded-2xl text-slate/40 font-bold hover:text-terracotta hover:border-terracotta/20 transition-all flex items-center justify-center gap-2"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                  Define New Code
