const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 800); // Simulated loading
    }
  }, [user]);

  const handleLogin = (email: string) => {
    const profile = dbService.login(email);
    setUser(profile);
  };

  const handleLogout = () => {
    dbService.logout();
    setUser(null);
    setView('AUTH');
    setCurrentProject(null);
    setCurrentInterview(null);
  };

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const openInterview = (i: Interview) => {
    setCurrentInterview(i);
    setView('INTERVIEW_DETAIL');
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH':
        return <AuthView onLogin={handleLogin} />;
      case 'PROJECTS':
        return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={handleLogout} />;
      case 'CREATE_PROJECT':
        return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'EDIT_PROJECT':
        return currentProject ? <EditProjectView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onUpdated={(p) => { 
          setProjects(projects.map(pj => pj.id === p.id ? p : pj));
          setCurrentProject(p);
          setView('PROJECT_DETAIL');
        }} /> : null;
      case 'PROJECT_DETAIL':
        return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={openInterview} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW':
        return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); openInterview(i); }} /> : null;
      case 'INTERVIEW_DETAIL':
        return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING':
        return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('PROJECT_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT':
        return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default:
        return <div>Loading...</div>;
    }
  };

  return renderView();
};

export default App;

import { Project, Interview, Code, CodedSegment, Profile } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: string[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.join(' '),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),
  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    // Check for existing coding on same sentence/code to avoid duplicates
    const filtered = segments.filter((s: CodedSegment) => 
      !(s.interview_id === segment.interview_id && 
        s.code_id === segment.code_id && 
        s.sentence_index === segment.sentence_index)
    );
    set(STORAGE_KEYS.CODED_SEGMENTS, [...filtered, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const transcribeText = async (rawInput: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `Break the following qualitative interview transcript into a clean list of individual sentences. Keep the exact meaning. Remove stutters like "um" or "uh" to make it research-ready. Output as a JSON array of strings.

          Transcript:
          ${rawInput}`
        }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const jsonStr = response.text || '[]';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    return rawInput.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  }
};

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType
            }
          },
          {
            text: "Please provide a high-quality transcription of this interview. Once transcribed, break it into a JSON array of clean, research-ready sentences. Remove filler words."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const jsonStr = response.text || '[]';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    // Return a structured error message so the UI can handle it gracefully
    return ["Error: Transcription failed. The model might be overloaded or the file type is unsupported."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: string[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => `Code: ${c.label}\nQuotes:\n- ${c.segments.join('\n- ')}`).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `You are a qualitative research assistant. Based on the following coded segments for the project "${projectTitle}", write a high-level summary report identifying key themes and patterns. Use academic but accessible language.

          Data:
          ${context}`
        }]
      }
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

