const CodingView: React.FC<{ interview: Interview, project: Project, codes: Code[], onFinish: () => void, onCodeCreated: (c: Code) => void }> = ({ interview, project, codes, onFinish, onCodeCreated }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(interview.id));
  const [showNewCodeInput, setShowNewCodeInput] = useState(false);
  const [newCodeLabel, setNewCodeLabel] = useState('');

  const handleApplyCode = (code: Code) => {
    if (selectedIdx === null) return;
    dbService.saveCodedSegment({ 
      interview_id: interview.id, 
      code_id: code.id, 
      segment_text: interview.sentences[selectedIdx], 
      sentence_index: selectedIdx 
    });
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
    setSelectedIdx(null);
  };

  const handleCreateCode = () => {
    if(newCodeLabel) {
      const c = dbService.createCode(project.id, newCodeLabel, CODE_COLORS[codes.length % CODE_COLORS.length]);
      onCodeCreated(c);
      handleApplyCode(c);
      setNewCodeLabel('');
      setShowNewCodeInput(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-4">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-xs text-slate/40 uppercase tracking-widest">{interview.title}</p>
        </div>
        <button onClick={onFinish} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md">Finish Session</button>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1 overflow-y-auto p-12 space-y-6">
          {interview.sentences.map((s, idx) => {
            const sentenceCodes = activeCodedSegments
              .filter(seg => seg.sentence_index === idx)
              .map(seg => codes.find(c => c.id === seg.code_id));

            return (
              <div 
                key={idx} 
                onClick={() => setSelectedIdx(idx)} 
                className={`p-6 rounded-2xl cursor-pointer transition-all ${selectedIdx === idx ? 'bg-white shadow-xl ring-2 ring-terracotta' : 'hover:bg-white/40'}`}
              >
                <div className="flex flex-wrap gap-1 mb-2">
                  {sentenceCodes.map((c, ci) => c && (
                    <div key={ci} className="h-1.5 px-4 rounded-full" style={{ backgroundColor: c.color }} />
                  ))}
                </div>
                <p className="text-xl leading-relaxed text-charcoal/90 font-serif">{s}</p>
              </div>
            );
          })}
        </div>

        <div className="w-96 bg-white border-l p-8 flex flex-col gap-6 shadow-2xl">
          <h2 className="text-xl font-bold text-slate">Codes</h2>
          {selectedIdx !== null ? (
            <div className="space-y-4">
              {codes.map(c => (
                <button 
                  key={c.id} 
                  onClick={() => handleApplyCode(c)} 
                  className="w-full p-4 bg-slate/5 rounded-xl border border-transparent hover:border-terracotta/20 flex items-center gap-3 transition-all"
                >
                  <div className="w-4 h-4 rounded-full" style={{backgroundColor: c.color}} />
                  <span className="font-bold text-slate">{c.label}</span>
                </button>
              ))}
              {!showNewCodeInput ? (
                <button onClick={() => setShowNewCodeInput(true)} className="w-full py-4 border-2 border-dashed border-slate/10 rounded-xl text-slate/40 font-bold hover:text-terracotta transition-all">+ New Code</button>
              ) : (
                <div className="space-y-2">
                  <input autoFocus value={newCodeLabel} onChange={e => setNewCodeLabel(e.target.value)} placeholder="Code label..." className="w-full h-12 px-4 rounded-xl border-2 border-slate/10 outline-none" />
                  <button onClick={handleCreateCode} className="w-full h-12 bg-terracotta text-white rounded-xl font-bold shadow-md">Create & Apply</button>
                </div>
              )}
            </div>
          ) : (
            <p className="text-slate/40 italic">Select a sentence to apply codes</p>
          )}
        </div>
      </div>
    </div>
  );
};

const ExportView: React.FC<{ project: Project, interviews: Interview[], codes: Code[], onBack: () => void }> = ({ project, interviews, codes, onBack }) => {
  const [report, setReport] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const codeSummaries = codes.map(c => {
      const segments = interviews.flatMap(i => 
        dbService.getCodedSegments(i.id)
          .filter(s => s.code_id === c.id)
          .map(s => s.segment_text)
      );
      return { label: c.label, segments };
    }).filter(c => c.segments.length > 0);

    const res = await generateReport(project.title, codeSummaries);
    setReport(res);
    setIsGenerating(false);
  };

  return (
    <Layout title="Analysis Report" onBack={onBack}>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-lg space-y-4">
            <h2 className="text-2xl font-bold text-slate">Code Frequency</h2>
            <div className="space-y-3">
              {codes.map(c => {
                const count = interviews.reduce((acc, i) => acc + dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id).length, 0);
                return (
                  <div key={c.id} className="flex items-center justify-between p-3 bg-slate/5 rounded-xl">
                    <div className="flex items-center gap-3">
                      <div className="w-3 h-3 rounded-full" style={{backgroundColor: c.color}} />
                      <span className="font-bold text-slate text-sm">{c.label}</span>
                    </div>
                    <span className="text-sage font-bold text-xs">{count} hits</span>
                  </div>
                );
              })}
            </div>
            <div className="pt-6">
               <WordCloud data={getWordFrequency(interviews.map(i => i.sentences.join(' ')).join(' '))} />
            </div>
          </div>
        </div>

        <div className="bg-white p-10 rounded-3xl shadow-lg space-y-6">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-bold text-slate">Thematic Summary</h2>
            <button onClick={handleGenerateReport} disabled={isGenerating} className="px-6 py-2 bg-terracotta text-white rounded-xl font-bold shadow-md disabled:opacity-50">
              {isGenerating ? 'Synthesizing...' : 'AI Analysis'}
