const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 800);
    }
  }, [user]);

  const handleLogin = (email: string) => {
    const profile = dbService.login(email);
    setUser(profile);
  };

  const handleLogout = () => {
    dbService.logout();
    setUser(null);
    setView('AUTH');
    setCurrentProject(null);
    setCurrentInterview(null);
  };

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const openInterview = (i: Interview) => {
    setCurrentInterview(i);
    setView('INTERVIEW_DETAIL');
  };

  const deleteInterview = (id: string) => {
    if (confirm("Permanently delete this interview and all associated coding?")) {
      dbService.deleteInterview(id);
      setInterviews(interviews.filter(i => i.id !== id));
      setView('PROJECT_DETAIL');
    }
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH':
        return <AuthView onLogin={handleLogin} />;
      case 'PROJECTS':
        return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={handleLogout} />;
      case 'CREATE_PROJECT':
        return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'EDIT_PROJECT':
        return currentProject ? <EditProjectView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onUpdated={(p) => { 
          setProjects(projects.map(pj => pj.id === p.id ? p : pj));
          setCurrentProject(p);
          setView('PROJECT_DETAIL');
        }} /> : null;
      case 'PROJECT_DETAIL':
        return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={openInterview} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW':
        return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); openInterview(i); }} /> : null;
      case 'INTERVIEW_DETAIL':
        return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onDelete={() => deleteInterview(currentInterview.id)} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING':
        return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT':
        return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default:
        return <div>Loading...</div>;
    }
  };

  return renderView();
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a high-end qualitative research assistant. 
Your task is to take raw input (audio transcription or document text) and break it into a JSON array of individual, numbered sentences.
Remove filler words, but preserve meaning.
Crucially, ensure every segment is a complete thought suitable for coding.`;

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `${SYSTEM_PROMPT} Please provide a JSON array of clean, research-ready sentences from this audio file.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return ["Error: Transcription failed. Support for this audio format may be limited."];
  }
};

export const processDocument = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `${SYSTEM_PROMPT} Extract the text from this document and break it into a JSON array of individual sentences for qualitative analysis.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Document Processing Error:", error);
    return ["Error: Document extraction failed. Please ensure the file is not password protected."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => 
      `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${String(s.ref + 1).padStart(3, '0')}] "${s.text}"`).join('\n')}`
    ).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `You are a qualitative research assistant. Write a formal thematic synthesis for the project "${projectTitle}". 
          Structure the report with an Introduction, Key Findings (referencing the coded segments), and a Conclusion.

          Data:
          ${context}`
        }]
      }
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

