const RecordInterviewView: React.FC<{ project: Project, onBack: () => void, onInterviewCreated: (i: Interview) => void }> = ({ project, onBack, onInterviewCreated }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const handleProcess = async () => {
    if (!selectedFile) return;
    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(selectedFile);
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
      });
      const base64 = await base64Promise;

      let sentences: string[] = [];
      const isAudio = selectedFile.type.startsWith('audio/');

      if (isAudio) {
        sentences = await transcribeAudio(base64, selectedFile.type);
      } else {
        sentences = await processDocument(base64, selectedFile.type || 'application/pdf');
      }

      if (sentences[0]?.startsWith("Error:")) {
        alert(sentences[0]);
        setIsProcessing(false);
        return;
      }

      const interview = dbService.createInterview(project.id, selectedFile.name.replace(/\.[^/.]+$/, ""), sentences);
      onInterviewCreated(interview);
    } catch (err) {
      console.error(err);
      alert("Failed to process file. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout title="Import Data" onBack={onBack}>
      <div className="max-w-3xl mx-auto bg-white p-12 rounded-3xl shadow-lg space-y-8 text-center">
         <div className="space-y-4">
           <h2 className="text-3xl font-bold text-slate">Import Qualitative Data</h2>
           <p className="text-slate/50 text-lg">Upload audio interviews or text documents (PDF, DOCX, TXT). Quilta will segment the content for categorical coding.</p>
         </div>

         <input 
            type="file" 
            accept="audio/*,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document,text/plain" 
            id="file-upload" 
            className="hidden" 
            onChange={e => setSelectedFile(e.target.files?.[0] || null)} 
         />
         <label htmlFor="file-upload" className="cursor-pointer group flex flex-col items-center p-20 border-4 border-dashed border-slate/10 hover:border-terracotta/30 transition-all rounded-3xl bg-slate/5">
            <div className={`w-20 h-20 rounded-full flex items-center justify-center mb-6 shadow-sm ${selectedFile ? 'bg-sage text-white' : 'bg-white text-slate/20'}`}>
              {selectedFile?.type.startsWith('audio/') ? (
                 <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              ) : (
                 <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
              )}
            </div>
            <p className="text-xl font-bold text-slate">
              {selectedFile ? selectedFile.name : 'Select Audio or Document'}
            </p>
         </label>

         <button 
           onClick={handleProcess} 
           disabled={isProcessing || !selectedFile} 
           className="w-full h-16 bg-terracotta text-white rounded-2xl font-bold text-xl shadow-lg disabled:opacity-50 flex items-center justify-center gap-3 transition-all"
         >
           {isProcessing ? 'Processing with AI...' : 'Begin Segmentation'}
         </button>
      </div>
    </Layout>
  );
};

