const CodingView: React.FC<{ 
  interview: Interview, 
  project: Project, 
  codes: Code[], 
  onFinish: () => void, 
  onCodeCreated: (c: Code) => void 
}> = ({ interview, project, codes, onFinish, onCodeCreated }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(interview.id));
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleOpenModal = (idx: number) => {
    setSelectedIdx(idx);
    setIsModalOpen(true);
  };

  const handleApplyCode = (code: Code) => {
    if (selectedIdx === null) return;
    dbService.saveCodedSegment({ 
      interview_id: interview.id, 
      code_id: code.id, 
      segment_text: interview.sentences[selectedIdx], 
      sentence_index: selectedIdx 
    });
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
    setIsModalOpen(false);
  };

  const handleCreateAndApply = (label: string, color: string) => {
    if (selectedIdx === null) return;
    const newCode = dbService.createCode(project.id, label, color);
    onCodeCreated(newCode);
    handleApplyCode(newCode);
  };

  const handleDeleteSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-terracotta/10 rounded-full flex items-center justify-center text-terracotta">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate leading-tight">Coding Studio</h1>
            <p className="text-xs text-slate/40 uppercase tracking-widest truncate max-w-[200px]">{interview.title}</p>
          </div>
        </div>
        <button onClick={onFinish} className="px-8 py-3 bg-slate text-white rounded-xl font-bold hover:bg-slate/90 transition-all shadow-md">Complete Session</button>
      </header>

      <div className="flex-1 overflow-y-auto p-12 space-y-6 flex flex-col items-center">
        <div className="max-w-4xl w-full space-y-4 pb-20">
          {interview.sentences.map((s, idx) => {
            const sentenceCodes = activeCodedSegments
              .filter(seg => seg.sentence_index === idx)
              .map(seg => ({ segmentId: seg.id, code: codes.find(c => c.id === seg.code_id) }));

            return (
              <div 
                key={idx} 
                onClick={() => handleOpenModal(idx)} 
                className={`group p-8 rounded-[20px] cursor-pointer transition-all border border-transparent hover:bg-white/50 relative ${selectedIdx === idx && isModalOpen ? 'bg-white shadow-xl ring-2 ring-terracotta' : ''}`}
              >
                <div className="flex items-center gap-3 mb-4">
                  <span className="text-[10px] font-bold text-slate/30 uppercase tracking-widest bg-slate/5 px-2 py-0.5 rounded">Ref #{String(idx + 1).padStart(3, '0')}</span>
                  <div className="flex flex-wrap gap-2 h-2">
                    {sentenceCodes.map((sc, ci) => sc.code && (
                      <div 
                        key={ci} 
                        className="h-2 px-6 rounded-full group/chip relative" 
                        style={{ backgroundColor: sc.code.color }}
                        title={sc.code.label}
                      >
                         <button 
                          onClick={(e) => { e.stopPropagation(); handleDeleteSegment(sc.segmentId); }}
                          className="absolute -top-3 -right-3 bg-slate text-white w-5 h-5 rounded-full text-[10px] flex items-center justify-center opacity-0 group-hover/chip:opacity-100 transition-opacity shadow-lg border-2 border-white"
                         >
                           ×
                         </button>
                      </div>
                    ))}
                  </div>
                </div>
                <p className="text-2xl leading-relaxed text-charcoal/90 font-serif">{s}</p>
              </div>
            );
          })}
        </div>
      </div>

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        sentenceText={selectedIdx !== null ? interview.sentences[selectedIdx] : ''}
        sentenceIndex={selectedIdx || 0}
        interviewId={interview.id}
        projectId={project.id}
        existingCodes={codes}
        onApply={handleApplyCode}
        onCreateAndApply={handleCreateAndApply}
      />
    </div>
  );
};

const ExportView: React.FC<{ project: Project, interviews: Interview[], codes: Code[], onBack: () => void }> = ({ project, interviews, codes, onBack }) => {
  const [report, setReport] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const codeSummaries = codes.map(c => {
      const segments = interviews.flatMap(i => 
        dbService.getCodedSegments(i.id)
          .filter(s => s.code_id === c.id)
          .map(s => ({ text: s.segment_text, ref: s.sentence_index }))
      );
      return { label: c.label, segments };
    }).filter(c => c.segments.length > 0);

    const res = await generateReport(project.title, codeSummaries);
    setReport(res);
    setIsGenerating(false);
  };

  const downloadAsWord = () => {
    const codebookHtml = codes.map(c => {
        const segments = interviews.flatMap(i => 
            dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)
        );
        return `
            <h2>Code: ${c.label}</h2>
            <p><i>Total Hits: ${segments.length}</i></p>
            <ul>
                ${segments.map(s => `<li>[Ref #${String(s.sentence_index + 1).padStart(3, '0')}] "${s.segment_text}"</li>`).join('')}
            </ul>
        `;
    }).join('');

    const content = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>Research Report</title></head>
      <body>
        <h1>${project.title} - Research Report</h1>
        <p><strong>Description:</strong> ${project.description}</p>
        <hr/>
        <h2>Synthesis Summary</h2>
        <div>${report ? report.replace(/\n/g, '<br/>') : "No summary generated."}</div>
        <hr/>
        <h1>Detailed Codebook</h1>
        ${codebookHtml}
      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', content], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${project.title.replace(/\s+/g, '_')}_Report.doc`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const downloadAsCSV = () => {
    let csv = "Interview,Code,Segment,Reference,Created At\n";
    interviews.forEach(i => {
      const segments = dbService.getCodedSegments(i.id);
      segments.forEach(s => {
        const code = codes.find(c => c.id === s.code_id);
        const row = [
          `"${i.title.replace(/"/g, '""')}"`,
          `"${code?.label.replace(/"/g, '""') || 'Unknown'}"`,
          `"${s.segment_text.replace(/"/g, '""')}"`,
          `"#${String(s.sentence_index + 1).padStart(3, '0')}"`,
          `"${i.created_at}"`
        ];
        csv += row.join(",") + "\n";
      });
    });

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${project.title.replace(/\s+/g, '_')}_Coding_Data.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const downloadAsRTF = () => {
    let rtf = "{\\rtf1\\ansi\\deff0\n";
    rtf += `{\\fonttbl{\\f0 Arial;}}\n`;
    rtf += `\\b ${project.title} - Research Coding Summary\\b0\\par\n`;
    rtf += `\\line ${project.description}\\par\\line\n`;

    codes.forEach(c => {
      const segments = interviews.flatMap(i => 
        dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)
      );
      if (segments.length > 0) {
        rtf += `\\b Code: ${c.label}\\b0 (Hits: ${segments.length})\\par\n`;
        segments.forEach(s => {
          rtf += `- [#${String(s.sentence_index + 1).padStart(3, '0')}] "${s.segment_text.replace(/[\\}{]/g, '\\$&')}"\\par\n`;
        });
        rtf += `\\line\n`;
      }
    });

    rtf += "}";
    const blob = new Blob([rtf], { type: 'application/rtf' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${project.title.replace(/\s+/g, '_')}_Summary.rtf`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const printReport = () => {
    window.print();
  };

  return (
    <Layout title="Export Center" onBack={onBack}>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Statistics & Insights */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-lg border border-slate/5">
            <h2 className="text-2xl font-bold text-slate mb-6">Project Overview</h2>
            <div className="space-y-4">
              {codes.map(c => {
                const count = interviews.reduce((acc, i) => acc + dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id).length, 0);
                return (
                  <div key={c.id} className="flex flex-col gap-1">
                    <div className="flex items-center justify-between text-sm">
                      <div className="flex items-center gap-2">
                         <div className="w-2 h-2 rounded-full" style={{backgroundColor: c.color}} />
                         <span className="font-bold text-slate">{c.label}</span>
                      </div>
                      <span className="font-mono text-xs opacity-40">{count} hits</span>
                    </div>
                    <div className="h-1.5 w-full bg-slate/5 rounded-full overflow-hidden">
                       <div className="h-full transition-all duration-1000" style={{ backgroundColor: c.color, width: `${Math.min(100, (count / 20) * 100)}%` }} />
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="mt-8 pt-6 border-t border-slate/5">
               <WordCloud data={getWordFrequency(interviews.map(i => i.sentences.join(' ')).join(' '))} />
            </div>
          </div>
        </div>

        {/* Synthesis & Export */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-10 rounded-3xl shadow-lg border border-slate/5 flex flex-col min-h-[500px]">
            <div className="flex justify-between items-center mb-8">
               <div className="space-y-1">
                <h2 className="text-2xl font-bold text-slate">Thematic Synthesis</h2>
                <p className="text-xs text-slate/40 uppercase tracking-widest">Manual Analysis Summary</p>
               </div>
               <button onClick={handleGenerateReport} disabled={isGenerating} className="px-8 py-3 bg-terracotta text-white rounded-xl font-bold shadow-md disabled:opacity-50 hover:bg-terracotta/90 transition-all flex items-center gap-2">
                {isGenerating && <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                {isGenerating ? 'Synthesizing...' : 'Generate AI Synthesis'}
               </button>
            </div>

            <div id="printable-report" className="flex-1 overflow-y-auto prose prose-slate max-w-none text-charcoal/80 leading-relaxed font-serif text-lg p-8 bg-slate/5 rounded-2xl border border-slate/5 italic whitespace-pre-line">
              {report || "Generate a thematic synthesis using your manual coding data. This summary is perfect for including in a formal thesis or report."}
            </div>

            <div className="mt-10">
              <h3 className="text-xs font-bold text-slate/30 uppercase tracking-[0.2em] mb-4">Export Analysis Center</h3>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 <button onClick={downloadAsWord} className="flex flex-col items-center gap-3 p-6 bg-blue-50/50 hover:bg-blue-100/50 border border-blue-100 rounded-2xl transition-all group">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm text-blue-600 group-hover:scale-110 transition-transform">
                      <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6zm1 14H9v-2h6v2zm0-4H9v-2h6v2zm-3-4V3.5L18.5 9H12z"/></svg>
                    </div>
                    <span className="text-[11px] font-bold text-blue-800 uppercase tracking-widest">Word (Doc)</span>
                 </button>

                 <button onClick={downloadAsCSV} className="flex flex-col items-center gap-3 p-6 bg-green-50/50 hover:bg-green-100/50 border border-green-100 rounded-2xl transition-all group">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm text-green-600 group-hover:scale-110 transition-transform">
                      <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6zm1 14H9v-2h6v2zm0-4H9v-2h6v2zm-3-4V3.5L18.5 9H12z"/></svg>
                    </div>
                    <span className="text-[11px] font-bold text-green-800 uppercase tracking-widest">Excel (CSV)</span>
                 </button>

                 <button onClick={downloadAsRTF} className="flex flex-col items-center gap-3 p-6 bg-purple-50/50 hover:bg-purple-100/50 border border-purple-100 rounded-2xl transition-all group">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm text-purple-600 group-hover:scale-110 transition-transform">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                    </div>
                    <span className="text-[11px] font-bold text-purple-800 uppercase tracking-widest">RTF Format</span>
                 </button>

                 <button onClick={printReport} className="flex flex-col items-center gap-3 p-6 bg-orange-50/50 hover:bg-orange-100/50 border border-orange-100 rounded-2xl transition-all group">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm text-orange-600 group-hover:scale-110 transition-transform">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" /></svg>
                    </div>
                    <span className="text-[11px] font-bold text-orange-800 uppercase tracking-widest">PDF (Print)</span>
                 </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-report, #printable-report * { visibility: visible; }
          #printable-report { position: absolute; left: 0; top: 0; padding: 20px; width: 100%; background: white; border: none; font-size: 12pt; font-family: 'Times New Roman', serif; }
        }
      `}</style>
    </Layout>
  );
};

// --- Main App Component ---

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 800);
    }
  }, [user]);

  const handleLogin = (email: string) => {
    const profile = dbService.login(email);
    setUser(profile);
  };

  const handleLogout = () => {
    dbService.logout();
    setUser(null);
    setView('AUTH');
    setCurrentProject(null);
    setCurrentInterview(null);
  };

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const openInterview = (i: Interview) => {
    setCurrentInterview(i);
    setView('INTERVIEW_DETAIL');
  };

  const deleteInterview = (id: string) => {
    if (confirm("Permanently delete this item and all associated coding?")) {
      dbService.deleteInterview(id);
      setInterviews(interviews.filter(i => i.id !== id));
      setView('PROJECT_DETAIL');
    }
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH':
        return <AuthView onLogin={handleLogin} />;
      case 'PROJECTS':
        return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={handleLogout} />;
      case 'CREATE_PROJECT':
        return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'EDIT_PROJECT':
        return currentProject ? <EditProjectView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onUpdated={(p) => { 
          setProjects(projects.map(pj => pj.id === p.id ? p : pj));
          setCurrentProject(p);
          setView('PROJECT_DETAIL');
        }} /> : null;
      case 'PROJECT_DETAIL':
        return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={openInterview} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW':
        return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); openInterview(i); }} /> : null;
      case 'INTERVIEW_DETAIL':
        return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onDelete={() => deleteInterview(currentInterview.id)} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING':
        return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT':
        return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default:
        return <div>Loading...</div>;
    }
  };

  return renderView();
};

