const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 800);
    }
  }, [user]);

  const handleLogin = (email: string) => {
    const profile = dbService.login(email);
    setUser(profile);
  };

  const handleLogout = () => {
    dbService.logout();
    setUser(null);
    setView('AUTH');
    setCurrentProject(null);
    setCurrentInterview(null);
  };

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const openInterview = (i: Interview) => {
    setCurrentInterview(i);
    setView('INTERVIEW_DETAIL');
  };

  const deleteInterview = (id: string) => {
    if (confirm("Delete this source?")) {
      dbService.deleteInterview(id);
      setInterviews(interviews.filter(i => i.id !== id));
      setView('PROJECT_DETAIL');
    }
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH':
        return <AuthView onLogin={handleLogin} />;
      case 'PROJECTS':
        return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={handleLogout} />;
      case 'CREATE_PROJECT':
        return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'EDIT_PROJECT':
        return currentProject ? <EditProjectView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onUpdated={(p) => { 
          setProjects(projects.map(pj => pj.id === p.id ? p : pj));
          setCurrentProject(p);
          setView('PROJECT_DETAIL');
        }} /> : null;
      case 'PROJECT_DETAIL':
        return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={openInterview} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW':
        return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); openInterview(i); }} /> : null;
      case 'INTERVIEW_DETAIL':
        return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onDelete={() => deleteInterview(currentInterview.id)} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING':
        return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT':
        return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default:
        return <div>Loading...</div>;
    }
  };

  return renderView();
};

export default App;

