import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a high-end qualitative research assistant. 
Your task is to take raw input (audio transcription or document text) and transcribe/extract the content EXACTLY as it is written or spoken.
DO NOT summarize.
DO NOT remove filler words.
DO NOT change the phrasing.
DO NOT correct grammar or spelling.
PRESERVE the original language of the input entirely.
Break the content into a JSON array of individual sentences or natural segments. 
Ensure every segment represents the original text verbatim, as this is for qualitative research coding.`;

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `${SYSTEM_PROMPT} Please provide a JSON array of the exact verbatim transcript segments from this audio file.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return ["Error: Transcription failed. Verify the audio format or project API key."];
  }
};

/**
 * Processes document content. 
 * If it's a PDF, we use multimodal inlineData.
 * If it's text (extracted from Word or TXT), we pass it as a text part.
 */
export const processDocument = async (payload: { base64?: string, text?: string, mimeType?: string }): Promise<string[]> => {
  try {
    const parts: any[] = [];

    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT} Extract the text from this PDF exactly as it appears and break it into a JSON array of verbatim sentences.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT} Process the following text and break it into a JSON array of verbatim sentences/segments without any changes or summarization:\n\n${payload.text}` });
    } else {
      throw new Error("Invalid payload: Missing content for processing.");
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Document Processing Error:", error);
    return ["Error: Verbatim document processing failed."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => 
      `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${String(s.ref + 1).padStart(3, '0')}] "${s.text}"`).join('\n')}`
    ).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `You are a qualitative research assistant. Write a formal thematic synthesis for the project "${projectTitle}". 
          Structure the report with an Introduction, Key Findings (referencing the coded segments verbatim), and a Conclusion.

          Coding Data:
          ${context}`
        }]
      }
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

