const RecordInterviewView: React.FC<{ project: Project, onBack: () => void, onInterviewCreated: (i: Interview) => void }> = ({ project, onBack, onInterviewCreated }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordTime, setRecordTime] = useState(0);
  const [mode, setMode] = useState<'select' | 'record' | 'upload'>('select');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64data = reader.result?.toString().split(',')[1];
          if (base64data) {
            setIsProcessing(true);
            const sentences = await transcribeAudio(base64data, 'audio/webm');
            const interview = dbService.createInterview(project.id, `Recorded Interview ${new Date().toLocaleTimeString()}`, sentences);
            onInterviewCreated(interview);
            setIsProcessing(false);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordTime(0);
      timerRef.current = window.setInterval(() => {
        setRecordTime(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error(err);
      alert("Microphone access failed.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) window.clearInterval(timerRef.current);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const isAudio = file.type.startsWith('audio/');
      const isPdf = file.type === 'application/pdf';
      const isWord = file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
      const isText = file.type === 'text/plain';

      let sentences: string[] = [];
      if (isAudio) {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        const base64 = await new Promise<string>((resolve) => {
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
        });
        sentences = await transcribeAudio(base64, file.type);
      } else if (isPdf) {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        const base64 = await new Promise<string>((resolve) => {
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
        });
        sentences = await processDocument({ base64, mimeType: 'application/pdf' });
      } else if (isWord) {
        const buffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer: buffer });
        sentences = await processDocument({ text: result.value });
      } else {
        const text = await file.text();
        sentences = await processDocument({ text });
      }

      const interview = dbService.createInterview(project.id, file.name.replace(/\.[^/.]+$/, ""), sentences);
      onInterviewCreated(interview);
    } catch (err) {
      console.error(err);
      alert("Processing failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout title="Import Data" onBack={onBack}>
      <div className="max-w-4xl mx-auto">
        {isProcessing ? (
          <div className="bg-white p-20 rounded-3xl shadow-lg text-center flex flex-col items-center gap-6">
            <div className="w-16 h-16 border-4 border-terracotta border-t-transparent rounded-full animate-spin" />
            <h2 className="text-2xl font-bold text-slate">AI Verbatim Analysis</h2>
            <p className="text-slate/60">Transcribing and segmenting your data verbatim...</p>
            <p className="text-[10px] uppercase tracking-widest text-slate/30 font-bold mt-2">English • German • Spanish • Russian</p>
          </div>
        ) : mode === 'select' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button 
              onClick={() => setMode('record')}
              className="bg-white p-12 rounded-3xl shadow-lg hover:shadow-xl transition-all border-4 border-transparent hover:border-terracotta flex flex-col items-center gap-6 group"
            >
              <div className="w-20 h-20 bg-terracotta/10 rounded-full flex items-center justify-center text-terracotta group-hover:scale-110 transition-transform">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </div>
              <div className="text-center">
                <h3 className="text-2xl font-bold text-slate">Record Audio</h3>
                <p className="text-slate/60 mt-2">Start a live verbatim recording</p>
                <p className="text-[10px] text-slate/30 font-bold uppercase mt-2">EN, DE, ES, RU Supported</p>
              </div>
            </button>

            <button 
              onClick={() => setMode('upload')}
              className="bg-white p-12 rounded-3xl shadow-lg hover:shadow-xl transition-all border-4 border-transparent hover:border-sage flex flex-col items-center gap-6 group"
            >
              <div className="w-20 h-20 bg-sage/10 rounded-full flex items-center justify-center text-sage group-hover:scale-110 transition-transform">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
              </div>
              <div className="text-center">
                <h3 className="text-2xl font-bold text-slate">Upload File</h3>
                <p className="text-slate/60 mt-2">DOCX, PDF, MP3, or TXT</p>
                <p className="text-[10px] text-slate/30 font-bold uppercase mt-2">Verbatim Multilingual Extraction</p>
              </div>
            </button>
          </div>
        ) : mode === 'record' ? (
          <div className="bg-white p-16 rounded-3xl shadow-lg text-center flex flex-col items-center gap-8">
            <h2 className="text-3xl font-bold text-slate">Multilingual Recorder</h2>
            <div className="text-6xl font-mono font-bold text-slate">
              {formatTime(recordTime)}
            </div>
            {isRecording && (
              <div className="flex gap-2 items-center">
                <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
                <span className="text-red-500 font-bold uppercase tracking-widest text-xs">Recording...</span>
              </div>
            )}
            <div className="flex gap-4">
              {!isRecording ? (
                <button 
                  onClick={startRecording}
                  className="px-10 py-4 bg-terracotta text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all"
                >
                  Start Recording
                </button>
              ) : (
                <button 
                  onClick={stopRecording}
                  className="px-10 py-4 bg-slate text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all"
                >
                  Stop & Process Verbatim
                </button>
              )}
              <button 
                onClick={() => setMode('select')}
                className="px-10 py-4 bg-slate/5 text-slate rounded-2xl font-bold text-xl hover:bg-slate/10 transition-all"
              >
                Cancel
              </button>
            </div>
            <p className="text-xs text-slate/30">Speak in English, German, Spanish, or Russian for verbatim transcription.</p>
          </div>
        ) : (
          <div className="bg-white p-16 rounded-3xl shadow-lg text-center flex flex-col items-center gap-8">
            <h2 className="text-3xl font-bold text-slate">Verbatim Import</h2>
            <p className="text-slate/60">Supported: MP3, WAV, DOCX, PDF, TXT</p>
