const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 500);
    }
  }, [user]);

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH': return <AuthView onLogin={(e) => setUser(dbService.login(e))} />;
      case 'PROJECTS': return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={() => { dbService.logout(); setUser(null); setView('AUTH'); }} />;
      case 'CREATE_PROJECT': return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'PROJECT_DETAIL': return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={(i) => { setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW': return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} /> : null;
      case 'INTERVIEW_DETAIL': return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onDelete={() => { dbService.deleteInterview(currentInterview.id); setInterviews(interviews.filter(i => i.id !== currentInterview.id)); setView('PROJECT_DETAIL'); }} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING': return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT': return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default: return null;
    }
  };

  return renderView();
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a high-end multilingual qualitative research assistant. 
Your primary task is to take raw input (audio transcription or document text) and transcribe/extract the content EXACTLY as it is written or spoken.

SUPPORTED LANGUAGES: English, German, Spanish, Russian. 
You must handle these languages with native-level accuracy.

RULES:
1. DO NOT summarize.
2. DO NOT remove filler words (e.g., "uh", "um", "well", "ah").
3. DO NOT change the phrasing or translate the content.
4. DO NOT correct grammar or spelling.
5. PRESERVE the original language and dialect entirely.
6. Break the content into a JSON array of individual sentences or natural segments. 

Ensure every segment represents the original text verbatim, as this is for strict qualitative research coding.`;

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `${SYSTEM_PROMPT} Please provide a JSON array of the exact verbatim transcript segments from this audio file. The speaker might be using English, German, Spanish, or Russian.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return ["Error: Transcription failed. Verify the audio format or project API key."];
  }
};

/**
 * Processes document content. 
 * If it's a PDF, we use multimodal inlineData.
 * If it's text (extracted from Word or TXT), we pass it as a text part.
 */
export const processDocument = async (payload: { base64?: string, text?: string, mimeType?: string }): Promise<string[]> => {
  try {
    const parts: any[] = [];

    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT} Extract the text from this PDF exactly as it appears and break it into a JSON array of verbatim sentences. The document may be in English, German, Spanish, or Russian.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT} Process the following text and break it into a JSON array of verbatim sentences/segments without any changes or summarization. The text may be in English, German, Spanish, or Russian:\n\n${payload.text}` });
    } else {
      throw new Error("Invalid payload: Missing content for processing.");
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Document Processing Error:", error);
    return ["Error: Verbatim document processing failed."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => 
      `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${String(s.ref + 1).padStart(3, '0')}] "${s.text}"`).join('\n')}`
    ).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `You are a qualitative research assistant. Write a formal thematic synthesis for the project "${projectTitle}". 
          The analysis should be based on the provided coded segments.
          Structure the report with an Introduction, Key Findings (referencing the coded segments verbatim), and a Conclusion.
          If the quotes are in German, Spanish, or Russian, you may provide English analysis but must keep the quotes verbatim in their original language.

          Coding Data:
          ${context}`
        }]
      }
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

