const CodingView: React.FC<{ 
  interview: Interview, 
  project: Project, 
  codes: Code[], 
  onFinish: () => void, 
  onCodeCreated: (c: Code) => void 
}> = ({ interview, project, codes, onFinish, onCodeCreated }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [selectionOffsets, setSelectionOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeCodedSegments, setActiveCodedSegments] = useState<CodedSegment[]>(dbService.getCodedSegments(interview.id));
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);

  const handleTextSelection = (idx: number) => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim().length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      setSelectedIdx(idx);
      setSelectedText(selection.toString().trim());
      setSelectionOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      setFloatingMenuPos(null);
    }
  };

  const handleApplyCode = (code: Code) => {
    if (selectedIdx === null || !selectionOffsets) return;
    dbService.saveCodedSegment({ 
      interview_id: interview.id, 
      code_id: code.id, 
      segment_text: selectedText, 
      sentence_index: selectedIdx,
      start_char: selectionOffsets.start,
      end_char: selectionOffsets.end
    });
    showToast.success('Code applied');
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    window.getSelection()?.removeAllRanges();
  };

  const handleCreateAndApply = (label: string, color: string, isInVivo?: boolean) => {
    if (selectedIdx === null || !selectionOffsets) return;
    const newCode = dbService.createCode(project.id, label, color, undefined, isInVivo);
    onCodeCreated(newCode);
    handleApplyCode(newCode);
  };

  const handleDeleteSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    showToast.success('Coding segment removed');
    setActiveCodedSegments(dbService.getCodedSegments(interview.id));
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-xs text-slate/40 truncate max-w-[200px]">{interview.title}</p>
        </div>
        <button onClick={onFinish} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:bg-slate/90 transition-colors">Done</button>
      </header>

      <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center animate-fade-in">
        <div className="max-w-4xl w-full space-y-12 pb-40">
          {interview.sentences.map((s, idx) => {
            const sentenceSegments = activeCodedSegments.filter(seg => seg.sentence_index === idx);
            return (
              <div key={idx} onMouseUp={() => handleTextSelection(idx)} className="group relative">
                <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-bold text-slate/20">#{String(idx + 1).padStart(3, '0')}</span>
                   <div className="flex flex-wrap gap-1">
                      {sentenceSegments.map(seg => {
                        const code = codes.find(c => c.id === seg.code_id);
                        return code && (
                          <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 group/chip" style={{ backgroundColor: code.color }}>
                            {code.is_invivo && <span>⚡</span>}
                            {code.label}
                            <button onClick={(e) => { e.stopPropagation(); handleDeleteSegment(seg.id); }} className="hover:text-black ml-1">×</button>
                          </div>
                        );
                      })}
                   </div>
                </div>
                <div className="text-2xl leading-relaxed text-charcoal/90 font-serif whitespace-pre-wrap select-text">
                  <GranularHighlighter text={s} segments={sentenceSegments} codes={codes} />
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {floatingMenuPos && (
        <div className="fixed z-[60] -translate-x-1/2 -translate-y-full mb-4 animate-in zoom-in-50 duration-200" style={{ left: floatingMenuPos.x, top: floatingMenuPos.y }}>
          <button onClick={() => setIsModalOpen(true)} className="px-6 py-3 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-2 hover:scale-105 active:scale-95 transition-all">
            Code Selection
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        sentenceText={selectedIdx !== null ? interview.sentences[selectedIdx] : ''}
        selectedSnippet={selectedText}
        sentenceIndex={selectedIdx || 0}
        interviewId={interview.id}
        projectId={project.id}
        existingCodes={codes}
        onApply={handleApplyCode}
        onCreateAndApply={handleCreateAndApply}
      />
    </div>
  );
};

const ExportView: React.FC<{ project: Project, interviews: Interview[], codes: Code[], onBack: () => void }> = ({ project, interviews, codes, onBack }) => {
  const [report, setReport] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const codeSummaries = codes.map(c => {
      const segments = interviews.flatMap(i => 
        dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id).map(s => ({ text: s.segment_text, ref: s.sentence_index }))
      );
      return { label: c.label, segments };
    }).filter(c => c.segments.length > 0);

    const promise = generateReport(project.title, codeSummaries);
    showToast.promise(promise, {
      loading: 'Generating thematic analysis...',
      success: 'Analysis complete!',
      error: 'Analysis generation failed.'
    });

    setReport(await promise);
    setIsGenerating(false);
  };

  const downloadAsWord = () => {
    const codebookHtml = codes.map(c => {
      const segments = interviews.flatMap(i => 
        dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id)
      );
      if (segments.length === 0) return '';
      return `<h2>Code: ${c.label} ${c.is_invivo ? '(In Vivo)' : ''}</h2><ul>${segments.map(s => `<li>[#${s.sentence_index + 1}] "${s.segment_text}"</li>`).join('')}</ul>`;
    }).join('');

    const content = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>${project.title} Report</title></head>
      <body style="font-family: Arial, sans-serif; padding: 40px;">
        <h1 style="color: #3D405B;">${project.title} Academic Report</h1>
        <p style="color: #666;">Generated via QUILTA - Qualitative Research Studio</p>
        <hr/>
        <h3 style="color: #E07A5F;">Thematic Synthesis (AI-Generated)</h3>
        <p style="white-space: pre-line; line-height: 1.6;">${report}</p>
        <hr/>
        <h3 style="color: #3D405B;">Verbatim Codebook</h3>
        ${codebookHtml}
      </body>
      </html>
    `;
    const blob = new Blob(['\ufeff', content], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${project.title.replace(/\s+/g, '_')}_Report.doc`;
    link.click();
    URL.revokeObjectURL(url);
    showToast.success('Word report downloaded');
  };

  const downloadAsCSV = () => {
    let csvContent = "Source,Code,Verbatim Segment,Reference Index\n";
    interviews.forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        const code = codes.find(c => c.id === s.code_id);
        const segment = s.segment_text.replace(/"/g, '""');
        const source = i.title.replace(/"/g, '""');
        csvContent += `"${source}","${code?.label || 'Unlabeled'}","${segment}","#${s.sentence_index + 1}"\n`;
      });
    });
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${project.title.replace(/\s+/g, '_')}_Verbatim_Data.csv`;
    link.click();
    URL.revokeObjectURL(url);
    showToast.success('CSV data downloaded');
  };

  return (
    <Layout title="Export Center" onBack={onBack}>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pb-32 animate-fade-in">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-lg border border-slate/5 sticky top-24">
            <h2 className="text-2xl font-bold text-slate mb-6">Research Summary</h2>
            <div className="space-y-4 mb-8">
              {codes.length === 0 ? (
                <p className="text-slate/30 text-sm italic">No codes applied yet.</p>
              ) : (
                codes.map(c => {
                  const count = interviews.reduce((acc, i) => acc + dbService.getCodedSegments(i.id).filter(s => s.code_id === c.id).length, 0);
                  return (
                    <div key={c.id} className="flex flex-col gap-1">
                      <div className="flex items-center justify-between text-sm">
                        <span className="font-bold text-slate truncate pr-2">{c.label} {c.is_invivo && "(⚡)"}</span>
                        <span className="font-mono opacity-40 shrink-0">{count}</span>
                      </div>
                      <div className="h-2 w-full bg-slate/5 rounded-full overflow-hidden">
                        <div className="h-full transition-all duration-1000" style={{ backgroundColor: c.color, width: `${Math.min(100, (count / 10) * 100)}%` }} />
                      </div>
                    </div>
                  );
                })
              )}
            </div>

            <div className="pt-6 border-t border-slate/5 grid grid-cols-1 gap-3">
               <button onClick={downloadAsWord} className="w-full py-4 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-md hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                 Download .DOC
               </button>
               <button onClick={downloadAsCSV} className="w-full py-4 bg-green-600 text-white rounded-xl font-bold text-sm shadow-md hover:bg-green-700 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                 Download .CSV
               </button>
               <button onClick={() => { window.print(); showToast.success('Print dialog opened'); }} className="w-full py-4 bg-orange-600 text-white rounded-xl font-bold text-sm shadow-md hover:bg-orange-700 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                 Export PDF / Print
               </button>
            </div>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-10 rounded-3xl shadow-lg min-h-[600px] flex flex-col border border-slate/5">
            <div className="flex justify-between items-center mb-8">
               <div className="flex flex-col">
                 <h2 className="text-2xl font-bold text-slate">Academic Synthesis</h2>
                 <p className="text-xs text-slate/30 uppercase tracking-widest font-bold mt-1">AI-Powered Thematic Report</p>
               </div>
               <button 
                onClick={handleGenerateReport} 
                disabled={isGenerating} 
                className="px-6 py-3 bg-terracotta text-white rounded-xl font-bold shadow-md hover:scale-105 transition-all disabled:opacity-50 active:scale-95"
               >
                {isGenerating ? 'Synthesizing...' : 'Generate Analysis'}
               </button>
            </div>
            <div id="printable-report" className="flex-1 prose prose-slate max-w-none text-lg p-10 bg-slate/5 rounded-2xl border border-slate/5 italic whitespace-pre-line overflow-y-auto max-h-[700px] font-serif leading-relaxed text-charcoal">
              {report || "Generate your thematic synthesis based on the verbatim coding data collected across your project sources."}
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-report, #printable-report * { visibility: visible; }
          #printable-report { position: absolute; left: 0; top: 0; padding: 40px; width: 100%; background: white; border: none; font-style: normal; }
        }
      `}</style>
    </Layout>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('AUTH');
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [user, setUser] = useState<Profile | null>(dbService.getCurrentUser());
  const [projects, setProjects] = useState<Project[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoadingProjects, setIsLoadingProjects] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoadingProjects(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoadingProjects(false), 500);
    }
  }, [user]);

  const openProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH': return <AuthView onLogin={(e) => setUser(dbService.login(e))} />;
      case 'PROJECTS': return <ProjectsView projects={projects} isLoading={isLoadingProjects} onOpen={openProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={() => { dbService.logout(); setUser(null); setView('AUTH'); }} />;
      case 'CREATE_PROJECT': return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); openProject(p); }} />;
      case 'PROJECT_DETAIL': return currentProject ? <ProjectDetailView project={currentProject} interviews={interviews} onBack={() => setView('PROJECTS')} onEdit={() => setView('EDIT_PROJECT')} onOpenInterview={(i) => { setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} onAddInterview={() => setView('RECORD_INTERVIEW')} onExport={() => setView('EXPORT')} /> : null;
      case 'RECORD_INTERVIEW': return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} /> : null;
      case 'INTERVIEW_DETAIL': return currentInterview ? <InterviewDetailView interview={currentInterview} onBack={() => setView('PROJECT_DETAIL')} onDelete={() => { dbService.deleteInterview(currentInterview.id); setInterviews(interviews.filter(i => i.id !== currentInterview.id)); setView('PROJECT_DETAIL'); }} onStartCoding={() => setView('CODING')} /> : null;
      case 'CODING': return currentInterview && currentProject ? <CodingView interview={currentInterview} project={currentProject} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodeCreated={(c) => setCodes([...codes, c])} /> : null;
      case 'EXPORT': return currentProject ? <ExportView project={currentProject} interviews={interviews} codes={codes} onBack={() => setView('PROJECT_DETAIL')} /> : null;
      default: return null;
    }
  };

  return (
    <>
      <Toaster position="top-right" />
      {renderView()}
    </>
  );
};

export default App;

