import { useState, useEffect } from 'react';
import { dbService } from '../../../services/dbService';
import { Code, CodedSegment } from '../../../types';
import { showToast } from '../../../lib/toast';

export const useCoding = (projectId?: string, interviewId?: string) => {
  const [codes, setCodes] = useState<Code[]>([]);
  const [segments, setSegments] = useState<CodedSegment[]>([]);

  useEffect(() => {
    if (projectId) setCodes(dbService.getCodes(projectId));
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
  }, [projectId, interviewId]);

  const addCode = (label: string, color: string, isInVivo?: boolean) => {
    if (!projectId) return;
    const newCode = dbService.createCode(projectId, label, color, undefined, isInVivo);
    setCodes(prev => [...prev, newCode]);
    return newCode;
  };

  const applyCode = (codeId: string, segmentText: string, sentenceIndex: number, start: number, end: number) => {
    if (!interviewId) return;
    const segment = dbService.saveCodedSegment({
      interview_id: interviewId,
      code_id: codeId,
      segment_text: segmentText,
      sentence_index: sentenceIndex,
      start_char: start,
      end_char: end
    });
    setSegments(prev => [...prev, segment]);
    showToast.success('Code applied');
  };

  const removeSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setSegments(prev => prev.filter(s => s.id !== id));
    showToast.success('Coding removed');
  };

  return {
    codes,
    segments,
    addCode,
    applyCode,
    removeSegment
  };
};

import React from 'react';
import { CodedSegment, Code } from '../../../types';

interface GranularHighlighterProps {
  text: string;
  segments: CodedSegment[];
  codes: Code[];
}

export const GranularHighlighter: React.FC<GranularHighlighterProps> = ({ text, segments, codes }) => {
  if (segments.length === 0) return <>{text}</>;

  const boundaries = new Set<number>([0, text.length]);
  segments.forEach(s => {
    if (s.start_char !== undefined) boundaries.add(s.start_char);
    if (s.end_char !== undefined) boundaries.add(s.end_char);
  });

  const sortedBoundaries = Array.from(boundaries).sort((a, b) => a - b);
  const parts: React.ReactNode[] = [];

  for (let i = 0; i < sortedBoundaries.length - 1; i++) {
    const start = sortedBoundaries[i];
    const end = sortedBoundaries[i + 1];
    const partText = text.substring(start, end);

    const matchingSegments = segments.filter(s => 
      s.start_char !== undefined && s.end_char !== undefined &&
      start >= s.start_char && end <= s.end_char
    );

    if (matchingSegments.length > 0) {
      const lastSegment = matchingSegments[matchingSegments.length - 1];
      const code = codes.find(c => c.id === lastSegment.code_id);

      parts.push(
        <mark 
          key={`${start}-${end}`} 
          style={{ 
            backgroundColor: (code?.color || '#eee') + '44',
            borderBottom: `2px solid ${code?.color || '#ccc'}`,
            color: 'inherit'
          }}
          className="transition-colors duration-200"
          title={code?.label}
        >
          {partText}
        </mark>
      );
    } else {
      parts.push(<span key={`${start}-${end}`}>{partText}</span>);
    }
  }

  return <>{parts}</>;
};

