## DAY 15-17: REAL AI TRANSCRIPTION

1. Set up Google Cloud Speech-to-Text:

Install dependencies:
```bash
npm install @google-cloud/speech
```

2. Update `src/services/geminiService.ts`:

Replace mock transcribeAudio with real implementation:
```typescript
import { SpeechClient } from '@google-cloud/speech';

const speechClient = new SpeechClient({
  apiKey: import.meta.env.VITE_GOOGLE_CLOUD_API_KEY,
});

export async function transcribeAudio(
  base64Audio: string, 
  mimeType: string
): Promise<string[]> {
  try {
    const audio = {
      content: base64Audio,
    };

    const config = {
      encoding: mimeType.includes('webm') ? 'WEBM_OPUS' : 'MP3',
      sampleRateHertz: 48000,
      languageCode: 'en-US',
      alternativeLanguageCodes: ['de-DE', 'es-ES', 'ru-RU'],
      enableAutomaticPunctuation: true,
      enableWordTimeOffsets: false,
      model: 'latest_long',
    };

    const request = {
      audio,
      config,
    };

    const [operation] = await speechClient.longRunningRecognize(request);
    const [response] = await operation.promise();

    const transcription = response.results
      ?.map(result => result.alternatives?.[0]?.transcript || '')
      .join(' ') || '';

    // Split into sentences
    const sentences = transcription
      .split(/[.!?]+/)
      .map(s => s.trim())
      .filter(s => s.length > 0);

    return sentences;
  } catch (error) {
    console.error('Transcription error:', error);
    throw new Error('Transcription failed: ' + (error as Error).message);
  }
}
```

