import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a high-end multilingual qualitative research assistant. 
Your primary task is to take raw input (audio transcription or document text) and transcribe/extract the content EXACTLY as it is written or spoken.

SUPPORTED LANGUAGES: English, German, Spanish, Russian. 
You must handle these languages with native-level accuracy.

RULES:
1. DO NOT summarize.
2. DO NOT remove filler words (e.g., "uh", "um", "well", "ah").
3. DO NOT change the phrasing or translate the content.
4. DO NOT correct grammar or spelling.
5. PRESERVE the original language and dialect entirely.
6. Break the content into a JSON array of individual sentences or natural segments. 

Ensure every segment represents the original text verbatim, as this is for strict qualitative research coding.`;

export const transcribeAudio = async (base64Data: string, mimeType: string, languageLabel: string = "English"): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      contents: [
        {
          role: 'user',
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: `${SYSTEM_PROMPT} Please provide a JSON array of the exact verbatim transcript segments from this audio file. The speaker is using ${languageLabel}.` }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return ["Error: Transcription failed. Verify the audio format or project API key."];
  }
};

/**
 * Processes document content. 
 */
export const processDocument = async (payload: { base64?: string, text?: string, mimeType?: string }): Promise<string[]> => {
  try {
    const parts: any[] = [];

    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT} Extract the text from this PDF exactly as it appears and break it into a JSON array of verbatim sentences. The document may be in English, German, Spanish, or Russian.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT} Process the following text and break it into a JSON array of verbatim sentences/segments without any changes or summarization. The text may be in English, German, Spanish, or Russian:\n\n${payload.text}` });
    } else {
      throw new Error("Invalid payload: Missing content for processing.");
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Document Processing Error:", error);
    return ["Error: Verbatim document processing failed."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  try {
    const context = codes.map(c => 
      `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${String(s.ref + 1).padStart(3, '0')}] "${s.text}"`).join('\n')}`
    ).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{
          text: `You are a qualitative research assistant. Write a formal thematic synthesis for the project "${projectTitle}". 
          The analysis should be based on the provided coded segments.
          Structure the report with an Introduction, Key Findings (referencing the coded segments verbatim), and a Conclusion.
          If the quotes are in German, Spanish, or Russian, you may provide English analysis but must keep the quotes verbatim in their original language.

          Coding Data:
          ${context}`
        }]
      }
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Error:", error);
    return "Failed to generate report summary.";
  }
};

export const getWordFrequency = (text: string): { word: string, count: number }[] => {
  const words = text.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !['this', 'that', 'with', 'from', 'they', 'their', 'there', 'them'].includes(w));

  const counts: Record<string, number> = {};
  words.forEach(w => counts[w] = (counts[w] || 0) + 1);

  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .map(([word, count]) => ({ word, count }));
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import mammoth from 'mammoth';
import Layout from '../../../shared/components/Layout';
import { ProcessingSpinner } from '../../../shared/components/LoadingStates';
import { transcribeAudio, processDocument } from '../../../services/geminiService';
import { useInterviews } from '../hooks/useInterviews';
import { showToast } from '../../../lib/toast';

const LANGUAGES = [
  { code: 'en-US', label: 'English' },
  { code: 'de-DE', label: 'German' },
  { code: 'es-ES', label: 'Spanish' },
  { code: 'ru-RU', label: 'Russian' },
];

const RecordInterviewView: React.FC = () => {
  const { projectId } = useParams();
  const navigate = useNavigate();
  const { createInterview } = useInterviews(projectId);

  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordTime, setRecordTime] = useState(0);
  const [mode, setMode] = useState<'select' | 'record' | 'upload'>('select');
  const [selectedLanguage, setSelectedLanguage] = useState(LANGUAGES[0].code);
  const [transcriptionProgress, setTranscriptionProgress] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await handleTranscription(audioBlob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordTime(0);
      timerRef.current = window.setInterval(() => {
        setRecordTime(prev => prev + 1);
      }, 1000);
      showToast.success('Recording started');
    } catch (err) {
      console.error(err);
      showToast.error('Microphone access failed.');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) window.clearInterval(timerRef.current);
    }
  };

  const handleTranscription = async (audioBlob: Blob) => {
    setIsProcessing(true);
    setTranscriptionProgress(10);

    const languageLabel = LANGUAGES.find(l => l.code === selectedLanguage)?.label || 'English';

    try {
      const progressInterval = setInterval(() => {
        setTranscriptionProgress(prev => Math.min(prev + 5, 90));
      }, 800);

      const reader = new FileReader();
      const base64 = await new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(audioBlob);
      });

      const promise = transcribeAudio(base64, audioBlob.type, languageLabel);
      showToast.promise(promise, {
        loading: `Transcribing ${languageLabel} audio verbatim...`,
        success: 'Transcription complete!',
        error: 'Transcription failed.'
      });

      const sentences = await promise;
      clearInterval(progressInterval);
      setTranscriptionProgress(100);

      const interview = createInterview(`Recorded ${languageLabel} Interview ${new Date().toLocaleTimeString()}`, sentences);
      if (interview) navigate(`/projects/${projectId}/interviews/${interview.id}`);
    } catch (err) {
      showToast.error('Transcription failed');
    } finally {
      setIsProcessing(false);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setTranscriptionProgress(10);
    try {
      const isAudio = file.type.startsWith('audio/');
      const isPdf = file.type === 'application/pdf';
      const isWord = file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';

      const progressInterval = setInterval(() => {
        setTranscriptionProgress(prev => Math.min(prev + 15, 95));
      }, 500);

      const promise = (async () => {
        if (isAudio) {
          const reader = new FileReader();
          reader.readAsDataURL(file);
          const base64 = await new Promise<string>((resolve) => {
            reader.onload = () => resolve((reader.result as string).split(',')[1]);
          });
          return await transcribeAudio(base64, file.type, LANGUAGES.find(l => l.code === selectedLanguage)?.label);
        } else if (isPdf) {
          const reader = new FileReader();
          reader.readAsDataURL(file);
          const base64 = await new Promise<string>((resolve) => {
            reader.onload = () => resolve((reader.result as string).split(',')[1]);
          });
          return await processDocument({ base64, mimeType: 'application/pdf' });
        } else if (isWord) {
          const buffer = await file.arrayBuffer();
          const result = await mammoth.extractRawText({ arrayBuffer: buffer });
          return await processDocument({ text: result.value });
        } else {
          const text = await file.text();
          return await processDocument({ text });
        }
      })();

      showToast.promise(promise, {
        loading: 'Extracting verbatim text...',
        success: 'File processed!',
        error: 'Processing failed.'
      });

      const sentences = await promise;
      clearInterval(progressInterval);
      setTranscriptionProgress(100);

      const interview = createInterview(file.name.replace(/\.[^/.]+$/, ""), sentences);
      if (interview) navigate(`/projects/${projectId}/interviews/${interview.id}`);
    } catch (err) {
      console.error(err);
      showToast.error('Processing failed');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout title="Import Data" onBack={() => navigate(`/projects/${projectId}`)}>
      <div className="max-w-4xl mx-auto animate-fade-in">
        {isProcessing ? (
          <div className="space-y-6">
            <ProcessingSpinner message="Synthesizing and segmenting your data verbatim..." />
            <div className="w-full bg-slate/10 rounded-full h-3 overflow-hidden">
              <div 
                className="h-full bg-terracotta transition-all duration-500"
                style={{ width: `${transcriptionProgress}%` }}
              />
            </div>
            <p className="text-center text-sm font-bold text-slate/40 uppercase tracking-widest">
              {transcriptionProgress}% complete
            </p>
          </div>
        ) : mode === 'select' ? (
          <div className="space-y-8">
            <div className="flex flex-col items-center gap-4 bg-white p-8 rounded-3xl border border-slate/5 shadow-sm">
              <label className="text-xs font-bold text-slate/40 uppercase tracking-widest">Input Language</label>
              <select 
                value={selectedLanguage}
                onChange={(e) => setSelectedLanguage(e.target.value)}
                className="px-6 py-3 bg-cream/50 rounded-xl border-2 border-slate/10 font-bold text-slate outline-none focus:border-terracotta transition-all"
              >
                {LANGUAGES.map(lang => (
                  <option key={lang.code} value={lang.code}>{lang.label}</option>
                ))}
              </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <button 
                onClick={() => setMode('record')}
                className="bg-white p-12 rounded-3xl shadow-lg hover:shadow-xl transition-all border-4 border-transparent hover:border-terracotta flex flex-col items-center gap-6 group"
              >
                <div className="w-20 h-20 bg-terracotta/10 rounded-full flex items-center justify-center text-terracotta group-hover:scale-110 transition-transform">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </div>
                <div className="text-center">
                  <h3 className="text-2xl font-bold text-slate">Record Audio</h3>
                  <p className="text-slate/60 mt-2">Start a live verbatim recording</p>
                </div>
              </button>

              <button 
                onClick={() => setMode('upload')}
                className="bg-white p-12 rounded-3xl shadow-lg hover:shadow-xl transition-all border-4 border-transparent hover:border-sage flex flex-col items-center gap-6 group"
              >
                <div className="w-20 h-20 bg-sage/10 rounded-full flex items-center justify-center text-sage group-hover:scale-110 transition-transform">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                </div>
                <div className="text-center">
                  <h3 className="text-2xl font-bold text-slate">Upload File</h3>
                  <p className="text-slate/60 mt-2">DOCX, PDF, MP3, or TXT</p>
                </div>
              </button>
            </div>
          </div>
        ) : mode === 'record' ? (
          <div className="bg-white p-16 rounded-3xl shadow-lg text-center flex flex-col items-center gap-8">
            <h2 className="text-3xl font-bold text-slate">Recorder ({LANGUAGES.find(l => l.code === selectedLanguage)?.label})</h2>
            <div className="text-6xl font-mono font-bold text-slate">
              {formatTime(recordTime)}
            </div>
            {isRecording && (
              <div className="flex gap-2 items-center">
                <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
                <span className="text-red-500 font-bold uppercase tracking-widest text-xs">Recording...</span>
              </div>
            )}
            <div className="flex gap-4">
              {!isRecording ? (
                <button 
                  onClick={startRecording}
                  className="px-10 py-4 bg-terracotta text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all"
                >
                  Start Recording
                </button>
              ) : (
                <button 
                  onClick={stopRecording}
                  className="px-10 py-4 bg-slate text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all"
                >
                  Stop & Process Verbatim
                </button>
              )}
              <button 
                onClick={() => setMode('select')}
                className="px-10 py-4 bg-slate/5 text-slate rounded-2xl font-bold text-xl hover:bg-slate/10 transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        ) : (
          <div className="bg-white p-16 rounded-3xl shadow-lg text-center flex flex-col items-center gap-8">
            <h2 className="text-3xl font-bold text-slate">Verbatim Import</h2>
            <p className="text-slate/60">Supported: MP3, WAV, DOCX, PDF, TXT</p>
            <input 
              type="file" 
              id="file-upload" 
              className="hidden" 
              onChange={handleFileUpload}
              accept="audio/*,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document,text/plain"
            />
            <label 
              htmlFor="file-upload" 
              className="cursor-pointer group flex flex-col items-center p-20 border-4 border-dashed border-slate/10 hover:border-sage transition-all rounded-3xl bg-slate/5 w-full"
            >
              <svg className="w-16 h-16 mb-4 text-slate/20 group-hover:text-sage transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
              <p className="text-xl font-bold text-slate">Click to browse files for exact extraction</p>
            </label>
            <button 
              onClick={() => setMode('select')}
              className="px-10 py-4 bg-slate/5 text-slate rounded-2xl font-bold text-xl hover:bg-slate/10 transition-all"
            >
              Back
            </button>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default RecordInterviewView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, applyCode, removeSegment } = useCoding(projectId, interviewId);

  const interview = interviewId ? dbService.getInterviewById(interviewId) : null;

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [selectionOffsets, setSelectionOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [selectedSentenceIndices, setSelectedSentenceIndices] = useState<number[]>([]);
  const [showShortcuts, setShowShortcuts] = useState(false);

  // Keyboard Shortcuts Configuration
  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || selectedSentenceIndices.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        const lastSegment = segments[segments.length - 1];
        removeSegment(lastSegment.id);
        showToast.success('Undone last code');
      }
    },
    showHelp: () => setShowShortcuts(true),
  });

  const codeUsageCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    const allInterviews = projectId ? dbService.getInterviews(projectId) : [];
    allInterviews.forEach(int => {
      dbService.getCodedSegments(int.id).forEach(seg => {
        counts[seg.code_id] = (counts[seg.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  if (!interview) return null;

  const handleTextSelection = (idx: number) => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim().length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      setSelectedIdx(idx);
      setSelectedText(selection.toString().trim());
      setSelectionOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      setFloatingMenuPos(null);
    }
  };

  const handleSegmentClick = (idx: number, e: React.MouseEvent) => {
    if (e.ctrlKey || e.metaKey) {
      setSelectedSentenceIndices(prev => 
        prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
      );
    } else {
      setSelectedSentenceIndices([idx]);
    }
  };

  const handleApply = (code: Code) => {
    if (selectedSentenceIndices.length > 1) {
      // Batch apply to multiple sentences
      selectedSentenceIndices.forEach(idx => {
        applyCode(code.id, interview.sentences[idx], idx, 0, interview.sentences[idx].length);
      });
      showToast.success(`Applied ${code.label} to ${selectedSentenceIndices.length} segments`);
      setSelectedSentenceIndices([]);
    } else if (selectedIdx !== null && selectionOffsets) {
      // Single selection
      applyCode(code.id, selectedText, selectedIdx, selectionOffsets.start, selectionOffsets.end);
    }

    setIsModalOpen(false);
    setFloatingMenuPos(null);
    window.getSelection()?.removeAllRanges();
  };

  const handleCreateAndApply = (label: string, color: string, isInVivo?: boolean) => {
    const newCode = addCode(label, color, isInVivo);
    if (newCode) handleApply(newCode);
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-xs text-slate/40 truncate max-w-[200px]">{interview.title}</p>
        </div>
        <div className="flex items-center gap-4">
          <button onClick={() => setShowShortcuts(true)} className="p-2 text-slate/30 hover:text-slate transition-colors" title="Keyboard Shortcuts">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 transition-all active:scale-95">Done</button>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center animate-fade-in">
        <div className="max-w-4xl w-full space-y-12 pb-40">
          {interview.sentences.map((s, idx) => {
            const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
            const isSelected = selectedSentenceIndices.includes(idx);

            return (
              <div 
                key={idx} 
                onMouseUp={() => handleTextSelection(idx)} 
                onClick={(e) => handleSegmentClick(idx, e)}
                className={`group relative p-4 -m-4 rounded-2xl transition-all cursor-pointer ${isSelected ? 'bg-terracotta/5 border-2 border-terracotta/20' : 'hover:bg-slate/5'}`}
              >
                <div className="flex items-center gap-2 mb-2">
                   <span className={`text-[10px] font-bold ${isSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                   <div className="flex flex-wrap gap-1">
                      {sentenceSegments.map(seg => {
                        const code = codes.find(c => c.id === seg.code_id);
                        return code && (
                          <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                            {code.label}
                            <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                          </div>
                        );
                      })}
                   </div>
                </div>
                <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap select-text ${isSelected ? 'text-charcoal' : 'text-charcoal/90'}`}>
                  <GranularHighlighter text={s} segments={sentenceSegments} codes={codes} />
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {(floatingMenuPos || selectedSentenceIndices.length > 0) && (
        <div 
          className="fixed z-[60] -translate-x-1/2 -translate-y-full mb-4 animate-in zoom-in-50 duration-200" 
          style={{ 
            left: floatingMenuPos ? floatingMenuPos.x : '50%', 
            top: floatingMenuPos ? floatingMenuPos.y : 'unset',
            bottom: floatingMenuPos ? 'unset' : '40px'
          }}
        >
          <button onClick={() => setIsModalOpen(true)} className="px-8 py-4 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
            Code {selectedSentenceIndices.length > 1 ? `${selectedSentenceIndices.length} Segments` : 'Selection'}
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={selectedSentenceIndices.length > 1 ? `Multiple segments (${selectedSentenceIndices.length})` : selectedText}
        existingCodes={codes}
        onApply={handleApply}
        onCreateAndApply={handleCreateAndApply}
        codeUsageCounts={codeUsageCounts}
      />

      <ConfirmDialog
        isOpen={showShortcuts}
        title="Keyboard Shortcuts"
        message="Ctrl/Cmd + K: Open code modal | Ctrl/Cmd + Z: Undo last code | Ctrl + Click: Multi-select | ESC: Close modal | ?: Show help"
        confirmText="Got it"
        onConfirm={() => setShowShortcuts(false)}
        onCancel={() => setShowShortcuts(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { Code } from '../../../types';
import { CODE_COLORS } from '../../../constants';

interface CodeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedSnippet: string;
  existingCodes: Code[];
  onApply: (code: Code) => void;
  onCreateAndApply: (label: string, color: string, isInVivo?: boolean) => void;
  codeUsageCounts?: Record<string, number>;
}

const CodeSelectionModal: React.FC<CodeSelectionModalProps> = ({
  isOpen,
  onClose,
  selectedSnippet,
  existingCodes,
  onApply,
  onCreateAndApply,
  codeUsageCounts = {}
}) => {
  const [newCodeLabel, setNewCodeLabel] = useState('');
  const [selectedColor, setSelectedColor] = useState(CODE_COLORS[0]);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredCodes = useMemo(() => {
    return existingCodes.filter(code => 
      code.label.toLowerCase().includes(searchQuery.toLowerCase())
    ).sort((a, b) => (codeUsageCounts[b.id] || 0) - (codeUsageCounts[a.id] || 0));
  }, [existingCodes, searchQuery, codeUsageCounts]);

  if (!isOpen) return null;

  const handleCreate = () => {
    if (newCodeLabel.trim().length >= 2) {
      onCreateAndApply(newCodeLabel.trim(), selectedColor, false);
      setNewCodeLabel('');
    }
  };

  const handleInVivo = () => {
    if (selectedSnippet.trim().length >= 1 && !selectedSnippet.startsWith('Multiple segments')) {
      onCreateAndApply(selectedSnippet.trim(), selectedColor, true);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center bg-slate/40 backdrop-blur-sm">
      <div className="fixed inset-0" onClick={onClose} />
      <div 
        className="relative w-full max-w-2xl bg-cream rounded-t-[32px] shadow-2xl flex flex-col max-h-[90vh] animate-in slide-in-from-bottom-full duration-300"
        style={{ height: '85%' }}
      >
        <div className="w-12 h-1.5 bg-slate/10 rounded-full mx-auto mt-4 mb-2" />
        <div className="p-8 overflow-y-auto flex-1 space-y-10">
          <header className="flex justify-between items-start">
            <div>
              <h2 className="text-3xl font-bold text-slate">Assign Code</h2>
              <p className="text-slate/40 text-xs font-bold uppercase tracking-widest mt-1">Research Taxonomy</p>
            </div>
            <button onClick={onClose} className="p-3 bg-slate/5 rounded-full text-slate/40 hover:bg-slate/10 transition-all">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-4">
             <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">Context</h3>
             <div className="p-6 bg-white rounded-2xl border-l-4 border-terracotta shadow-sm">
                <p className="text-xl text-charcoal font-serif italic leading-relaxed">"{selectedSnippet}"</p>
             </div>
          </div>

          <section className="space-y-6">
            <div className="flex items-center justify-between">
              <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">Existing Codes</h3>
              <div className="relative w-48">
                <input 
                  type="text" 
                  placeholder="Filter... (Ctrl+K)"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-10 px-4 bg-white/50 border border-slate/10 rounded-lg text-sm focus:bg-white transition-all outline-none"
                  autoFocus
                />
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {filteredCodes.length === 0 ? (
                <p className="text-sm text-slate/30 italic py-4">No codes match your search.</p>
              ) : (
                filteredCodes.map(code => (
                  <button 
                    key={code.id} 
                    onClick={() => onApply(code)} 
                    className="flex items-center gap-5 p-5 bg-white rounded-2xl border border-slate/5 hover:border-terracotta/30 hover:shadow-md active:scale-[0.98] transition-all text-left group"
                  >
                    <div className="w-5 h-5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />
                    <span className="font-bold text-slate flex-1 truncate text-lg">{code.label}</span>
                    <span className="px-3 py-1 bg-slate/5 rounded-full text-[10px] font-bold text-slate/30 group-hover:bg-terracotta/10 group-hover:text-terracotta transition-colors">
                      {codeUsageCounts[code.id] || 0}
                    </span>
                  </button>
                ))
              )}
            </div>
          </section>

          <div className="h-px bg-slate/5" />

          <section className="space-y-6 pb-12">
            <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">New Concept</h3>
            <div className="flex gap-3">
              <input 
                type="text" 
                value={newCodeLabel} 
                onChange={(e) => setNewCodeLabel(e.target.value)} 
                placeholder="Name your category..." 
                className="flex-1 h-16 px-6 rounded-2xl border-2 border-slate/5 bg-white outline-none focus:border-terracotta font-bold text-slate shadow-sm" 
              />
              <button 
                onClick={handleCreate} 
                disabled={newCodeLabel.trim().length < 2} 
                className="px-8 bg-slate text-white rounded-2xl font-bold shadow-lg disabled:opacity-20 hover:bg-terracotta transition-colors"
              >
                Create
              </button>
            </div>
            <div className="flex flex-wrap gap-4">
              {CODE_COLORS.map(color => (
                <button 
                  key={color} 
                  onClick={() => setSelectedColor(color)} 
                  className={`w-10 h-10 rounded-full transition-all border-4 ${selectedColor === color ? 'border-white ring-2 ring-terracotta scale-110' : 'border-transparent opacity-60'}`} 
                  style={{ backgroundColor: color }} 
                />
              ))}
            </div>
            {!selectedSnippet.startsWith('Multiple segments') && (
              <button onClick={handleInVivo} className="w-full flex items-center justify-between p-6 bg-sage/5 border-2 border-dashed border-sage/20 rounded-2xl hover:bg-sage/10 transition-all text-left group">
                <div className="flex flex-col">
                  <span className="font-bold text-sage text-lg">In Vivo Code</span>
                  <span className="text-xs text-sage/40">Use verbatim selection as label</span>
                </div>
                <svg className="w-8 h-8 text-sage/40 group-hover:text-sage transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </button>
            )}
          </section>
        </div>
      </div>
    </div>
  );
};

export default CodeSelectionModal;

