import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a professional multilingual qualitative research assistant. 
Your primary task is to transcribing or extracting content EXACTLY as it is written or spoken.

SUPPORTED LANGUAGES: English (en-US), German (de-DE), Spanish (es-ES), Russian (ru-RU). 

RULES:
1. VERBATIM ONLY: Do not summarize. Preserve filler words ("uh", "um", "well").
2. NO TRANSLATION: Do not translate the source content.
3. PRESERVE NUANCE: Maintain dialects and original phrasing.
4. FORMAT: Return a JSON array where each item is a single sentence or natural segment from the source.

Goal: Provide high-fidelity raw data for qualitative coding.`;

export const transcribeAudio = async (base64Data: string, mimeType: string, languageLabel: string = "English"): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      contents: [
        {
          role: 'user',
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: `${SYSTEM_PROMPT}\n\nPlease provide a JSON array of the exact verbatim transcript segments from this audio file. The speaker is using ${languageLabel}.` }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const text = response.text || '[]';
    return JSON.parse(text);
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Verbatim transcription failed.");
  }
};

export const processDocument = async (payload: { base64?: string, text?: string, mimeType?: string }): Promise<string[]> => {
  try {
    const parts: any[] = [];
    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT}\n\nExtract text from this PDF verbatim and return as a JSON array of sentences.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT}\n\nSegment this text verbatim into a JSON array of sentences:\n\n${payload.text}` });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Doc Processing Error:", error);
    return ["Error: Extraction failed."];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  const context = codes.map(c => 
    `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${s.ref + 1}] "${s.text}"`).join('\n')}`
  ).join('\n\n');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a researcher. Write a thematic synthesis for "${projectTitle}".
      Data:
      ${context}

      Structure: Intro, Findings (citing quotes verbatim), Conclusion.`
    });
    return response.text || "Report generation failed.";
  } catch (error) {
    return "Thematic analysis failed.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import mammoth from 'mammoth';
import Layout from '../../../shared/components/Layout';
import { ProcessingSpinner } from '../../../shared/components/LoadingStates';
import { transcribeAudio, processDocument } from '../../../services/geminiService';
import { useInterviews } from '../hooks/useInterviews';
import { showToast } from '../../../lib/toast';

const LANGUAGES = [
  { code: 'en-US', label: 'English' },
  { code: 'de-DE', label: 'German' },
  { code: 'es-ES', label: 'Spanish' },
  { code: 'ru-RU', label: 'Russian' },
];

const RecordInterviewView: React.FC = () => {
  const { projectId } = useParams();
  const navigate = useNavigate();
  const { createInterview } = useInterviews(projectId);

  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordTime, setRecordTime] = useState(0);
  const [mode, setMode] = useState<'select' | 'record' | 'upload'>('select');
  const [selectedLanguage, setSelectedLanguage] = useState(LANGUAGES[0].code);
  const [progress, setProgress] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await processAudio(audioBlob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordTime(0);
      timerRef.current = window.setInterval(() => setRecordTime(t => t + 1), 1000);
      showToast.success('Recording started');
    } catch (err) {
      showToast.error('Mic access failed');
    }
  };

  const processAudio = async (blob: Blob) => {
    setIsProcessing(true);
    setProgress(15);
    const langLabel = LANGUAGES.find(l => l.code === selectedLanguage)?.label || 'English';

    try {
      const interval = setInterval(() => setProgress(p => Math.min(p + 5, 90)), 1000);

      const reader = new FileReader();
      const base64 = await new Promise<string>((res) => {
        reader.onload = () => res((reader.result as string).split(',')[1]);
        reader.readAsDataURL(blob);
      });

      const sentences = await transcribeAudio(base64, blob.type, langLabel);
      clearInterval(interval);
      setProgress(100);

      const interview = createInterview(`Interview ${new Date().toLocaleTimeString()}`, sentences);
      if (interview) {
        showToast.success('Transcription complete!');
        navigate(`/projects/${projectId}/interviews/${interview.id}`);
      }
    } catch (e) {
      showToast.error('AI Processing failed');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setProgress(20);
    try {
      let sentences: string[] = [];
      if (file.type.startsWith('audio/')) {
        await processAudio(file);
        return;
      } else if (file.type === 'application/pdf') {
        const reader = new FileReader();
        const base64 = await new Promise<string>((res) => {
          reader.onload = () => res((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });
        sentences = await processDocument({ base64, mimeType: 'application/pdf' });
      } else if (file.type.includes('wordprocessingml')) {
        const buffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer: buffer });
        sentences = await processDocument({ text: result.value });
      } else {
        const text = await file.text();
        sentences = await processDocument({ text });
      }

      const interview = createInterview(file.name.replace(/\.[^/.]+$/, ""), sentences);
      if (interview) navigate(`/projects/${projectId}/interviews/${interview.id}`);
    } catch (err) {
      showToast.error('Processing failed');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout title="Import Data" onBack={() => navigate(`/projects/${projectId}`)}>
      <div className="max-w-4xl mx-auto animate-fade-in">
        {isProcessing ? (
          <div className="space-y-8">
            <ProcessingSpinner message="AI Verbatim Extraction" />
            <div className="max-w-md mx-auto space-y-2">
              <div className="w-full bg-slate/10 rounded-full h-2 overflow-hidden">
                <div className="h-full bg-terracotta transition-all duration-700" style={{ width: `${progress}%` }} />
              </div>
              <p className="text-center text-[10px] font-bold text-slate/30 uppercase tracking-widest">{progress}% Processed</p>
            </div>
          </div>
        ) : (
          <div className="space-y-10">
            <div className="flex flex-col items-center gap-4 bg-white p-8 rounded-3xl border border-slate/5 shadow-sm">
              <label className="text-[10px] font-bold text-slate/40 uppercase tracking-widest">Input Language</label>
              <div className="flex gap-2">
                {LANGUAGES.map(l => (
                  <button 
                    key={l.code} 
                    onClick={() => setSelectedLanguage(l.code)}
                    className={`px-4 py-2 rounded-xl border-2 transition-all font-bold text-sm ${selectedLanguage === l.code ? 'border-terracotta bg-terracotta/5 text-terracotta' : 'border-slate/5 bg-slate/5 text-slate/40 hover:bg-slate/10'}`}
                  >
                    {l.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <button onClick={() => setMode('record')} className={`bg-white p-12 rounded-3xl shadow-lg border-4 transition-all flex flex-col items-center gap-6 group ${mode === 'record' ? 'border-terracotta' : 'border-transparent hover:border-terracotta/20'}`}>
                 <div className="w-20 h-20 bg-terracotta/10 rounded-full flex items-center justify-center text-terracotta"><svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg></div>
                 <h3 className="text-2xl font-bold text-slate">Recorder</h3>
              </button>
              <button onClick={() => setMode('upload')} className={`bg-white p-12 rounded-3xl shadow-lg border-4 transition-all flex flex-col items-center gap-6 group ${mode === 'upload' ? 'border-sage' : 'border-transparent hover:border-sage/20'}`}>
                 <div className="w-20 h-20 bg-sage/10 rounded-full flex items-center justify-center text-sage"><svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg></div>
                 <h3 className="text-2xl font-bold text-slate">File Upload</h3>
              </button>
            </div>

            {mode === 'record' && (
              <div className="bg-white p-12 rounded-3xl shadow-xl text-center space-y-8 animate-fade-in">
                <div className="text-6xl font-mono font-bold text-slate">{Math.floor(recordTime / 60)}:{(recordTime % 60).toString().padStart(2, '0')}</div>
                <div className="flex justify-center gap-4">
                  {!isRecording ? <button onClick={startRecording} className="px-10 py-4 bg-terracotta text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all">Start Recording</button> : <button onClick={stopRecording} className="px-10 py-4 bg-slate text-white rounded-2xl font-bold text-xl shadow-lg hover:scale-105 active:scale-95 transition-all">Stop & Transcribe</button>}
                </div>
              </div>
            )}

            {mode === 'upload' && (
              <div className="bg-white p-12 rounded-3xl shadow-xl text-center space-y-6 animate-fade-in">
                <input type="file" id="file-up" className="hidden" onChange={handleFileUpload} accept="audio/*,application/pdf,.docx,text/plain" />
                <label htmlFor="file-up" className="cursor-pointer block p-16 border-4 border-dashed border-slate/10 rounded-3xl hover:border-sage bg-slate/5 transition-all">
                   <p className="text-xl font-bold text-slate">Drop source file here for verbatim extraction</p>
                   <span className="text-xs text-slate/30 mt-2 block">Audio, PDF, Word, or TXT</span>
                </label>
              </div>
            )}
          </div>
        )}
      </div>
    </Layout>
  );
};

export default RecordInterviewView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, applyCode, removeSegment } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Keyboard Shortcuts
  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim()) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(selection.toString().trim());
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      setFloatingMenuPos(null);
    }
  };

  const handleSegmentClick = (idx: number, e: React.MouseEvent) => {
    if (e.ctrlKey || e.metaKey) {
      setMultiSelect(prev => prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]);
    } else {
      setMultiSelect([idx]);
    }
  };

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        applyCode(code.id, interview.sentences[idx], idx, 0, interview.sentences[idx].length);
      });
      showToast.success(`Batch applied ${code.label}`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }

    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Keyboard Help">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Done</button>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center animate-fade-in">
        <div className="max-w-4xl w-full space-y-12 pb-60">
          {interview.sentences.map((s, idx) => {
            const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
            const isMultiSelected = multiSelect.includes(idx);
            return (
              <div 
                key={idx} 
                onMouseUp={() => handleSelection(idx)} 
                onClick={(e) => handleSegmentClick(idx, e)}
                className={`group relative p-4 -m-4 rounded-2xl transition-all cursor-pointer ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
              >
                <div className="flex items-center gap-2 mb-2">
                   <span className={`text-[10px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                   <div className="flex flex-wrap gap-1">
                      {sentenceSegments.map(seg => {
                        const code = codes.find(c => c.id === seg.code_id);
                        return code && (
                          <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                            {code.label}
                            <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                          </div>
                        );
                      })}
                   </div>
                </div>
                <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap select-text ${isMultiSelected ? 'text-charcoal font-semibold' : 'text-charcoal/90'}`}>
                  <GranularHighlighter text={s} segments={sentenceSegments} codes={codes} />
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-1/2">
          <button onClick={() => setIsModalOpen(true)} className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
            Code {multiSelect.length > 1 ? `${multiSelect.length} Segments` : 'Selection'}
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Coding Shortcuts"
        message="Ctrl/Cmd + K: Open Code Selector | Ctrl/Cmd + Z: Undo Last | Ctrl/Cmd + Click: Multi-select | ?: Toggle this guide | ESC: Close menus"
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { Code } from '../../../types';
import { CODE_COLORS } from '../../../constants';

interface CodeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedSnippet: string;
  existingCodes: Code[];
  onApply: (code: Code) => void;
  onCreateAndApply: (label: string, color: string, isInVivo?: boolean) => void;
  codeUsageCounts?: Record<string, number>;
}

const CodeSelectionModal: React.FC<CodeSelectionModalProps> = ({
  isOpen,
  onClose,
  selectedSnippet,
  existingCodes,
  onApply,
  onCreateAndApply,
  codeUsageCounts = {}
}) => {
  const [newLabel, setNewLabel] = useState('');
  const [color, setColor] = useState(CODE_COLORS[0]);
  const [search, setSearch] = useState('');

  const filtered = useMemo(() => {
    return existingCodes.filter(c => 
      c.label.toLowerCase().includes(search.toLowerCase())
    ).sort((a, b) => (codeUsageCounts[b.id] || 0) - (codeUsageCounts[a.id] || 0));
  }, [existingCodes, search, codeUsageCounts]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center bg-slate/40 backdrop-blur-sm">
      <div className="fixed inset-0" onClick={onClose} />
      <div className="relative w-full max-w-2xl bg-cream rounded-t-[40px] shadow-2xl flex flex-col max-h-[90vh] animate-in slide-in-from-bottom-full duration-300" style={{ height: '85%' }}>
        <div className="w-16 h-1.5 bg-slate/10 rounded-full mx-auto mt-4 mb-2" />
        <div className="p-10 overflow-y-auto flex-1 space-y-12">
          <header className="flex justify-between items-start">
            <h2 className="text-3xl font-bold text-slate">Assign Code</h2>
            <button onClick={onClose} className="p-3 bg-slate/5 rounded-full text-slate/40 hover:bg-slate/10 transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
          </header>

          <div className="p-6 bg-white rounded-3xl border-l-8 border-terracotta shadow-sm italic text-xl font-serif text-charcoal">
             "{selectedSnippet}"
          </div>

          <section className="space-y-6">
            <div className="flex items-center justify-between gap-4">
              <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">Research Taxonomy</h3>
              <input 
                type="text" 
                placeholder="Search codes..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="flex-1 max-w-[200px] h-10 px-4 bg-white/50 border border-slate/10 rounded-xl text-sm focus:bg-white transition-all outline-none"
                autoFocus
              />
            </div>

