import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    set(STORAGE_KEYS.CODES, codes.filter((c: Code) => c.id !== codeId));
    // Cascade delete segments across all interviews
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState } from 'react';
import { Code, Project } from '../types';
import { CODE_COLORS } from '../constants';

interface CodeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  sentenceText?: string;
  selectedSnippet: string;
  sentenceIndex?: number;
  interviewId?: string;
  projectId?: string;
  existingCodes: Code[];
  onApply: (code: Code) => void;
  onCreateAndApply: (label: string, color: string, isInVivo?: boolean) => void;
  onDeleteCode?: (codeId: string) => void;
  codeUsageCounts?: Record<string, number>;
}

const CodeSelectionModal: React.FC<CodeSelectionModalProps> = ({
  isOpen,
  onClose,
  sentenceText,
  selectedSnippet,
  existingCodes,
  onApply,
  onCreateAndApply,
  onDeleteCode,
  codeUsageCounts = {}
}) => {
  const [newCodeLabel, setNewCodeLabel] = useState('');
  const [selectedColor, setSelectedColor] = useState(CODE_COLORS[0]);
  const [codeToDelete, setCodeToDelete] = useState<Code | null>(null);

  if (!isOpen) return null;

  const handleCreate = () => {
    if (newCodeLabel.trim().length >= 2) {
      onCreateAndApply(newCodeLabel.trim(), selectedColor, false);
      setNewCodeLabel('');
    }
  };

  const handleInVivo = () => {
    if (selectedSnippet.trim().length >= 1) {
      onCreateAndApply(selectedSnippet.trim(), selectedColor, true);
    }
  };

  const confirmDelete = (code: Code) => {
    setCodeToDelete(code);
  };

  const finalizeDelete = () => {
    if (codeToDelete && onDeleteCode) {
      onDeleteCode(codeToDelete.id);
      setCodeToDelete(null);
    }
  };

  // Sort codes by frequency of use if codeUsageCounts is provided
  const sortedCodes = [...existingCodes].sort((a, b) => 
    (codeUsageCounts[b.id] || 0) - (codeUsageCounts[a.id] || 0)
  );

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center bg-slate/40 backdrop-blur-sm transition-opacity duration-300">
      <div 
        className="fixed inset-0" 
        onClick={onClose} 
      />
      <div 
        className="relative w-full max-w-2xl bg-cream rounded-t-[24px] shadow-2xl flex flex-col max-h-[90vh] animate-in slide-in-from-bottom-full duration-300"
        style={{ height: '80%' }}
      >
        <div className="w-12 h-1.5 bg-slate/10 rounded-full mx-auto mt-3 mb-1" />

        <div className="p-6 overflow-y-auto flex-1 space-y-8">
          <header className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-bold text-slate">Code Selection</h2>
              <p className="text-slate/40 text-xs uppercase tracking-widest font-bold mt-1">Granular Qualitative Analysis</p>
            </div>
            <button onClick={onClose} className="p-2 bg-slate/5 rounded-full text-slate/40 hover:text-slate">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </header>

          <div className="space-y-3">
             <h3 className="text-xs font-bold text-slate/40 uppercase tracking-widest">Selected Segment</h3>
             <div className="p-5 bg-white rounded-xl border-l-4 border-terracotta shadow-inner">
                <p className="text-lg text-charcoal leading-relaxed font-serif italic">"...{selectedSnippet}..."</p>
             </div>
          </div>

          <section className="space-y-4">
            <h3 className="text-xs font-bold text-slate/40 uppercase tracking-widest">In Vivo Coding</h3>
            <button
              onClick={handleInVivo}
              className="w-full flex items-center justify-between p-5 bg-sage/10 border-2 border-sage/20 rounded-xl hover:bg-sage/20 transition-all text-left group"
            >
              <div>
                <span className="block font-bold text-sage">Use as In Vivo Code</span>
                <span className="text-xs text-sage/60">Create a new code named "{selectedSnippet}"</span>
              </div>
              <svg className="w-6 h-6 text-sage group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </button>
          </section>

          <div className="h-px bg-slate/10" />

          <section>
            <h3 className="text-xs font-bold text-slate/40 uppercase tracking-widest mb-4">Apply Existing Code</h3>
            <div className="grid grid-cols-1 gap-2">
              {sortedCodes.length === 0 ? (
                <p className="text-sm text-slate/30 italic">No existing codes.</p>
              ) : (
                sortedCodes.map(code => (
                  <div key={code.id} className="group relative flex items-center gap-2">
                    <button
                      onClick={() => onApply(code)}
                      className="flex-1 flex items-center gap-4 p-4 bg-white rounded-xl border border-slate/5 hover:border-terracotta/30 active:scale-[0.98] transition-all text-left h-14"
                    >
                      <div className="w-4 h-4 rounded-full flex-shrink-0" style={{ backgroundColor: code.color }} />
                      <span className="font-bold text-slate flex-1 truncate">{code.label}</span>
                      {codeUsageCounts[code.id] !== undefined && (
                        <span className="text-[10px] text-slate/30 font-bold">{codeUsageCounts[code.id]}</span>
                      )}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); confirmDelete(code); }}
                      className="p-3 opacity-0 group-hover:opacity-100 hover:text-red-500 text-slate/20 transition-all"
