  const [currentInterview, setCurrentInterview] = useState<Interview | null>(null);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [codes, setCodes] = useState<Code[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  useEffect(() => {
    if (user) {
      setIsLoading(true);
      setProjects(dbService.getProjects());
      setView('PROJECTS');
      setTimeout(() => setIsLoading(false), 500);
    }
  }, [user]);

  const onLogin = (email: string) => setUser(dbService.login(email));
  const onLogout = () => { dbService.logout(); setUser(null); setView('AUTH'); showToast.success('Logged out'); };

  const onOpenProject = (p: Project) => {
    setCurrentProject(p);
    setInterviews(dbService.getInterviews(p.id));
    setCodes(dbService.getCodes(p.id));
    setView('PROJECT_DETAIL');
  };

  const renderView = () => {
    switch (view) {
      case 'AUTH': return <AuthView onLogin={onLogin} />;
      case 'PROJECTS': return <ProjectsView projects={projects} isLoading={isLoading} onOpen={onOpenProject} onCreate={() => setView('CREATE_PROJECT')} onLogout={onLogout} />;
      case 'CREATE_PROJECT': return <CreateProjectView onBack={() => setView('PROJECTS')} onCreated={(p) => { setProjects([...projects, p]); onOpenProject(p); }} />;
      case 'PROJECT_DETAIL': return currentProject ? (
        <Layout title={currentProject.title} onBack={() => setView('PROJECTS')} 
          actions={<div className="flex gap-2">
            <button onClick={() => setView('EXPORT')} className="px-4 py-2 bg-sage text-white rounded-xl font-bold text-sm shadow-sm hover:bg-sage/90">Export</button>
          </div>}
        >
          <div className="relative pb-32 animate-fade-in">
            <h2 className="text-2xl font-bold text-charcoal mb-2">{currentProject.title}</h2>
            <p className="text-charcoal/60 mb-6">{currentProject.description || "No description."}</p>
            <div className="space-y-3">
              {interviews.map(i => (
                <div key={i.id} onClick={() => { setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} className="bg-white p-5 rounded-xl flex items-center justify-between shadow-sm cursor-pointer hover:shadow-md border border-slate/5 transition-all">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-slate/5 flex items-center justify-center text-slate/40"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg></div>
                    <h3 className="text-lg font-bold text-charcoal">{i.title}</h3>
                  </div>
                  <span className="px-3 py-1 bg-slate/5 text-slate/40 text-[10px] font-bold uppercase rounded-full">{dbService.getCodedSegments(i.id).length} Codes</span>
                </div>
              ))}
            </div>
            <button onClick={() => setView('RECORD_INTERVIEW')} className="fixed bottom-8 right-8 w-16 h-16 bg-terracotta text-white rounded-full flex items-center justify-center shadow-2xl hover:scale-110 active:scale-95 transition-all z-50"><svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg></button>
          </div>
        </Layout>
      ) : null;
      case 'RECORD_INTERVIEW': return currentProject ? <RecordInterviewView project={currentProject} onBack={() => setView('PROJECT_DETAIL')} onInterviewCreated={(i) => { setInterviews([...interviews, i]); setCurrentInterview(i); setView('INTERVIEW_DETAIL'); }} /> : null;
      case 'INTERVIEW_DETAIL': return currentInterview && currentProject ? (
        <Layout title={currentInterview.title} onBack={() => setView('PROJECT_DETAIL')} 
          actions={<button onClick={() => setShowDeleteConfirm(true)} className="p-2 text-slate/20 hover:text-red-500"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>}
        >
          <div className="max-w-4xl mx-auto space-y-8 pb-40 animate-fade-in">
            <div className="bg-white p-10 rounded-3xl shadow-lg">
              <div className="space-y-6">
                {currentInterview.sentences.map((s, idx) => (
                  <div key={idx} className="flex gap-4"><span className="text-[10px] font-bold text-slate/10 mt-2 shrink-0">#{idx+1}</span><p className="text-lg font-serif">{s.text}</p></div>
                ))}
              </div>
            </div>
            <button onClick={() => setView('CODING')} className="fixed bottom-12 right-8 h-16 px-10 bg-terracotta text-white rounded-full font-bold shadow-2xl hover:scale-105 active:scale-95 transition-all">Coding Studio</button>
            <ConfirmDialog isOpen={showDeleteConfirm} title="Delete Source?" message="This will permanently delete this interview." confirmText="Delete" onConfirm={() => { dbService.deleteInterview(currentInterview.id); setInterviews(interviews.filter(i => i.id !== currentInterview.id)); setShowDeleteConfirm(false); setView('PROJECT_DETAIL'); showToast.success('Interview deleted'); }} onCancel={() => setShowDeleteConfirm(false)} variant="danger" />
          </div>
        </Layout>
      ) : null;
      case 'CODING': return currentProject && currentInterview ? <CodingView project={currentProject} interview={currentInterview} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodesUpdated={(c) => setCodes(c)} /> : null;
      case 'EXPORT': return currentProject ? (
        <Layout title="Export Center" onBack={() => setView('PROJECT_DETAIL')}>
          <div className="max-w-5xl mx-auto py-10 animate-fade-in"><p className="text-slate/60 mb-10">Generate thematic analysis and academic reports based on your verbatim coding.</p>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="bg-white p-8 rounded-3xl shadow-lg h-fit space-y-4">
                <button onClick={() => { showToast.success('Exporting...'); }} className="w-full h-14 bg-blue-600 text-white rounded-xl font-bold">Download Word (.DOC)</button>
                <button onClick={() => { window.print(); }} className="w-full h-14 bg-orange-600 text-white rounded-xl font-bold">Print/PDF Report</button>
              </div>
              <div className="lg:col-span-2 bg-white p-10 rounded-3xl shadow-lg min-h-[400px]">
                <h3 className="text-2xl font-bold text-slate mb-4">Academic Synthesis</h3>
                <p className="text-charcoal/40 italic">Synthesis of verbatim segments will appear here after analysis generation.</p>
              </div>
            </div>
          </div>
        </Layout>
      ) : null;
      default: return null;
    }
  };

  return (
    <div className="App">
      <Toaster position="top-right" />
      {renderView()}
    </div>
  );
};

export default App;

export interface Profile {
  id: string;
  email: string;
  full_name: string;
}

export interface Project {
  id: string;
  title: string;
  description: string;
  owner_id: string;
  created_at: string;
}

export interface TranscriptSentence {
  speaker: string;
  text: string;
}

export interface Interview {
  id: string;
  project_id: string;
  title: string;
  transcript: string; // Raw text or JSON segments
  audio_url?: string;
  duration?: string;
  created_at: string;
  sentences: TranscriptSentence[]; // Processed for coding with speaker labels
}

export interface Code {
  id: string;
  project_id: string;
  label: string;
  color: string;
  created_by: string;
  description?: string;
  is_invivo?: boolean;
  parent_id?: string; // Support for hierarchical coding
  comment?: string;    // Research notes or definitions
}

export interface CodedSegment {
  id: string;
  interview_id: string;
  code_id: string;
  segment_text: string;
  sentence_index: number;
  start_char?: number; // Offset within the sentence
  end_char?: number;   // Offset within the sentence
}

export type AppView = 
  | 'AUTH' 
  | 'PROJECTS' 
  | 'CREATE_PROJECT' 
  | 'EDIT_PROJECT'
  | 'PROJECT_DETAIL' 
  | 'RECORD_INTERVIEW' 
  | 'INTERVIEW_DETAIL' 
  | 'CODING' 
  | 'EXPORT';

import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex((c: Code) => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Also delete children if it's a parent
    const filteredCodes = codes.filter((c: Code) => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, filteredCodes);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!].push(c);
    });
    return map;
  }, [codes]);

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim()) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(selection.toString().trim());
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      setFloatingMenuPos(null);
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter sub-code name:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const hasChildren = subCodesMap[code.id]?.length > 0;
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/5 scale-[1.02] shadow-lg' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
        >
          <div className="flex items-center gap-3">
            {level === 0 && (
              <button 
                onClick={(e) => { e.stopPropagation(); toggleExpand(code.id); }}
                className={`p-1 hover:bg-slate/20 rounded transition-transform ${isExpanded ? 'rotate-90' : ''}`}
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </button>
            )}
            <div className="relative group/color">
               <div className="w-3 h-3 rounded-full shadow-inner" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 group-hover/color:opacity-100 transition-opacity bg-white shadow-xl rounded-lg p-2 grid grid-cols-4 gap-1 z-[60] w-32 -translate-x-1/2">
                 {CODE_COLORS.map(c => (
                   <button key={c} onClick={() => handleUpdateCodeColor(code.id, c)} className="w-5 h-5 rounded-full" style={{ backgroundColor: c }} />
                 ))}
               </div>
            </div>
            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>
            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => setEditingCodeId(isEditing ? null : code.id)} className="p-1 text-slate/40 hover:text-slate">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z" /></svg>
              </button>
              {level === 0 && (
                <button onClick={() => handleAddSubCode(code.id)} className="p-1 text-slate/40 hover:text-terracotta">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>
            <span className="text-[9px] text-slate/30 font-bold">{codeUsage[code.id] || 0}</span>
          </div>

          {isEditing && (
            <div className="mt-2 space-y-2 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Code definition or research notes..."
                className="w-full text-xs p-2 rounded-lg bg-white border border-slate/10 focus:border-terracotta outline-none h-20 resize-none font-medium"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <button onClick={() => deleteCode(code.id)} className="text-[10px] text-red-500 font-bold hover:underline">Delete Code</button>
            </div>
          )}
        </div>
        {isExpanded && subCodesMap[code.id]?.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md">Done</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - No more draggable on containers to fix selection */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Drag handle only visible when text is selected in this sentence */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      className="absolute -left-10 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-2 bg-terracotta text-white rounded-lg shadow-lg z-50 animate-bounce"
                      title="Drag to code"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/5'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/5 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/5 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Root Code Name:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1 hover:bg-slate/10 rounded text-slate/40"
               >
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">Select text & drag handle to a code</p>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-2">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-20">
                <svg className="w-12 h-12 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold">Codebook Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
