  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!].push(c);
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim()) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(selection.toString().trim());
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      setFloatingMenuPos(null);
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    showToast.success('Color updated');
    // We need a force refresh or to rely on useCoding to pull new data
    // In this app structure, we might need a small delay or a trigger
    window.location.reload(); // Quickest way to sync the complex hierarchy state
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter sub-code name:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/5 scale-[1.02] shadow-lg' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
        >
          <div className="flex items-center gap-3">
            {level === 0 && (
              <button 
                onClick={(e) => { e.stopPropagation(); toggleExpand(code.id); }}
                className={`p-1 hover:bg-slate/20 rounded transition-transform ${isExpanded ? 'rotate-90' : ''}`}
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </button>
            )}
            <div className="relative group/color">
               <div className="w-4 h-4 rounded-full shadow-inner cursor-pointer border border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 group-hover/color:opacity-100 transition-opacity bg-white shadow-xl rounded-lg p-2 grid grid-cols-4 gap-1 z-[60] w-32 -translate-x-1/2">
                 {CODE_COLORS.map(c => (
                   <button key={c} onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} className="w-5 h-5 rounded-full hover:scale-110 transition-transform" style={{ backgroundColor: c }} />
                 ))}
               </div>
            </div>
            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>
            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} className="p-1 text-slate/40 hover:text-slate">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} className="p-1 text-slate/40 hover:text-terracotta">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>
            <span className="text-[10px] text-slate/30 font-bold px-1.5 py-0.5 bg-white/50 rounded-md shadow-sm">{codeUsage[code.id] || 0}</span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Definition, memos or research notes..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button onClick={() => deleteCode(code.id)} className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded">Delete Code</button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved automatically</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && subCodesMap[code.id]?.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Done</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - select-text enabled, no draggable on container */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Drag handle only visible when text is selected in this sentence */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag this selection to a code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/5'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/5 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/5 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Root Code Name:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="Add Root Code"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">Drag handle from selection to code</p>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-20 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Category Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>
          <div className="p-4 bg-slate/5 border-t border-slate/5 flex gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex-1 py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button onClick={() => setIsModalOpen(true)} className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Researcher Guide"
        message="• HIGHLIGHT: Select text with touch or mouse. • DRAG: A terracotta handle appears when text is selected; drag it onto a code. • HIERARCHY: Use root concepts and '+' to create sub-codes (max 2 levels). • COMMENTS: Click the pencil to add research notes or definitions to any code."
        confirmText="Start Coding"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { useState, useEffect } from 'react';
import { dbService } from '../../../services/dbService';
import { Code, CodedSegment } from '../../../types';
import { showToast } from '../../../lib/toast';

export const useCoding = (projectId?: string, interviewId?: string) => {
  const [codes, setCodes] = useState<Code[]>([]);
  const [segments, setSegments] = useState<CodedSegment[]>([]);

  useEffect(() => {
    if (projectId) setCodes(dbService.getCodes(projectId));
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
  }, [projectId, interviewId]);

  const refreshCodes = () => {
    if (projectId) setCodes(dbService.getCodes(projectId));
  };

  const addCode = (label: string, color: string, isInVivo?: boolean, parentId?: string) => {
    if (!projectId) return;
    const newCode = dbService.createCode(projectId, label, color, undefined, isInVivo, parentId);
    refreshCodes();
    return newCode;
  };

  const deleteCode = (codeId: string) => {
    dbService.deleteCode(codeId);
    refreshCodes();
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
    showToast.success('Code deleted');
  };

  const applyCode = (codeId: string, segmentText: string, sentenceIndex: number, start: number, end: number) => {
    if (!interviewId) return;
    const segment = dbService.saveCodedSegment({
      interview_id: interviewId,
      code_id: codeId,
      segment_text: segmentText,
      sentence_index: sentenceIndex,
      start_char: start,
      end_char: end
    });
    setSegments(prev => [...prev, segment]);
  };

  const removeSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setSegments(prev => prev.filter(s => s.id !== id));
    showToast.success('Coding removed');
  };

  return {
    codes,
    segments,
    addCode,
    deleteCode,
    applyCode,
    removeSegment,
    refreshCodes
  };
};

import React, { useState, useMemo, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!].push(c);
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      // Don't clear immediately if we're clicking the handle
      // This is a common issue with selection clearing on mousedown
    }
  };

  // Clear selection if clicking outside sentences
  const handleStageClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      setSelectedText("");
      setSelectedIdx(null);
      setFloatingMenuPos(null);
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Set a ghost image or just let browser handle it
    const dragIcon = document.createElement('div');
    dragIcon.className = "px-3 py-1 bg-terracotta text-white rounded text-xs font-bold";
    dragIcon.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragIcon);
    e.dataTransfer.setDragImage(dragIcon, 0, 0);
    setTimeout(() => document.body.removeChild(dragIcon), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter sub-code name:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/5 scale-[1.02] shadow-lg' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-4 h-4 rounded-full shadow-sm border border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-xl rounded-lg p-2 grid grid-cols-4 gap-1 z-[70] w-32 -translate-x-1/2">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-5 h-5 rounded-full hover:scale-110 transition-transform" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white/50 transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit definition & notes"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white/50"
                  title="Add Sub-code"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/30 font-bold px-1.5 py-0.5 bg-white/50 rounded-md shadow-sm select-none">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or research notes..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this code and all its references?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Code
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Autosaved</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Keyboard Shortcuts"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Done</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div 
          className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text"
          onMouseDown={handleStageClick}
        >
          <div className="max-w-4xl w-full space-y-12 pb-60">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Handle that appears when text is selected */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag this selection onto a code in the sidebar"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/5'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/5 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/5 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root category:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="Add Root Code"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">Highlight text, then drag the terracotta handle onto a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">No categories yet</p>
                <button 
                  onClick={() => { const l = prompt("Enter name for your first category:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="mt-4 text-xs font-bold text-terracotta hover:underline"
                >
                  Create Root Category
                </button>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/5 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
            <p className="text-[9px] text-center text-slate/30 font-bold uppercase tracking-widest px-4">Tip: Click the pencil to add memos to your codes</p>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
            Apply Code to Selection
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Researcher Guide"
        message="• HIGHLIGHT: Use your mouse or touch to select transcript text. • DRAG: A terracotta handle appears next to your selection; drag it onto a code in the sidebar. • HIERARCHY: Create root codes and use '+' for sub-codes. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

