export type AppView = 
  | 'AUTH' 
  | 'PROJECTS' 
  | 'CREATE_PROJECT' 
  | 'EDIT_PROJECT'
  | 'PROJECT_DETAIL' 
  | 'RECORD_INTERVIEW' 
  | 'INTERVIEW_DETAIL' 
  | 'CODING' 
  | 'EXPORT';

import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex(c => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Cascade delete sub-codes
    const codesWithSubDeleted = codes.filter(c => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, codesWithSubDeleted);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import { useState, useEffect } from 'react';
import { dbService } from '../../../services/dbService';
import { Code, CodedSegment } from '../../../types';
import { showToast } from '../../../lib/toast';

export const useCoding = (projectId?: string, interviewId?: string) => {
  const [codes, setCodes] = useState<Code[]>([]);
  const [segments, setSegments] = useState<CodedSegment[]>([]);

  const refreshCodes = () => {
    if (projectId) setCodes(dbService.getCodes(projectId));
  };

  useEffect(() => {
    if (projectId) setCodes(dbService.getCodes(projectId));
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
  }, [projectId, interviewId]);

  const addCode = (label: string, color: string, isInVivo?: boolean, parentId?: string) => {
    if (!projectId) return;
    const newCode = dbService.createCode(projectId, label, color, undefined, isInVivo, parentId);
    refreshCodes();
    return newCode;
  };

  const deleteCode = (codeId: string) => {
    dbService.deleteCode(codeId);
    refreshCodes();
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
    showToast.success('Code deleted and segments unlinked');
  };

  const applyCode = (codeId: string, segmentText: string, sentenceIndex: number, start: number, end: number) => {
    if (!interviewId) return;
    const segment = dbService.saveCodedSegment({
      interview_id: interviewId,
      code_id: codeId,
      segment_text: segmentText,
      sentence_index: sentenceIndex,
      start_char: start,
      end_char: end
    });
    setSegments(prev => [...prev, segment]);
    showToast.success('Code applied');
  };

  const removeSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setSegments(prev => prev.filter(s => s.id !== id));
    showToast.success('Coding removed');
  };

  return {
    codes,
    segments,
    addCode,
    deleteCode,
    applyCode,
    removeSegment,
    refreshCodes
  };
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Create custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Selection Handle */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1 select-text">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are a professional multilingual qualitative research assistant. 
Your task is to transcribe content EXACTLY as it is spoken and IDENTIFY SPEAKERS.

RULES:
1. VERBATIM ONLY: Do not summarize. Preserve filler words ("uh", "um", "well", "ah") and stuttering.
2. NO TRANSLATION: Transcribe in the original language.
3. SPEAKER IDENTIFICATION: Identify different speakers. 
   - Use provided "Speaker Hints" if available to map identities.
   - Otherwise, label them as "Interviewer" and "Respondent" if clear.
   - Use "Speaker 1", "Speaker 2", etc. as fallback.
   - Use consistent labels throughout.
4. FORMAT: Return a JSON array of objects, each containing "speaker" and "text" fields.
5. LENGTH: If the input is very long, ensure the JSON array is complete and valid. Do not cut off mid-object.`;

const SENTENCE_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      speaker: { type: Type.STRING, description: "Label of the speaker (e.g. Interviewer, Respondent, S1)" },
      text: { type: Type.STRING, description: "The verbatim sentence or segment spoken." }
    },
    required: ["speaker", "text"]
  }
};

export const transcribeAudio = async (
  base64Data: string, 
  mimeType: string, 
  languageLabel: string = "Auto-Detect",
  speakerHints: string = ""
): Promise<{speaker: string, text: string}[]> => {
  try {
    const languageInstruction = languageLabel === "Auto-Detect" 
      ? "Automatically detect the language used in this audio." 
      : `The speaker is using ${languageLabel}.`;

    const hintInstruction = speakerHints ? `\n\nSPEAKER HINTS: Use these identities for mapping: ${speakerHints}` : "";

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          role: 'user',
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: `${SYSTEM_PROMPT}${hintInstruction}\n\nTask: ${languageInstruction}\nProvide a complete JSON array of structured transcript segments with speaker labels. Ensure the JSON is terminated correctly.` }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: SENTENCE_SCHEMA,
        thinkingConfig: { thinkingBudget: 4000 },
        maxOutputTokens: 8192
      }
    });

    const text = response.text || '[]';
    return JSON.parse(text);
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Verbatim transcription failed.");
  }
};

export const processDocument = async (
  payload: { base64?: string, text?: string, mimeType?: string },
  speakerHints: string = ""
): Promise<{speaker: string, text: string}[]> => {
  try {
    const parts: any[] = [];
    const hintInstruction = speakerHints ? `\n\nSPEAKER HINTS: Use these identities for mapping: ${speakerHints}` : "";

    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT}${hintInstruction}\n\nExtract text from this PDF verbatim. Try to identify speakers. Return a complete, valid JSON array of speaker/text objects. Do not truncate.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT}${hintInstruction}\n\nSegment this text verbatim and identify speakers. Return a complete, valid JSON array of speaker/text objects:\n\n${payload.text}` });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: SENTENCE_SCHEMA,
        thinkingConfig: { thinkingBudget: 4000 },
        maxOutputTokens: 8192
      }
    });

    const text = response.text || '[]';
    return JSON.parse(text);
  } catch (error) {
    console.error("Doc Processing Error:", error);
    return [{ speaker: "System", text: "Error: Extraction failed. The document might be too large or complex for a single pass." }];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  const context = codes.map(c => 
    `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${s.ref + 1}] "${s.text}"`).join('\n')}`
  ).join('\n\n');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a researcher. Write a thematic synthesis for "${projectTitle}".
      Data:
      ${context}

      Structure: Intro, Findings (citing quotes verbatim and mentioning speaker patterns if relevant), Conclusion.`,
      config: {
        thinkingConfig: { thinkingBudget: 2000 }
      }
    });
    return response.text || "Report generation failed.";
  } catch (error) {
    return "Thematic analysis failed.";
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Create custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Selection Handle - FIXED: Only the handle is draggable, allowing normal text selection on the transcript */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1 select-text">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex(c => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Cascade delete sub-codes
    const codesWithSubDeleted = codes.filter(c => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, codesWithSubDeleted);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    } else {
      // Don't clear immediately to allow handle clicking
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Create custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - CRITICAL: select-text enabled, no 'draggable' on container */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Selection Handle - Only this element is draggable */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1 select-text">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 25 ? selectedText.substring(0, 25) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - CRITICAL: 'select-text' enabled, NO 'draggable' on container */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle - FIXED: Only this handle is draggable, allowing normal mouse selection on the transcript */}
                  {isPartiallySelected && selectedText && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none pointer-events-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <span className={`text-[9px] font-bold uppercase tracking-tight truncate w-full text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                  </div>

                  <div className="flex-1 select-text">
                    <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                        {sentenceSegments.map(seg => {
                          const code = codes.find(c => c.id === seg.code_id);
                          return code && (
                            <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                              {code.label}
                              <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                            </div>
                          );
                        })}
                     </div>
                    <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                      <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  updateSentence: (interviewId: string, index: number, updates: Partial<TranscriptSentence>): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview && interview.sentences[index]) {
      interview.sentences[index] = { ...interview.sentences[index], ...updates };
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteSentence: (interviewId: string, index: number): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interviewIndex = interviews.findIndex((i: Interview) => i.id === interviewId);
    if (interviewIndex !== -1) {
      const interview = interviews[interviewIndex];
      interview.sentences.splice(index, 1);
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);

      // Cascading shifts for coded segments
      const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
      const filteredSegments = segments.filter(s => !(s.interview_id === interviewId && s.sentence_index === index));
      const shiftedSegments = filteredSegments.map(s => {
        if (s.interview_id === interviewId && s.sentence_index > index) {
          return { ...s, sentence_index: s.sentence_index - 1 };
        }
        return s;
      });
      set(STORAGE_KEYS.CODED_SEGMENTS, shiftedSegments);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex(c => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Cascade delete sub-codes
    const codesWithSubDeleted = codes.filter(c => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, codesWithSubDeleted);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Layout from '../../../shared/components/Layout';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { useInterviews } from '../hooks/useInterviews';
import { dbService } from '../../../services/dbService';
import { showToast } from '../../../lib/toast';

const InterviewDetailView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { getInterview, deleteInterview, refresh } = useInterviews(projectId);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [renameSpeaker, setRenameSpeaker] = useState<{ oldLabel: string; newLabel: string } | null>(null);

  // Sentence editing state
  const [editingIdx, setEditingIdx] = useState<number | null>(null);
  const [editBuffer, setEditBuffer] = useState<string>("");

  const interview = interviewId ? getInterview(interviewId) : null;

  if (!interview) return null;

  const handleDelete = () => {
    deleteInterview(interview.id);
    setShowDeleteConfirm(false);
    navigate(`/projects/${projectId}`);
  };

  const handleRenameSpeaker = () => {
    if (renameSpeaker && renameSpeaker.newLabel.trim()) {
      dbService.updateSpeakerLabel(interview.id, renameSpeaker.oldLabel, renameSpeaker.newLabel.trim());
      showToast.success(`Renamed ${renameSpeaker.oldLabel} to ${renameSpeaker.newLabel}`);
      setRenameSpeaker(null);
      refresh();
    }
  };

  const startEditing = (idx: number, currentText: string) => {
    setEditingIdx(idx);
    setEditBuffer(currentText);
  };

  const saveCorrection = () => {
    if (editingIdx !== null) {
      dbService.updateSentence(interview.id, editingIdx, { text: editBuffer });
      showToast.success('Verbatim corrected');
      setEditingIdx(null);
      refresh();
    }
  };

  const deleteSentence = (idx: number) => {
    if (confirm("Permanently delete this verbatim block? Coding segments for this block will be removed.")) {
      dbService.deleteSentence(interview.id, idx);
      showToast.success('Block removed');
      refresh();
    }
  };

  const getSpeakerColor = (name: string) => {
    const colors = ['#E07A5F', '#81B29A', '#3D405B', '#F2CC8F', '#A06040', '#4A6D5A'];
    let hash = 0;
    for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
  };

  return (
    <Layout 
      title={interview.title} 
      onBack={() => navigate(`/projects/${projectId}`)}
      actions={
        <button onClick={() => setShowDeleteConfirm(true)} className="p-2 text-slate/20 hover:text-red-500 transition-colors">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
        </button>
      }
    >
      <div className="max-w-4xl mx-auto space-y-8 pb-40 animate-fade-in">
        <div className="bg-white p-10 rounded-3xl shadow-lg border border-slate/5">
          <div className="space-y-8">
            {interview.sentences.map((s, idx) => (
              <div key={idx} className="flex gap-4 group items-start">
                <div className="flex flex-col items-end w-28 shrink-0 mt-1">
                   <span className="text-[9px] font-bold text-slate/10 group-hover:text-slate/20 transition-colors">#{String(idx + 1).padStart(3, '0')}</span>
                   <button 
                    onClick={() => setRenameSpeaker({ oldLabel: s.speaker, newLabel: s.speaker })}
                    className="text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-tighter truncate max-w-full hover:scale-105 transition-all active:scale-95"
                    style={{ backgroundColor: `${getSpeakerColor(s.speaker)}15`, color: getSpeakerColor(s.speaker) }}
                   >
                     {s.speaker}
                   </button>
                </div>

                <div className="flex-1 min-w-0">
                  {editingIdx === idx ? (
                    <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-200">
                      <textarea 
                        className="w-full p-4 bg-cream/30 border-2 border-terracotta rounded-2xl font-serif text-lg leading-relaxed outline-none focus:bg-white transition-all min-h-[120px]"
                        value={editBuffer}
                        onChange={(e) => setEditBuffer(e.target.value)}
                        autoFocus
                      />
                      <div className="flex gap-2">
                        <button onClick={saveCorrection} className="px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-md">Save Changes</button>
                        <button onClick={() => setEditingIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-xl font-bold text-sm">Cancel</button>
                      </div>
                    </div>
                  ) : (
                    <div className="relative group/sentence">
                      <p className="text-lg leading-relaxed text-charcoal/90 font-serif border-l-2 border-slate/5 pl-6 group-hover:border-terracotta/20 transition-colors whitespace-pre-wrap">
                        {s.text}
                      </p>
                      <div className="absolute right-0 top-0 opacity-0 group-hover/sentence:opacity-100 transition-opacity flex gap-2">
                        <button 
                          onClick={() => startEditing(idx, s.text)}
                          className="p-1.5 bg-white shadow-sm border border-slate/10 rounded-lg text-slate/40 hover:text-terracotta hover:border-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        </button>
                        <button 
                          onClick={() => deleteSentence(idx)}
                          className="p-1.5 bg-white shadow-sm border border-slate/10 rounded-lg text-slate/40 hover:text-red-500 hover:border-red-200 transition-all"
                          title="Delete Sentence"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>

        <button 
          onClick={() => navigate(`/projects/${projectId}/interviews/${interview.id}/coding`)}
          className="fixed bottom-12 right-8 h-16 px-10 bg-terracotta text-white rounded-full font-bold text-lg shadow-2xl hover:scale-105 transition-all z-50 flex items-center gap-3 active:scale-95"
        >
          Open Coding Studio
        </button>

        {renameSpeaker && (
          <div className="fixed inset-0 bg-slate/40 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
             <div className="bg-white p-10 rounded-3xl shadow-2xl max-w-md w-full space-y-6 animate-in zoom-in-95 duration-200">
                <h3 className="text-2xl font-bold text-slate">Rename Speaker</h3>
                <p className="text-slate/60 text-sm">Update "{renameSpeaker.oldLabel}" to a specific name or abbreviation globally.</p>
                <input 
                  type="text" 
                  value={renameSpeaker.newLabel}
                  onChange={(e) => setRenameSpeaker({ ...renameSpeaker, newLabel: e.target.value })}
                  className="w-full h-14 px-6 rounded-2xl border-2 border-slate/10 outline-none focus:border-terracotta text-lg font-bold"
                  autoFocus
                />
                <div className="flex gap-3 pt-4">
                   <button onClick={() => setRenameSpeaker(null)} className="flex-1 py-4 bg-slate/5 text-slate rounded-2xl font-bold">Cancel</button>
                   <button onClick={handleRenameSpeaker} className="flex-1 py-4 bg-terracotta text-white rounded-2xl font-bold shadow-lg">Update All</button>
                </div>
             </div>
          </div>
        )}

        <ConfirmDialog
          isOpen={showDeleteConfirm}
          title="Delete Interview?"
          message="This will permanently delete this interview and all its coded segments. This cannot be undone."
          confirmText="Delete"
          onConfirm={handleDelete}
          onCancel={() => setShowDeleteConfirm(false)}
          variant="danger"
        />
      </div>
    </Layout>
  );
};

export default InterviewDetailView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Correction state
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return; // Disable selection while editing
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 25 ? selectedText.substring(0, 25) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
      // segments state is updated in hook
    }
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle - Drag source for coding */}
                  {isPartiallySelected && selectedText && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Correction state
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
      showToast.success('Code applied');
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return; 
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    // Custom drag ghost
    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 25 ? selectedText.substring(0, 25) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleUpdateCodeColor = (codeId: string, color: string) => {
    dbService.updateCode(codeId, { color });
    refreshCodes();
    showToast.success('Color updated');
  };

  const handleUpdateCodeComment = (codeId: string, comment: string) => {
    dbService.updateCode(codeId, { comment });
    refreshCodes();
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const handleAddSubCode = (parentId: string) => {
    const label = prompt("Enter name for this sub-concept:");
    if (label) {
      const parent = codes.find(c => c.id === parentId);
      addCode(label, parent?.color || CODE_COLORS[0], false, parentId);
    }
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            {level === 0 && (
              <div className={`p-1 transition-transform ${isExpanded ? 'rotate-90' : ''} ${children.length > 0 ? 'opacity-100' : 'opacity-0'}`}>
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
              </div>
            )}

            <div className="relative group/color-swatch flex-shrink-0">
               <div className="w-5 h-5 rounded-full shadow-sm border-2 border-white" style={{ backgroundColor: code.color }} />
               <div className="absolute top-0 left-0 opacity-0 pointer-events-none group-hover/color-swatch:pointer-events-auto group-hover/color-swatch:opacity-100 transition-opacity bg-white shadow-2xl rounded-xl p-3 grid grid-cols-4 gap-2 z-[70] w-36 -translate-x-1/2 mt-4 border border-slate/5">
                 {CODE_COLORS.map(c => (
                   <button 
                    key={c} 
                    onClick={(e) => { e.stopPropagation(); handleUpdateCodeColor(code.id, c); }} 
                    className="w-6 h-6 rounded-full hover:scale-125 transition-transform shadow-sm" 
                    style={{ backgroundColor: c }} 
                   />
                 ))}
               </div>
            </div>

            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); setEditingCodeId(isEditing ? null : code.id); }} 
                className={`p-1 rounded hover:bg-white transition-colors ${isEditing ? 'text-terracotta' : 'text-slate/40'}`}
                title="Edit notes & definition"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </button>
              {level === 0 && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleAddSubCode(code.id); }} 
                  className="p-1 text-slate/40 hover:text-terracotta rounded hover:bg-white"
                  title="Add Sub-concept"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </button>
              )}
            </div>

            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>

          {isEditing && (
            <div className="mt-3 space-y-3 animate-fade-in" onClick={e => e.stopPropagation()}>
              <textarea 
                defaultValue={code.comment}
                placeholder="Memo, definition, or coding rule..."
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate/10 focus:border-terracotta outline-none h-24 resize-none font-medium shadow-inner"
                onBlur={(e) => handleUpdateCodeComment(code.id, e.target.value)}
              />
              <div className="flex justify-between items-center">
                <button 
                  onClick={() => { if(confirm("Delete this concept permanently?")) deleteCode(code.id); }} 
                  className="text-[10px] text-red-500 font-bold hover:underline px-2 py-1 hover:bg-red-50 rounded"
                >
                  Delete Concept
                </button>
                <span className="text-[9px] text-slate/30 font-bold uppercase tracking-widest">Saved locally</span>
              </div>
            </div>
          )}
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - CRITICAL: Removed draggable from container to allow mouse selection */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle - FIXED: This is now the ONLY draggable element, enabling normal mouse selection on text */}
                  {isPartiallySelected && selectedText && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar - Hierarchical Codebook */}
        <aside className="w-96 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <div className="flex justify-between items-center mb-2">
               <h2 className="text-lg font-bold text-slate">Codebook</h2>
               <button 
                  onClick={() => { const l = prompt("Enter name for a new root concept:"); if(l) addCode(l, CODE_COLORS[0]); }}
                  className="p-1.5 bg-white border border-slate/10 hover:border-terracotta hover:text-terracotta rounded-lg transition-all shadow-sm group"
                  title="New Root Category"
               >
                 <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
               </button>
            </div>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select verbatim text <br/> 2. Drag handle to a code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {rootCodes.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
                <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                <p className="text-sm font-bold uppercase tracking-widest">Library Empty</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 flex flex-col gap-2">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-sm shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              Quick Search & Apply
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-terracotta text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all border-4 border-white/20"
          >
            Assign Concept
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Quilta Coding Guide"
        message="• HIGHLIGHT: Use your mouse or touchscreen to select verbatim text directly from the transcript. • DRAG: A terracotta handle will appear; drag this handle onto any concept in the right sidebar. • MULTI-SELECT: Use Ctrl+Click on sentences to select entire blocks. • MEMOS: Click the pencil icon on any code to add definitions or research notes."
        confirmText="Start Research"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start,
      end: offsets?.end
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const deleteSentence = (idx: number) => {
    if (confirm("Delete this block? Associated codes will be removed and subsequent blocks will shift up.")) {
      dbService.deleteSentence(interview.id, idx);
      showToast.success('Block deleted');
      setSelectedIdx(null);
      setSelectedText("");
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const isExpanded = expandedCodes.has(code.id);
    const isEditing = editingCodeId === code.id;
    const children = subCodesMap[code.id] || [];

    return (
      <div key={code.id} className="space-y-1">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`group flex flex-col p-3 rounded-xl border-2 transition-all cursor-pointer ${isDraggingOverCode === code.id ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' : 'border-transparent bg-slate/5 hover:bg-slate/10'} ${level > 0 ? 'ml-6' : ''}`}
          onClick={() => level === 0 && children.length > 0 && toggleExpand(code.id)}
        >
          <div className="flex items-center gap-2">
            <div className="w-4 h-4 rounded-full shadow-inner" style={{ backgroundColor: code.color }} />
            <p className="font-bold text-slate text-sm truncate flex-1">{code.label}</p>
            <span className="text-[10px] text-slate/40 font-bold px-2 py-0.5 bg-white rounded-md shadow-sm select-none border border-slate/5">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>
        {isExpanded && children.map(sub => renderCodeItem(sub, level + 1))}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area - CRITICAL: select-text enabled, no draggable on container */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isPartiallySelected = selectedIdx === idx;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle - This is the ONLY draggable element to preserve normal highlighting */}
                  {isPartiallySelected && selectedText && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" /></svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-2">
            {rootCodes.map(code => renderCodeItem(code))}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-terracotta text-white rounded-xl font-bold text-sm shadow-md"
            >
              Manage Codes
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Coding Guide"
        message="1. HIGHLIGHT: Highlight text with your mouse. 2. DRAG: Grab the handle that appears on the left. 3. APPLY: Drop it onto a code in the sidebar. 4. EDIT: Click the pencil icon to fix transcription errors."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

