      case 'CODING': return currentProject && currentInterview ? <CodingView project={currentProject} interview={currentInterview} codes={codes} onFinish={() => setView('INTERVIEW_DETAIL')} onCodesUpdated={(c) => setCodes(c)} /> : null;
