                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-2">
            {rootCodes.map(code => renderCodeItem(code))}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10">
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-terracotta text-white rounded-xl font-bold text-sm shadow-md"
            >
              Manage Codes
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : selectedText}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv) => {
          const newCode = addCode(l, c, iv);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Coding Guide"
        message="1. HIGHLIGHT: Highlight text with your mouse. 2. DRAG: Grab the handle that appears on the left. 3. APPLY: Drop it onto a code in the sidebar. 4. EDIT: Click the pencil icon to fix transcription errors."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

