      default: return null;
    }
  };

  return (
    <div className="App">
      <Toaster position="top-right" />
      {renderView()}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);
  const [editingCodeId, setEditingCodeId] = useState<string | null>(null);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingOverNew(false);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      // The modal is already set to use the current 'selectedText'
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const deleteSentence = (idx: number) => {
    if (confirm("Delete this block? Associated codes will be removed and subsequent blocks will shift up.")) {
      dbService.deleteSentence(interview.id, idx);
      showToast.success('Block deleted');
      setSelectedIdx(null);
      setSelectedText("");
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;

    return (
      <div key={code.id} className="group/item">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-2.5 rounded-xl border-2 transition-all cursor-pointer ${
            isDraggingOverCode === code.id 
              ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10' 
              : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          <div className="flex items-center gap-2 flex-1 min-w-0">
            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            {/* New Concept Drop Zone */}
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => setIsModalOpen(true)}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta">
                {isDraggingOverNew ? 'Drop to Create' : 'New Concept'}
              </p>
            </div>

            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              Manage Taxonomy
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : (selectedText || "New segment")}
        existingCodes={codes}
        onApply={onApply}
        onCreateAndApply={(l, c, iv, pid) => {
          const newCode = addCode(l, c, iv, pid);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      <ConfirmDialog
        isOpen={showHelp}
        title="Coding Guide"
        message="HIGHLIGHT: Select text in the transcript. DRAG: Grab the handle that appears. APPLY: Drop it onto an existing code. CREATE: Drop it onto 'New Concept' to create a sub-code or root category. MANAGE: Use the taxonomy button to rearrange hierarchy."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { Code } from '../../../types';
import { CODE_COLORS } from '../../../constants';

interface CodeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedSnippet: string;
  existingCodes: Code[];
  onApply: (code: Code) => void;
  // Fix: Added parentId to the callback signature to resolve type mismatch in CodingView.tsx
  onCreateAndApply: (label: string, color: string, isInVivo?: boolean, parentId?: string) => void;
  onDeleteCode?: (codeId: string) => void;
  codeUsageCounts?: Record<string, number>;
}

const CodeSelectionModal: React.FC<CodeSelectionModalProps> = ({
  isOpen,
  onClose,
  selectedSnippet,
  existingCodes,
  onApply,
  onCreateAndApply,
  onDeleteCode,
  codeUsageCounts = {}
}) => {
  const [newLabel, setNewLabel] = useState('');
  const [color, setColor] = useState(CODE_COLORS[0]);
  const [search, setSearch] = useState('');
  const [codeToDelete, setCodeToDelete] = useState<Code | null>(null);
  // Add state for hierarchical category creation
  const [selectedParentId, setSelectedParentId] = useState<string>('');

  const filtered = useMemo(() => {
    return existingCodes.filter(c => 
      c.label.toLowerCase().includes(search.toLowerCase())
    ).sort((a, b) => (codeUsageCounts[b.id] || 0) - (codeUsageCounts[a.id] || 0));
  }, [existingCodes, search, codeUsageCounts]);

  // Root codes used for the parent selection dropdown
  const rootCodesForParentSelection = useMemo(() => 
    existingCodes.filter(c => !c.parent_id), 
    [existingCodes]
  );

  if (!isOpen) return null;

  const finalizeDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (codeToDelete && onDeleteCode) {
      onDeleteCode(codeToDelete.id);
      setCodeToDelete(null);
    }
  };

  // Helper to trigger creation with parent selection
  const handleCreateNew = () => {
    if (newLabel.length >= 2) {
      onCreateAndApply(newLabel, color, false, selectedParentId || undefined);
      setNewLabel('');
      setSelectedParentId('');
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center bg-slate/40 backdrop-blur-sm">
      <div className="fixed inset-0" onClick={onClose} />
      <div className="relative w-full max-w-2xl bg-cream rounded-t-[40px] shadow-2xl flex flex-col max-h-[90vh] animate-in slide-in-from-bottom-full duration-300" style={{ height: '85%' }}>
        <div className="w-16 h-1.5 bg-slate/10 rounded-full mx-auto mt-4 mb-2" />
        <div className="p-10 overflow-y-auto flex-1 space-y-12">
          <header className="flex justify-between items-start">
            <h2 className="text-3xl font-bold text-slate">Assign Code</h2>
            <button onClick={onClose} className="p-3 bg-slate/5 rounded-full text-slate/40 hover:bg-slate/10 transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
          </header>

          <div className="p-6 bg-white rounded-3xl border-l-8 border-terracotta shadow-sm italic text-xl font-serif text-charcoal">
             "{selectedSnippet}"
          </div>

          <section className="space-y-6">
            <div className="flex items-center justify-between gap-4">
              <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">Research Taxonomy</h3>
              <input 
                type="text" 
                placeholder="Search codes..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="flex-1 max-w-[200px] h-10 px-4 bg-white/50 border border-slate/10 rounded-xl text-sm focus:bg-white transition-all outline-none"
                autoFocus
              />
            </div>

            <div className="grid grid-cols-1 gap-3">
              {filtered.map(c => (
                <div key={c.id} className="group relative flex items-center gap-2">
                  <button onClick={() => onApply(c)} className="flex-1 flex items-center gap-5 p-5 bg-white rounded-2xl border border-slate/5 hover:border-terracotta/30 hover:shadow-lg active:scale-[0.98] transition-all text-left group">
                    <div className="w-5 h-5 rounded-full shadow-inner" style={{ backgroundColor: c.color }} />
                    <span className="font-bold text-slate flex-1 truncate text-lg">{c.label}</span>
                    <span className="px-3 py-1 bg-slate/5 rounded-full text-[10px] font-bold text-slate/30">{codeUsageCounts[c.id] || 0} usage</span>
                  </button>
                  <button 
                    onClick={(e) => { e.stopPropagation(); setCodeToDelete(c); }}
                    className="p-3 opacity-0 group-hover:opacity-100 hover:text-red-500 text-slate/20 transition-all"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              ))}
            </div>
          </section>

          <section className="space-y-6 pb-20">
            <h3 className="text-[10px] font-bold text-slate/30 uppercase tracking-[0.2em]">Add New Concept</h3>
            <div className="space-y-4">
              <div className="flex gap-4">
                <input type="text" value={newLabel} onChange={(e) => setNewLabel(e.target.value)} placeholder="Category label..." className="flex-1 h-16 px-6 rounded-2xl border-2 border-slate/5 bg-white font-bold text-slate outline-none focus:border-terracotta" />
                <button onClick={handleCreateNew} disabled={newLabel.length < 2} className="px-8 bg-slate text-white rounded-2xl font-bold shadow-lg disabled:opacity-20 hover:bg-terracotta transition-all">Create</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate/40 uppercase tracking-widest">Parent Concept (Optional)</label>
                <select 
                  value={selectedParentId} 
                  onChange={(e) => setSelectedParentId(e.target.value)}
                  className="w-full h-14 px-4 rounded-xl border-2 border-slate/5 bg-white text-slate font-medium outline-none focus:border-terracotta transition-colors"
                >
                  <option value="">No Parent (Root Category)</option>
                  {rootCodesForParentSelection.map(c => (
                    <option key={c.id} value={c.id}>{c.label}</option>
                  ))}
                </select>
              </div>

              <div className="flex flex-wrap gap-4">
                {CODE_COLORS.map(c => <button key={c} onClick={() => setColor(c)} className={`w-10 h-10 rounded-full transition-all border-4 ${color === c ? 'border-white ring-2 ring-terracotta scale-110' : 'border-transparent opacity-60'}`} style={{ backgroundColor: c }} />)}
              </div>
            </div>
            {!selectedSnippet.includes('Multiple') && (
              <button onClick={() => onCreateAndApply(selectedSnippet, color, true)} className="w-full p-6 bg-sage/5 border-2 border-dashed border-sage/20 rounded-2xl hover:bg-sage/10 text-sage font-bold flex justify-between items-center transition-all">
                <span>⚡ Use verbatim as In Vivo code</span>
                <svg className="w-6 h-6 opacity-30" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </button>
            )}
          </section>
        </div>

        {/* Confirmation overlay */}
        {codeToDelete && (
          <div className="absolute inset-0 z-[110] bg-cream/95 backdrop-blur-sm rounded-t-[40px] flex items-center justify-center p-12 text-center animate-in zoom-in-95 duration-200">
             <div className="space-y-6 max-w-sm">
                <h3 className="text-2xl font-bold text-slate">Delete "{codeToDelete.label}"?</h3>
                <p className="text-slate/60">This will remove this code from all interviews in your project. This action is irreversible.</p>
                <div className="flex gap-3">
                   <button onClick={(e) => { e.stopPropagation(); setCodeToDelete(null); }} className="flex-1 h-14 bg-slate/5 text-slate rounded-2xl font-bold">Cancel</button>
                   <button onClick={finalizeDelete} className="flex-1 h-14 bg-red-600 text-white rounded-2xl font-bold shadow-lg">Delete</button>
                </div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CodeSelectionModal;

import { GoogleGenAI, Type } from "@google/genai";

// Always initialize GoogleGenAI with the apiKey property from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `You are a professional multilingual qualitative research assistant. 
Your task is to transcribe content EXACTLY as it is spoken and IDENTIFY SPEAKERS.

RULES:
1. VERBATIM ONLY: Do not summarize. Preserve filler words ("uh", "um", "well", "ah") and stuttering.
2. NO TRANSLATION: Transcribe in the original language.
3. SPEAKER IDENTIFICATION: Identify different speakers. 
   - Use provided "Speaker Hints" if available to map identities.
   - Otherwise, label them as "Interviewer" and "Respondent" if clear.
   - Use "Speaker 1", "Speaker 2", etc. as fallback.
   - Use consistent labels throughout.
4. FORMAT: Return a JSON array of objects, each containing "speaker" and "text" fields.
5. LENGTH: If the input is very long, ensure the JSON array is complete and valid. Do not cut off mid-object.`;

const SENTENCE_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      speaker: { type: Type.STRING, description: "Label of the speaker (e.g. Interviewer, Respondent, S1)" },
      text: { type: Type.STRING, description: "The verbatim sentence or segment spoken." }
    },
    required: ["speaker", "text"]
  }
};

export const transcribeAudio = async (
  base64Data: string, 
  mimeType: string, 
  languageLabel: string = "Auto-Detect",
  speakerHints: string = ""
): Promise<{speaker: string, text: string}[]> => {
  try {
    const languageInstruction = languageLabel === "Auto-Detect" 
      ? "Automatically detect the language used in this audio." 
      : `The speaker is using ${languageLabel}.`;

    const hintInstruction = speakerHints ? `\n\nSPEAKER HINTS: Use these identities for mapping: ${speakerHints}` : "";

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      // Using parts array directly for multi-part input as per guidelines
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `${SYSTEM_PROMPT}${hintInstruction}\n\nTask: ${languageInstruction}\nProvide a complete JSON array of structured transcript segments with speaker labels. Ensure the JSON is terminated correctly.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: SENTENCE_SCHEMA,
        thinkingConfig: { thinkingBudget: 4000 },
        maxOutputTokens: 8192
      }
    });

    // Access .text property directly (not as a method)
    const text = response.text || '[]';
    return JSON.parse(text);
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Verbatim transcription failed.");
  }
};

export const processDocument = async (
  payload: { base64?: string, text?: string, mimeType?: string },
  speakerHints: string = ""
): Promise<{speaker: string, text: string}[]> => {
  try {
    const parts: any[] = [];
    const hintInstruction = speakerHints ? `\n\nSPEAKER HINTS: Use these identities for mapping: ${speakerHints}` : "";

    if (payload.base64 && payload.mimeType === 'application/pdf') {
      parts.push({ inlineData: { data: payload.base64, mimeType: 'application/pdf' } });
      parts.push({ text: `${SYSTEM_PROMPT}${hintInstruction}\n\nExtract text from this PDF verbatim. Try to identify speakers. Return a complete, valid JSON array of speaker/text objects. Do not truncate.` });
    } else if (payload.text) {
      parts.push({ text: `${SYSTEM_PROMPT}${hintInstruction}\n\nSegment this text verbatim and identify speakers. Return a complete, valid JSON array of speaker/text objects:\n\n${payload.text}` });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: SENTENCE_SCHEMA,
        thinkingConfig: { thinkingBudget: 4000 },
        maxOutputTokens: 8192
      }
    });

    // Access .text property directly
    const text = response.text || '[]';
    return JSON.parse(text);
  } catch (error) {
    console.error("Doc Processing Error:", error);
    return [{ speaker: "System", text: "Error: Extraction failed. The document might be too large or complex for a single pass." }];
  }
};

export const generateReport = async (
  projectTitle: string, 
  codes: {label: string, segments: {text: string, ref: number}[]}[]
): Promise<string> => {
  const context = codes.map(c => 
    `Code: ${c.label}\nQuotes:\n${c.segments.map(s => `- [#${s.ref + 1}] "${s.text}"`).join('\n')}`
  ).join('\n\n');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a researcher. Write a thematic synthesis for "${projectTitle}".
      Data:
      ${context}

      Structure: Intro, Findings (citing quotes verbatim and mentioning speaker patterns if relevant), Conclusion.`,
      config: {
        thinkingConfig: { thinkingBudget: 2000 }
      }
    });
    // Access .text property directly
    return response.text || "Report generation failed.";
  } catch (error) {
    return "Thematic analysis failed.";
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Drag states
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverPlus, setIsDraggingOverPlus] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);
  const [preSelectedParentId, setPreSelectedParentId] = useState<string | undefined>(undefined);

  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
    setPreSelectedParentId(undefined);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, code: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      try {
        const data = JSON.parse(dataStr);
        applyCode(code.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${code.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
      } catch (err) {
        console.error("Drop failed", err);
      }
    }
  };

  const handleDropToCreateSub = (e: React.DragEvent, parentCode: Code) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingOverPlus(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(parentCode.id);
      setIsModalOpen(true);
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingOverNew(false);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(undefined);
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const deleteSentence = (idx: number) => {
    if (confirm("Delete this block? Associated codes will be removed and subsequent blocks will shift up.")) {
      dbService.deleteSentence(interview.id, idx);
      showToast.success('Block deleted');
      setSelectedIdx(null);
      setSelectedText("");
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;
    const isAssignTarget = isDraggingOverCode === code.id;
    const isPlusTarget = isDraggingOverPlus === code.id;

    return (
      <div key={code.id} className="group/item">
        <div 
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-2.5 rounded-xl border-2 transition-all cursor-pointer ${
            isAssignTarget 
              ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10' 
              : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          <div className="flex items-center gap-2 flex-1 min-w-0">
            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            {/* Sub-code Creation Target - Only visible/active for Root codes and when dragging */}
            {level === 0 && (
              <div 
                onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDraggingOverPlus(code.id); }}
                onDragLeave={() => setIsDraggingOverPlus(null)}
                onDrop={(e) => handleDropToCreateSub(e, code)}
                className={`p-1 rounded-md transition-all ${
                  isPlusTarget ? 'bg-terracotta text-white scale-125' : 'text-slate/20 hover:text-terracotta'
                }`}
                title="Drop here to create sub-code"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
              </div>
            )}

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign or create code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            {/* New Concept Drop Zone */}
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta">
                {isDraggingOverNew ? 'Drop to Create' : 'New Concept'}
              </p>
            </div>

            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
