import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  updateSentence: (interviewId: string, index: number, updates: Partial<TranscriptSentence>): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview && interview.sentences[index]) {
      interview.sentences[index] = { ...interview.sentences[index], ...updates };
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteSentence: (interviewId: string, index: number): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interviewIndex = interviews.findIndex((i: Interview) => i.id === interviewId);
    if (interviewIndex !== -1) {
      const interview = interviews[interviewIndex];
      interview.sentences.splice(index, 1);
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);

      // Cascading shifts for coded segments
      const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
      const filteredSegments = segments.filter(s => !(s.interview_id === interviewId && s.sentence_index === index));
      const shiftedSegments = filteredSegments.map(s => {
        if (s.interview_id === interviewId && s.sentence_index > index) {
          return { ...s, sentence_index: s.sentence_index - 1 };
        }
        return s;
      });
      set(STORAGE_KEYS.CODED_SEGMENTS, shiftedSegments);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex(c => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Cascade delete sub-codes
    const codesWithSubDeleted = codes.filter(c => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, codesWithSubDeleted);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  mergeCodes: (sourceId: string, targetId: string): void => {
    if (sourceId === targetId) return;

    const codes = get(STORAGE_KEYS.CODES, []);
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);

    // 1. Reassign all segments from source to target
    const updatedSegments = segments.map(s => 
      s.code_id === sourceId ? { ...s, code_id: targetId } : s
    );
    set(STORAGE_KEYS.CODED_SEGMENTS, updatedSegments);

    // 2. Reparent any sub-codes of the source to the target
    const updatedCodes = codes.map(c => 
      c.parent_id === sourceId ? { ...c, parent_id: targetId } : c
    );

    // 3. Delete the source code
    const finalCodes = updatedCodes.filter(c => c.id !== sourceId);
    set(STORAGE_KEYS.CODES, finalCodes);
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Merge state
  const [mergeConfirmation, setMergeConfirmation] = useState<{ source: Code, target: Code } | null>(null);

  // Drag states
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverPlus, setIsDraggingOverPlus] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);
  const [preSelectedParentId, setPreSelectedParentId] = useState<string | undefined>(undefined);

  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    // Calculate global usage for this project
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
    setPreSelectedParentId(undefined);
  };

  if (!interview) return null;

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    const data = {
      type: 'segment',
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleCodeDragStart = (e: React.DragEvent, code: Code) => {
    const data = {
      type: 'code',
      codeId: code.id
    };
    e.dataTransfer.setData('application/quilta-code', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'move';

    const ghost = document.createElement('div');
    ghost.className = "px-4 py-2 bg-slate text-white rounded-lg font-bold text-xs shadow-xl";
    ghost.innerText = `Merge: ${code.label}`;
    document.body.appendChild(ghost);
    e.dataTransfer.setDragImage(ghost, 0, 0);
    setTimeout(() => document.body.removeChild(ghost), 0);
  };

  const handleDropOnCode = (e: React.DragEvent, targetCode: Code) => {
    e.preventDefault();
    setIsDraggingOverCode(null);

    // Case 1: Dropping a text segment to code it
    const segmentDataStr = e.dataTransfer.getData('application/quilta-selection');
    if (segmentDataStr) {
      try {
        const data = JSON.parse(segmentDataStr);
        applyCode(targetCode.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${targetCode.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
        return;
      } catch (err) { /* ignore */ }
    }

    // Case 2: Dropping a code to merge it
    const codeDataStr = e.dataTransfer.getData('application/quilta-code');
    if (codeDataStr) {
      try {
        const data = JSON.parse(codeDataStr);
        if (data.codeId === targetCode.id) return; // Can't merge with self

        const sourceCode = codes.find(c => c.id === data.codeId);
        if (sourceCode) {
          setMergeConfirmation({ source: sourceCode, target: targetCode });
        }
      } catch (err) { /* ignore */ }
    }
  };

  const finalizeMerge = () => {
    if (!mergeConfirmation) return;
    const { source, target } = mergeConfirmation;
    dbService.mergeCodes(source.id, target.id);
    refreshCodes();
    setMergeConfirmation(null);
    showToast.success(`Merged "${source.label}" into "${target.label}"`);
  };

  const handleDropToCreateSub = (e: React.DragEvent, parentCode: Code) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingOverPlus(null);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(parentCode.id);
      setIsModalOpen(true);
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingOverNew(false);
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(undefined);
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const deleteSentence = (idx: number) => {
    if (confirm("Delete this block? Associated codes will be removed and subsequent blocks will shift up.")) {
      dbService.deleteSentence(interview.id, idx);
      showToast.success('Block deleted');
      setSelectedIdx(null);
      setSelectedText("");
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;
    const isTarget = isDraggingOverCode === code.id;
    const isPlusTarget = isDraggingOverPlus === code.id;

    return (
      <div key={code.id} className="group/item">
        <div 
          draggable
          onDragStart={(e) => handleCodeDragStart(e, code)}
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-2.5 rounded-xl border-2 transition-all cursor-pointer ${
            isTarget 
              ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10' 
              : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          <div className="flex items-center gap-2 flex-1 min-w-0">
            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            {/* Sub-code Creation Target */}
            {level === 0 && (
              <div 
                onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDraggingOverPlus(code.id); }}
                onDragLeave={() => setIsDraggingOverPlus(null)}
                onDrop={(e) => handleDropToCreateSub(e, code)}
                className={`p-1 rounded-md transition-all ${
                  isPlusTarget ? 'bg-terracotta text-white scale-125' : 'text-slate/20 hover:text-terracotta'
                }`}
                title="Drop here to create sub-code"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
              </div>
            )}

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleDragStart(e, idx)}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign or create code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta">
                {isDraggingOverNew ? 'Drop to Create' : 'New Concept'}
              </p>
            </div>

            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              Manage Taxonomy
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => { setIsModalOpen(false); setPreSelectedParentId(undefined); }}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : (selectedText || "New segment")}
        existingCodes={codes}
        onApply={onApply}
        initialParentId={preSelectedParentId}
        onCreateAndApply={(l, c, iv, pid) => {
          const newCode = addCode(l, c, iv, pid);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      {mergeConfirmation && (
        <ConfirmDialog
          isOpen={!!mergeConfirmation}
          title="Merge Concepts?"
          message={`Are you sure you want to merge "${mergeConfirmation.source.label}" into "${mergeConfirmation.target.label}"? All coded segments will be reassigned, and sub-concepts will be moved. This cannot be undone.`}
          confirmText="Merge Concepts"
          onConfirm={finalizeMerge}
          onCancel={() => setMergeConfirmation(null)}
          variant="warning"
        />
      )}

      <ConfirmDialog
        isOpen={showHelp}
        title="Coding Guide"
        message="HIGHLIGHT: Select text. DRAG: Grab the handle to code. MERGE: Drag one code over another in the sidebar to combine them. SUB-CODE: Drop selection on '+' next to a code. NEW ROOT: Drop on 'New Concept'."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Drag-and-Drop State
  const [dragType, setDragType] = useState<'segment' | 'code' | null>(null);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverPlus, setIsDraggingOverPlus] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);

  // Merge state
  const [mergeConfirmation, setMergeConfirmation] = useState<{ source: Code, target: Code } | null>(null);
  const [preSelectedParentId, setPreSelectedParentId] = useState<string | undefined>(undefined);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
    setPreSelectedParentId(undefined);
  };

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleSegmentDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    setDragType('segment');
    const data = {
      type: 'segment',
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleCodeDragStart = (e: React.DragEvent, code: Code) => {
    setDragType('code');
    const data = {
      type: 'code',
      codeId: code.id
    };
    e.dataTransfer.setData('application/quilta-code', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'move';

    const ghost = document.createElement('div');
    ghost.className = "px-5 py-3 bg-slate text-white rounded-xl font-bold text-sm shadow-2xl flex items-center gap-2";
    ghost.innerHTML = `<span style="width:12px; height:12px; background:${code.color}; border-radius:100%"></span> Merge: ${code.label}`;
    document.body.appendChild(ghost);
    e.dataTransfer.setDragImage(ghost, 0, 0);
    setTimeout(() => document.body.removeChild(ghost), 0);
  };

  const handleDragEnd = () => {
    setDragType(null);
    setIsDraggingOverCode(null);
    setIsDraggingOverPlus(null);
    setIsDraggingOverNew(false);
  };

  const handleDropOnCode = (e: React.DragEvent, targetCode: Code) => {
    e.preventDefault();
    const type = dragType;
    handleDragEnd();

    // Case 1: Dropping a text segment to code it
    const segmentDataStr = e.dataTransfer.getData('application/quilta-selection');
    if (segmentDataStr) {
      try {
        const data = JSON.parse(segmentDataStr);
        applyCode(targetCode.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${targetCode.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
        return;
      } catch (err) { /* ignore */ }
    }

    // Case 2: Dropping a code to merge it
    const codeDataStr = e.dataTransfer.getData('application/quilta-code');
    if (codeDataStr) {
      try {
        const data = JSON.parse(codeDataStr);
        if (data.codeId === targetCode.id) return; // Can't merge with self

        const sourceCode = codes.find(c => c.id === data.codeId);
        if (sourceCode) {
          setMergeConfirmation({ source: sourceCode, target: targetCode });
        }
      } catch (err) { /* ignore */ }
    }
  };

  const finalizeMerge = () => {
    if (!mergeConfirmation) return;
    const { source, target } = mergeConfirmation;
    dbService.mergeCodes(source.id, target.id);
    refreshCodes();
    setMergeConfirmation(null);
    showToast.success(`Merged "${source.label}" into "${target.label}"`);
  };

  const handleDropToCreateSub = (e: React.DragEvent, parentCode: Code) => {
    e.preventDefault();
    e.stopPropagation();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(parentCode.id);
      setIsModalOpen(true);
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(undefined);
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;

    const isDropTarget = isDraggingOverCode === code.id;
    const isMergeAction = dragType === 'code' && isDropTarget;
    const isCodingAction = dragType === 'segment' && isDropTarget;
    const isPlusTarget = isDraggingOverPlus === code.id;

    return (
      <div key={code.id} className="group/item">
        <div 
          draggable
          onDragStart={(e) => handleCodeDragStart(e, code)}
          onDragEnd={handleDragEnd}
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-3 rounded-xl border-2 transition-all cursor-pointer relative ${
            isMergeAction 
              ? 'border-terracotta border-dashed bg-terracotta/5 scale-[1.05] shadow-xl z-20 animate-pulse' 
              : isCodingAction
                ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10'
                : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          {isMergeAction && (
             <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-terracotta text-white text-[9px] px-2 py-0.5 rounded-full font-bold uppercase shadow-lg">Merge Target</div>
          )}

          <div className="flex items-center gap-2 flex-1 min-w-0">
            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            {/* Sub-code Creation Target - Hide during code merging */}
            {level === 0 && dragType !== 'code' && (
              <div 
                onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDraggingOverPlus(code.id); }}
                onDragLeave={() => setIsDraggingOverPlus(null)}
                onDrop={(e) => handleDropToCreateSub(e, code)}
                className={`p-1.5 rounded-md transition-all ${
                  isPlusTarget ? 'bg-terracotta text-white scale-125' : 'text-slate/20 hover:text-terracotta'
                }`}
                title="Drop selection to create sub-concept"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
              </div>
            )}

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleSegmentDragStart(e, idx)}
                      onDragEnd={handleDragEnd}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign or create code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta">
                {isDraggingOverNew ? 'Drop to Create' : 'New Concept'}
              </p>
            </div>

            <button 
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              Manage Taxonomy
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => { setIsModalOpen(false); setPreSelectedParentId(undefined); }}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : (selectedText || "New segment")}
        existingCodes={codes}
        onApply={onApply}
        initialParentId={preSelectedParentId}
        onCreateAndApply={(l, c, iv, pid) => {
          const newCode = addCode(l, c, iv, pid);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      {mergeConfirmation && (
        <ConfirmDialog
          isOpen={!!mergeConfirmation}
          title="Merge Research Concepts?"
          message={`Are you sure you want to merge "${mergeConfirmation.source.label}" into "${mergeConfirmation.target.label}"? All segments currently assigned to "${mergeConfirmation.source.label}" will be permanently reassigned to "${mergeConfirmation.target.label}". This operation is irreversible.`}
          confirmText="Merge Concepts"
          onConfirm={finalizeMerge}
          onCancel={() => setMergeConfirmation(null)}
          variant="warning"
        />
      )}

      <ConfirmDialog
        isOpen={showHelp}
        title="Researcher's Manual: Drag & Drop"
        message="HIGHLIGHT: Select text in transcript. HANDLE: Drag selection onto a code to assign. MERGE: Drag one code over another in the sidebar to combine them. SUB-CODE: Drop selection onto the '+' icon next to any parent code."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { useState, useEffect } from 'react';
import { dbService } from '../../../services/dbService';
import { Code, CodedSegment } from '../../../types';
import { showToast } from '../../../lib/toast';

export const useCoding = (projectId?: string, interviewId?: string) => {
  const [codes, setCodes] = useState<Code[]>([]);
  const [segments, setSegments] = useState<CodedSegment[]>([]);

  const refreshCodes = () => {
    if (projectId) setCodes(dbService.getCodes(projectId));
  };

  // Add refreshSegments to trigger re-renders of components dependent on the transcript data
  const refreshSegments = () => {
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
  };

  useEffect(() => {
    if (projectId) setCodes(dbService.getCodes(projectId));
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
  }, [projectId, interviewId]);

  const addCode = (label: string, color: string, isInVivo?: boolean, parentId?: string) => {
    if (!projectId) return;
    const newCode = dbService.createCode(projectId, label, color, undefined, isInVivo, parentId);
    refreshCodes();
    return newCode;
  };

  const deleteCode = (codeId: string) => {
    dbService.deleteCode(codeId);
    refreshCodes();
    if (interviewId) setSegments(dbService.getCodedSegments(interviewId));
    showToast.success('Code deleted and segments unlinked');
  };

  const applyCode = (codeId: string, segmentText: string, sentenceIndex: number, start: number, end: number) => {
    if (!interviewId) return;
    const segment = dbService.saveCodedSegment({
      interview_id: interviewId,
      code_id: codeId,
      segment_text: segmentText,
      sentence_index: sentenceIndex,
      start_char: start,
      end_char: end
    });
    setSegments(prev => [...prev, segment]);
    showToast.success('Code applied');
  };

  const removeSegment = (id: string) => {
    dbService.deleteCodedSegment(id);
    setSegments(prev => prev.filter(s => s.id !== id));
    showToast.success('Coding removed');
  };

  return {
    codes,
    segments,
    addCode,
    deleteCode,
    applyCode,
    removeSegment,
    refreshCodes,
    refreshSegments
  };
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes, refreshSegments } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Drag-and-Drop State
  const [dragType, setDragType] = useState<'segment' | 'code' | null>(null);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverPlus, setIsDraggingOverPlus] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);

  // Merge state
  const [mergeConfirmation, setMergeConfirmation] = useState<{ source: Code, target: Code } | null>(null);
  const [preSelectedParentId, setPreSelectedParentId] = useState<string | undefined>(undefined);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
    setPreSelectedParentId(undefined);
  };

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleSegmentDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    setDragType('segment');
    const data = {
      type: 'segment',
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleCodeDragStart = (e: React.DragEvent, code: Code) => {
    setDragType('code');
    const data = {
      type: 'code',
      codeId: code.id
    };
    e.dataTransfer.setData('application/quilta-code', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'move';

    const ghost = document.createElement('div');
    ghost.className = "px-5 py-3 bg-slate text-white rounded-xl font-bold text-sm shadow-2xl flex items-center gap-2";
    ghost.innerHTML = `<span style="width:12px; height:12px; background:${code.color}; border-radius:100%"></span> Merge: ${code.label}`;
    document.body.appendChild(ghost);
    e.dataTransfer.setDragImage(ghost, 0, 0);
    setTimeout(() => document.body.removeChild(ghost), 0);
  };

  const handleDragEnd = () => {
    setDragType(null);
    setIsDraggingOverCode(null);
    setIsDraggingOverPlus(null);
    setIsDraggingOverNew(false);
  };

  const handleDropOnCode = (e: React.DragEvent, targetCode: Code) => {
    e.preventDefault();
    const type = dragType;
    handleDragEnd();

    // Case 1: Dropping a text segment to code it
    const segmentDataStr = e.dataTransfer.getData('application/quilta-selection');
    if (segmentDataStr) {
      try {
        const data = JSON.parse(segmentDataStr);
        applyCode(targetCode.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${targetCode.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
        return;
      } catch (err) { /* ignore */ }
    }

    // Case 2: Dropping a code to merge it
    const codeDataStr = e.dataTransfer.getData('application/quilta-code');
    if (codeDataStr) {
      try {
        const data = JSON.parse(codeDataStr);
        if (data.codeId === targetCode.id) return; // Can't merge with self

        const sourceCode = codes.find(c => c.id === data.codeId);
        if (sourceCode) {
          setMergeConfirmation({ source: sourceCode, target: targetCode });
        }
      } catch (err) { /* ignore */ }
    }
  };

  const finalizeMerge = () => {
    if (!mergeConfirmation) return;
    const { source, target } = mergeConfirmation;
    dbService.mergeCodes(source.id, target.id);
    refreshCodes();
    setMergeConfirmation(null);
    showToast.success(`Merged "${source.label}" into "${target.label}"`);
  };

  const handleDropToCreateSub = (e: React.DragEvent, parentCode: Code) => {
    e.preventDefault();
    e.stopPropagation();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(parentCode.id);
      setIsModalOpen(true);
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(undefined);
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
      refreshSegments(); // Ensure the UI reflects the edited text and any shifted coding segments
    }
  };

  // Fix: implement missing deleteSentence function to resolve the reference on line 415
  const deleteSentence = (idx: number) => {
    if (interviewId && confirm("Permanently delete this verbatim block? All coding segments for this block will be removed and subsequent ones shifted.")) {
      dbService.deleteSentence(interviewId, idx);
      showToast.success('Block removed');
      setEditingSentenceIdx(null);
      refreshSegments(); // Trigger re-memoization of the interview data
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;

    const isDropTarget = isDraggingOverCode === code.id;
    const isMergeAction = dragType === 'code' && isDropTarget;
    const isCodingAction = dragType === 'segment' && isDropTarget;
    const isPlusTarget = isDraggingOverPlus === code.id;

    return (
      <div key={code.id} className="group/item">
        <div 
          draggable
          onDragStart={(e) => handleCodeDragStart(e, code)}
          onDragEnd={handleDragEnd}
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-3 rounded-xl border-2 transition-all cursor-pointer relative ${
            isMergeAction 
              ? 'border-terracotta border-dashed bg-terracotta/5 scale-[1.05] shadow-xl z-20 animate-pulse' 
              : isCodingAction
                ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10'
                : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          {isMergeAction && (
             <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-terracotta text-white text-[9px] px-2 py-0.5 rounded-full font-bold uppercase shadow-lg">Merge Target</div>
          )}

          <div className="flex items-center gap-2 flex-1 min-w-0">
            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            {/* Sub-code Creation Target - Hide during code merging */}
            {level === 0 && dragType !== 'code' && (
              <div 
                onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDraggingOverPlus(code.id); }}
                onDragLeave={() => setIsDraggingOverPlus(null)}
                onDrop={(e) => handleDropToCreateSub(e, code)}
                className={`p-1.5 rounded-md transition-all ${
                  isPlusTarget ? 'bg-terracotta text-white scale-125' : 'text-slate/20 hover:text-terracotta'
                }`}
                title="Drop selection to create sub-concept"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
              </div>
            )}

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleSegmentDragStart(e, idx)}
                      onDragEnd={handleDragEnd}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign or create code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta">
                {isDraggingOverNew ? 'Drop to Create' : 'New Concept'}
              </p>
            </div>

            <button 
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              Manage Taxonomy
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => { setIsModalOpen(false); setPreSelectedParentId(undefined); }}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : (selectedText || "New segment")}
        existingCodes={codes}
        onApply={onApply}
        initialParentId={preSelectedParentId}
        onCreateAndApply={(l, c, iv, pid) => {
          const newCode = addCode(l, c, iv, pid);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      {mergeConfirmation && (
        <ConfirmDialog
          isOpen={!!mergeConfirmation}
          title="Merge Research Concepts?"
          message={`Are you sure you want to merge "${mergeConfirmation.source.label}" into "${mergeConfirmation.target.label}"? All segments currently assigned to "${mergeConfirmation.source.label}" will be permanently reassigned to "${mergeConfirmation.target.label}". This operation is irreversible.`}
          confirmText="Merge Concepts"
          onConfirm={finalizeMerge}
          onCancel={() => setMergeConfirmation(null)}
          variant="warning"
        />
      )}

      <ConfirmDialog
        isOpen={showHelp}
        title="Researcher's Manual: Drag & Drop"
        message="HIGHLIGHT: Select text in transcript. HANDLE: Drag selection onto a code to assign. MERGE: Drag one code over another in the sidebar to combine them. SUB-CODE: Drop selection onto the '+' icon next to any parent code."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

import { Project, Interview, Code, CodedSegment, Profile, TranscriptSentence } from '../types';

const STORAGE_KEYS = {
  USER: 'quilta_user',
  PROJECTS: 'quilta_projects',
  INTERVIEWS: 'quilta_interviews',
  CODES: 'quilta_codes',
  CODED_SEGMENTS: 'quilta_coded_segments'
};

const get = <T,>(key: string, defaultValue: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultValue;
};

const set = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const dbService = {
  // Auth
  getCurrentUser: (): Profile | null => get(STORAGE_KEYS.USER, null),
  login: (email: string): Profile => {
    const user = { id: 'u1', email, full_name: 'Research Student' };
    set(STORAGE_KEYS.USER, user);
    return user;
  },
  logout: () => localStorage.removeItem(STORAGE_KEYS.USER),

  // Projects
  getProjects: (): Project[] => get(STORAGE_KEYS.PROJECTS, []),
  createProject: (title: string, description: string): Project => {
    const user = dbService.getCurrentUser();
    const projects = dbService.getProjects();
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      description,
      owner_id: user?.id || 'anon',
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.PROJECTS, [...projects, newProject]);
    return newProject;
  },
  updateProject: (id: string, title: string, description: string): Project => {
    const projects = dbService.getProjects();
    const index = projects.findIndex(p => p.id === id);
    if (index === -1) throw new Error("Project not found");
    const updatedProject = { ...projects[index], title, description };
    projects[index] = updatedProject;
    set(STORAGE_KEYS.PROJECTS, projects);
    return updatedProject;
  },

  // Interviews
  getInterviews: (projectId: string): Interview[] => 
    get(STORAGE_KEYS.INTERVIEWS, []).filter((i: Interview) => i.project_id === projectId),
  createInterview: (projectId: string, title: string, sentences: TranscriptSentence[]): Interview => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const newInterview: Interview = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      title,
      transcript: sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n'),
      sentences,
      created_at: new Date().toISOString()
    };
    set(STORAGE_KEYS.INTERVIEWS, [...interviews, newInterview]);
    return newInterview;
  },
  getInterviewById: (id: string): Interview | undefined => 
    get(STORAGE_KEYS.INTERVIEWS, []).find((i: Interview) => i.id === id),

  updateSpeakerLabel: (interviewId: string, oldLabel: string, newLabel: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview) {
      interview.sentences = interview.sentences.map(s => 
        s.speaker === oldLabel ? { ...s, speaker: newLabel } : s
      );
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  updateSentence: (interviewId: string, index: number, updates: Partial<TranscriptSentence>): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interview = interviews.find((i: Interview) => i.id === interviewId);
    if (interview && interview.sentences[index]) {
      interview.sentences[index] = { ...interview.sentences[index], ...updates };
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);
    }
  },

  deleteSentence: (interviewId: string, index: number): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    const interviewIndex = interviews.findIndex((i: Interview) => i.id === interviewId);
    if (interviewIndex !== -1) {
      const interview = interviews[interviewIndex];
      interview.sentences.splice(index, 1);
      interview.transcript = interview.sentences.map(s => `[${s.speaker}] ${s.text}`).join('\n');
      set(STORAGE_KEYS.INTERVIEWS, interviews);

      // Cascading shifts for coded segments
      const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
      const filteredSegments = segments.filter(s => !(s.interview_id === interviewId && s.sentence_index === index));
      const shiftedSegments = filteredSegments.map(s => {
        if (s.interview_id === interviewId && s.sentence_index > index) {
          return { ...s, sentence_index: s.sentence_index - 1 };
        }
        return s;
      });
      set(STORAGE_KEYS.CODED_SEGMENTS, shiftedSegments);
    }
  },

  deleteInterview: (id: string): void => {
    const interviews = get(STORAGE_KEYS.INTERVIEWS, []);
    set(STORAGE_KEYS.INTERVIEWS, interviews.filter((i: Interview) => i.id !== id));
    // Also delete associated coded segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.interview_id !== id));
  },

  // Codes
  getCodes: (projectId: string): Code[] => 
    get(STORAGE_KEYS.CODES, []).filter((c: Code) => c.project_id === projectId),
  createCode: (projectId: string, label: string, color: string, description?: string, isInVivo?: boolean, parentId?: string): Code => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const newCode: Code = {
      id: Math.random().toString(36).substr(2, 9),
      project_id: projectId,
      label,
      color,
      description,
      is_invivo: isInVivo,
      parent_id: parentId,
      created_by: dbService.getCurrentUser()?.id || 'anon'
    };
    set(STORAGE_KEYS.CODES, [...codes, newCode]);
    return newCode;
  },
  updateCode: (id: string, updates: Partial<Code>): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    const index = codes.findIndex(c => c.id === id);
    if (index !== -1) {
      codes[index] = { ...codes[index], ...updates };
      set(STORAGE_KEYS.CODES, codes);
    }
  },
  deleteCode: (codeId: string): void => {
    const codes = get(STORAGE_KEYS.CODES, []);
    // Cascade delete sub-codes
    const codesWithSubDeleted = codes.filter(c => c.id !== codeId && c.parent_id !== codeId);
    set(STORAGE_KEYS.CODES, codesWithSubDeleted);
    // Cascade delete segments
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.code_id !== codeId));
  },

  mergeCodes: (sourceId: string, targetId: string): void => {
    if (sourceId === targetId) return;

    const codes = get(STORAGE_KEYS.CODES, []);
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const sourceCode = codes.find(c => c.id === sourceId);
    const targetCode = codes.find(c => c.id === targetId);
    if (!sourceCode || !targetCode) return;

    // 1. Reassign all segments from source to target
    const updatedSegments = segments.map(s => 
      s.code_id === sourceId ? { ...s, code_id: targetId } : s
    );
    set(STORAGE_KEYS.CODED_SEGMENTS, updatedSegments);

    // 2. Reparent any sub-codes of the source to the target
    const updatedCodes = codes.map(c => {
      if (c.parent_id === sourceId) {
        // Prevent loop if target was a child of source
        if (c.id === targetId) return { ...c, parent_id: sourceCode.parent_id };
        return { ...c, parent_id: targetId };
      }
      return c;
    });

    // 3. Delete the source code
    const finalCodes = updatedCodes.filter(c => c.id !== sourceId);
    set(STORAGE_KEYS.CODES, finalCodes);
  },

  // Coded Segments
  getCodedSegments: (interviewId: string): CodedSegment[] => 
    get(STORAGE_KEYS.CODED_SEGMENTS, []).filter((s: CodedSegment) => s.interview_id === interviewId),
  saveCodedSegment: (segment: Omit<CodedSegment, 'id'>): CodedSegment => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    const newSegment: CodedSegment = {
      ...segment,
      id: Math.random().toString(36).substr(2, 9),
    };
    set(STORAGE_KEYS.CODED_SEGMENTS, [...segments, newSegment]);
    return newSegment;
  },
  deleteCodedSegment: (id: string): void => {
    const segments = get(STORAGE_KEYS.CODED_SEGMENTS, []);
    set(STORAGE_KEYS.CODED_SEGMENTS, segments.filter((s: CodedSegment) => s.id !== id));
  }
};

import React, { useState, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useCoding } from '../hooks/useCoding';
import { dbService } from '../../../services/dbService';
import { GranularHighlighter } from './GranularHighlighter';
import CodeSelectionModal from './CodeSelectionModal';
import { Code } from '../../../types';
import { useKeyboardShortcuts } from '../../../hooks/useKeyboardShortcuts';
import ConfirmDialog from '../../../shared/components/ConfirmDialog';
import { showToast } from '../../../lib/toast';
import { CODE_COLORS } from '../../../constants';

const CodingView: React.FC = () => {
  const { projectId, interviewId } = useParams();
  const navigate = useNavigate();
  const { codes, segments, addCode, deleteCode, applyCode, removeSegment, refreshCodes, refreshSegments } = useCoding(projectId, interviewId);

  const interview = useMemo(() => interviewId ? dbService.getInterviewById(interviewId) : null, [interviewId, segments]);

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [selectedText, setSelectedText] = useState<string>("");
  const [offsets, setOffsets] = useState<{start: number, end: number} | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [floatingMenuPos, setFloatingMenuPos] = useState<{ x: number, y: number } | null>(null);
  const [multiSelect, setMultiSelect] = useState<number[]>([]);
  const [showHelp, setShowHelp] = useState(false);

  // Drag-and-Drop State
  const [dragType, setDragType] = useState<'segment' | 'code' | null>(null);
  const [isDraggingOverCode, setIsDraggingOverCode] = useState<string | null>(null);
  const [isDraggingOverPlus, setIsDraggingOverPlus] = useState<string | null>(null);
  const [isDraggingOverNew, setIsDraggingOverNew] = useState(false);

  // Merge state
  const [mergeConfirmation, setMergeConfirmation] = useState<{ source: Code, target: Code } | null>(null);
  const [preSelectedParentId, setPreSelectedParentId] = useState<string | undefined>(undefined);
  const [expandedCodes, setExpandedCodes] = useState<Set<string>>(new Set());

  // Transcript Correction State
  const [editingSentenceIdx, setEditingSentenceIdx] = useState<number | null>(null);
  const [sentenceBuffer, setSentenceBuffer] = useState<string>("");

  useKeyboardShortcuts({
    openCodeModal: () => {
      if (selectedText || multiSelect.length > 0) setIsModalOpen(true);
    },
    closeModal: () => setIsModalOpen(false),
    undo: () => {
      if (segments.length > 0) {
        removeSegment(segments[segments.length - 1].id);
      }
    },
    showHelp: () => setShowHelp(true),
  });

  const codeUsage = useMemo(() => {
    const counts: Record<string, number> = {};
    dbService.getInterviews(projectId || '').forEach(i => {
      dbService.getCodedSegments(i.id).forEach(s => {
        counts[s.code_id] = (counts[s.code_id] || 0) + 1;
      });
    });
    return counts;
  }, [segments, projectId, codes]);

  const rootCodes = useMemo(() => codes.filter(c => !c.parent_id), [codes]);
  const subCodesMap = useMemo(() => {
    const map: Record<string, Code[]> = {};
    codes.filter(c => c.parent_id).forEach(c => {
      if (!map[c.parent_id!]) map[c.parent_id!] = [];
      map[c.parent_id!] = [...(map[c.parent_id!] || []), c];
    });
    return map;
  }, [codes]);

  const onApply = (code: Code) => {
    if (multiSelect.length > 1) {
      multiSelect.forEach(idx => {
        if (interview) {
          applyCode(
            code.id,
            interview.sentences[idx].text,
            idx,
            0,
            interview.sentences[idx].text.length
          );
        }
      });
      showToast.success(`Batch coded ${multiSelect.length} segments`);
    } else if (selectedIdx !== null && offsets) {
      applyCode(code.id, selectedText, selectedIdx, offsets.start, offsets.end);
    }
    setIsModalOpen(false);
    setFloatingMenuPos(null);
    setMultiSelect([]);
    window.getSelection()?.removeAllRanges();
    setSelectedText("");
    setSelectedIdx(null);
    setPreSelectedParentId(undefined);
  };

  const handleSelection = (idx: number) => {
    if (editingSentenceIdx !== null) return;
    const selection = window.getSelection();
    const text = selection?.toString().trim();
    if (selection && text && text.length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();
      setSelectedIdx(idx);
      setSelectedText(text);
      setOffsets({ start: range.startOffset, end: range.endOffset });
      setFloatingMenuPos({ x: rect.left + rect.width / 2, y: rect.top - 10 });
    }
  };

  const handleSegmentDragStart = (e: React.DragEvent, idx: number) => {
    if (!selectedText) return;
    setDragType('segment');
    const data = {
      type: 'segment',
      text: selectedText,
      sentenceIndex: idx,
      start: offsets?.start || 0,
      end: offsets?.end || selectedText.length
    };
    e.dataTransfer.setData('application/quilta-selection', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'copy';

    const dragGhost = document.createElement('div');
    dragGhost.className = "px-4 py-2 bg-terracotta text-white rounded-xl font-bold text-sm shadow-2xl z-[1000]";
    dragGhost.innerText = selectedText.length > 20 ? selectedText.substring(0, 20) + '...' : selectedText;
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 0, 0);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleCodeDragStart = (e: React.DragEvent, code: Code) => {
    setDragType('code');
    const data = {
      type: 'code',
      codeId: code.id
    };
    e.dataTransfer.setData('application/quilta-code', JSON.stringify(data));
    e.dataTransfer.effectAllowed = 'move';

    const ghost = document.createElement('div');
    ghost.className = "px-5 py-3 bg-slate text-white rounded-xl font-bold text-sm shadow-2xl flex items-center gap-2";
    ghost.innerHTML = `<span style="width:12px; height:12px; background:${code.color}; border-radius:100%"></span> Merge: ${code.label}`;
    document.body.appendChild(ghost);
    e.dataTransfer.setDragImage(ghost, 0, 0);
    setTimeout(() => document.body.removeChild(ghost), 0);
  };

  const handleDragEnd = () => {
    setDragType(null);
    setIsDraggingOverCode(null);
    setIsDraggingOverPlus(null);
    setIsDraggingOverNew(false);
  };

  // Helper to check if a code is a child of another to prevent hierarchy loops
  const isChildOf = (parentId: string, childId: string): boolean => {
    let current = codes.find(c => c.id === childId);
    while (current && current.parent_id) {
      if (current.parent_id === parentId) return true;
      current = codes.find(c => c.id === current.parent_id);
    }
    return false;
  };

  const handleDropOnCode = (e: React.DragEvent, targetCode: Code) => {
    e.preventDefault();
    const type = dragType;
    handleDragEnd();

    // Case 1: Dropping a text segment to code it
    const segmentDataStr = e.dataTransfer.getData('application/quilta-selection');
    if (segmentDataStr) {
      try {
        const data = JSON.parse(segmentDataStr);
        applyCode(targetCode.id, data.text, data.sentenceIndex, data.start, data.end);
        showToast.success(`Coded: ${targetCode.label}`);
        window.getSelection()?.removeAllRanges();
        setSelectedText("");
        setSelectedIdx(null);
        return;
      } catch (err) { /* ignore */ }
    }

    // Case 2: Dropping a code to merge it
    const codeDataStr = e.dataTransfer.getData('application/quilta-code');
    if (codeDataStr) {
      try {
        const data = JSON.parse(codeDataStr);
        if (data.codeId === targetCode.id) return; // Can't merge with self

        // Prevent merging a parent into its own child as it breaks the 2-level logic simply
        if (isChildOf(data.codeId, targetCode.id)) {
          showToast.error("Cannot merge a parent concept into its own sub-concept.");
          return;
        }

        const sourceCode = codes.find(c => c.id === data.codeId);
        if (sourceCode) {
          setMergeConfirmation({ source: sourceCode, target: targetCode });
        }
      } catch (err) { /* ignore */ }
    }
  };

  const finalizeMerge = () => {
    if (!mergeConfirmation) return;
    const { source, target } = mergeConfirmation;
    dbService.mergeCodes(source.id, target.id);
    refreshCodes();
    setMergeConfirmation(null);
    showToast.success(`Merged "${source.label}" into "${target.label}"`);
    refreshSegments();
  };

  const handleDropToCreateSub = (e: React.DragEvent, parentCode: Code) => {
    e.preventDefault();
    e.stopPropagation();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(parentCode.id);
      setIsModalOpen(true);
    }
  };

  const handleDropOnNew = (e: React.DragEvent) => {
    e.preventDefault();
    handleDragEnd();
    const dataStr = e.dataTransfer.getData('application/quilta-selection');
    if (dataStr) {
      setPreSelectedParentId(undefined);
      setIsModalOpen(true);
    }
  };

  const startEditingSentence = (idx: number, text: string) => {
    setEditingSentenceIdx(idx);
    setSentenceBuffer(text);
    setSelectedText("");
    setSelectedIdx(null);
  };

  const saveSentenceCorrection = () => {
    if (editingSentenceIdx !== null && interviewId) {
      dbService.updateSentence(interviewId, editingSentenceIdx, { text: sentenceBuffer });
      showToast.success('Transcription updated');
      setEditingSentenceIdx(null);
      refreshSegments();
    }
  };

  const deleteSentence = (idx: number) => {
    if (interviewId && confirm("Permanently delete this verbatim block? All coding segments for this block will be removed and subsequent ones shifted.")) {
      dbService.deleteSentence(interviewId, idx);
      showToast.success('Block removed');
      setEditingSentenceIdx(null);
      refreshSegments();
    }
  };

  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedCodes);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedCodes(newExpanded);
  };

  const renderCodeItem = (code: Code, level: number = 0) => {
    const children = subCodesMap[code.id] || [];
    const isExpanded = expandedCodes.has(code.id);
    const hasChildren = children.length > 0;

    const isDropTarget = isDraggingOverCode === code.id;
    const isMergeAction = dragType === 'code' && isDropTarget;
    const isCodingAction = dragType === 'segment' && isDropTarget;
    const isPlusTarget = isDraggingOverPlus === code.id;

    return (
      <div key={code.id} className="group/item">
        <div 
          draggable
          onDragStart={(e) => handleCodeDragStart(e, code)}
          onDragEnd={handleDragEnd}
          onDragOver={(e) => { e.preventDefault(); setIsDraggingOverCode(code.id); }}
          onDragLeave={() => setIsDraggingOverCode(null)}
          onDrop={(e) => handleDropOnCode(e, code)}
          className={`flex items-center p-3 rounded-xl border-2 transition-all cursor-pointer relative ${
            isMergeAction 
              ? 'border-terracotta border-dashed bg-terracotta/5 scale-[1.05] shadow-xl z-20 animate-pulse' 
              : isCodingAction
                ? 'border-terracotta bg-terracotta/10 scale-[1.02] shadow-lg z-10'
                : 'border-transparent hover:bg-slate/5'
          } ${level > 0 ? 'ml-6' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            if (hasChildren) toggleExpand(code.id);
          }}
        >
          {isMergeAction && (
             <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-terracotta text-white text-[9px] px-2 py-0.5 rounded-full font-bold uppercase shadow-lg z-30">Merge Target</div>
          )}

          <div className="flex items-center gap-2 flex-1 min-w-0">
            {/* Drag Handle for tablet ergonomics */}
            <div className="text-slate/20 group-hover/item:text-slate/40 cursor-grab px-1 select-none">⠿</div>

            {hasChildren ? (
              <div className={`transition-transform duration-200 ${isExpanded ? 'rotate-90' : ''}`}>
                <svg className="w-3 h-3 text-slate/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ) : (
              <div className="w-3" />
            )}

            <div className="w-3.5 h-3.5 rounded-full shadow-inner flex-shrink-0" style={{ backgroundColor: code.color }} />

            <div className="flex-1 truncate">
              <p className={`font-bold text-slate leading-tight ${level > 0 ? 'text-xs' : 'text-sm'}`}>
                {code.label}
              </p>
            </div>

            {/* Sub-code Creation Target - Hide during code merging */}
            {level === 0 && dragType !== 'code' && (
              <div 
                onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDraggingOverPlus(code.id); }}
                onDragLeave={() => setIsDraggingOverPlus(null)}
                onDrop={(e) => handleDropToCreateSub(e, code)}
                className={`p-1.5 rounded-md transition-all ${
                  isPlusTarget ? 'bg-terracotta text-white scale-125' : 'text-slate/20 hover:text-terracotta'
                }`}
                title="Drop selection to create sub-concept"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
              </div>
            )}

            <span className="text-[9px] text-slate/40 font-bold px-1.5 py-0.5 bg-white rounded border border-slate/5 group-hover/item:border-slate/20 transition-colors">
              {codeUsage[code.id] || 0}
            </span>
          </div>
        </div>

        {isExpanded && hasChildren && (
          <div className="mt-1 space-y-1 relative">
            <div className="absolute left-4 top-0 bottom-2 w-px bg-slate/10" />
            {children.map(sub => renderCodeItem(sub, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-screen flex flex-col bg-cream overflow-hidden">
      <header className="bg-white border-b px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-slate">Coding Studio</h1>
          <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold truncate max-w-[250px]">{interview.title}</p>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setShowHelp(true)} className="p-2 text-slate/20 hover:text-slate transition-colors" title="Researcher's Manual">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button onClick={() => navigate(`/projects/${projectId}/interviews/${interviewId}`)} className="px-8 py-3 bg-slate text-white rounded-xl font-bold shadow-md hover:scale-105 active:scale-95 transition-all">Finish Coding</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Transcript Area */}
        <div className="flex-1 overflow-y-auto p-12 flex flex-col items-center relative select-text">
          <div className="max-w-4xl w-full space-y-12 pb-60 select-text">
            {interview.sentences.map((s, idx) => {
              const sentenceSegments = segments.filter(seg => seg.sentence_index === idx);
              const isMultiSelected = multiSelect.includes(idx);
              const isSelectionActive = selectedIdx === idx && selectedText;
              const isEditing = editingSentenceIdx === idx;

              return (
                <div 
                  key={idx} 
                  onMouseUp={() => handleSelection(idx)} 
                  className={`group relative p-4 -m-4 rounded-2xl transition-all flex gap-6 select-text ${isMultiSelected ? 'bg-terracotta/5 border-2 border-terracotta/20 ring-4 ring-terracotta/5' : 'hover:bg-slate/5 border-2 border-transparent'}`}
                >
                  {/* Quilt Handle */}
                  {isSelectionActive && !isEditing && (
                    <div 
                      draggable
                      onDragStart={(e) => handleSegmentDragStart(e, idx)}
                      onDragEnd={handleDragEnd}
                      onMouseDown={(e) => e.stopPropagation()}
                      className="absolute -left-12 top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing p-3 bg-terracotta text-white rounded-xl shadow-2xl z-50 animate-bounce flex items-center justify-center border-2 border-white"
                      title="Drag to sidebar to assign or create code"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l4-4 4 4m0 6l-4 4-4-4" />
                      </svg>
                    </div>
                  )}

                  <div className="flex flex-col items-end w-20 shrink-0 mt-1 select-none">
                     <span className={`text-[9px] font-bold ${isMultiSelected ? 'text-terracotta' : 'text-slate/20'}`}>#{String(idx + 1).padStart(3, '0')}</span>
                     <div className="flex items-center gap-1">
                        <span className={`text-[9px] font-bold uppercase tracking-tight truncate max-w-[50px] text-right ${isMultiSelected ? 'text-terracotta' : 'text-slate/30'}`}>{s.speaker}</span>
                        <button 
                          onClick={() => startEditingSentence(idx, s.text)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate/20 hover:text-terracotta transition-all"
                          title="Correct Verbatim"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                          </svg>
                        </button>
                     </div>
                  </div>

                  <div className="flex-1 select-text">
                    {isEditing ? (
                      <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
                        <textarea 
                          className="w-full p-4 bg-white border-2 border-terracotta rounded-xl font-serif text-2xl leading-relaxed outline-none shadow-inner"
                          value={sentenceBuffer}
                          onChange={(e) => setSentenceBuffer(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) saveSentenceCorrection();
                            if (e.key === 'Escape') setEditingSentenceIdx(null);
                          }}
                          autoFocus
                        />
                        <div className="flex gap-2">
                           <button onClick={saveSentenceCorrection} className="px-4 py-2 bg-terracotta text-white rounded-lg font-bold text-xs shadow-md">Save Changes</button>
                           <button onClick={() => deleteSentence(idx)} className="px-4 py-2 bg-red-50 text-red-500 rounded-lg font-bold text-xs">Delete Block</button>
                           <button onClick={() => setEditingSentenceIdx(null)} className="px-4 py-2 bg-slate/5 text-slate rounded-lg font-bold text-xs">Cancel</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <div className="flex flex-wrap gap-1 mb-2 min-h-[20px] select-none">
                            {sentenceSegments.map(seg => {
                              const code = codes.find(c => c.id === seg.code_id);
                              return code && (
                                <div key={seg.id} className="px-2 py-0.5 rounded text-[8px] font-bold text-white flex items-center gap-1 shadow-sm" style={{ backgroundColor: code.color }}>
                                  {code.label}
                                  <button onClick={(e) => { e.stopPropagation(); removeSegment(seg.id); }} className="hover:scale-125 ml-1 transition-transform">×</button>
                                </div>
                              );
                            })}
                        </div>
                        <div className={`text-2xl leading-relaxed font-serif whitespace-pre-wrap border-l-2 pl-4 transition-colors select-text ${isMultiSelected ? 'text-charcoal font-semibold border-terracotta' : 'text-charcoal/90 border-slate/10'}`}>
                          <GranularHighlighter text={s.text} segments={sentenceSegments} codes={codes} />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Hierarchical Sidebar */}
        <aside className="w-80 bg-white border-l border-slate/10 flex flex-col shadow-2xl z-40">
          <div className="p-6 border-b border-slate/10 bg-slate/5">
            <h2 className="text-lg font-bold text-slate">Codebook</h2>
            <p className="text-[10px] text-slate/40 uppercase tracking-widest font-bold">1. Select text <br/> 2. Drag handle to code or '+'</p>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1">
            {rootCodes.length === 0 ? (
              <div className="py-20 text-center opacity-20">
                <p className="font-bold text-xs uppercase tracking-widest">No concepts</p>
              </div>
            ) : (
              rootCodes.map(code => renderCodeItem(code))
            )}
          </div>

          <div className="p-4 bg-slate/5 border-t border-slate/10 space-y-3">
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverNew(true); }}
              onDragLeave={() => setIsDraggingOverNew(false)}
              onDrop={handleDropOnNew}
              className={`p-4 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center gap-2 transition-all cursor-pointer group ${
                isDraggingOverNew 
                  ? 'border-terracotta bg-terracotta/10 scale-[1.05] shadow-xl' 
                  : 'border-slate/10 bg-white hover:border-terracotta/30'
              }`}
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
            >
              <div className="w-10 h-10 rounded-full bg-slate/5 flex items-center justify-center text-slate/30 group-hover:text-terracotta transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <p className="text-[10px] font-bold text-slate/40 uppercase tracking-widest group-hover:text-terracotta text-center leading-tight">
                {isDraggingOverNew ? 'Drop to Create' : 'Add Root concept'}
              </p>
            </div>

            <button 
              onClick={() => { setPreSelectedParentId(undefined); setIsModalOpen(true); }}
              className="w-full py-4 bg-slate text-white rounded-xl font-bold text-xs shadow-md hover:bg-slate/90 transition-all flex items-center justify-center gap-2"
            >
              Manage Taxonomy
            </button>
          </div>
        </aside>
      </div>

      {(floatingMenuPos || multiSelect.length > 0) && (
        <div className="fixed z-[60] -translate-x-1/2 bottom-12 left-[40%]">
          <button 
            onClick={() => setIsModalOpen(true)} 
            className="px-10 py-5 bg-slate text-white rounded-full font-bold shadow-2xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"
          >
            Assign Code
          </button>
        </div>
      )}

      <CodeSelectionModal 
        isOpen={isModalOpen}
        onClose={() => { setIsModalOpen(false); setPreSelectedParentId(undefined); }}
        selectedSnippet={multiSelect.length > 1 ? `Multiple segments (${multiSelect.length})` : (selectedText || "New segment")}
        existingCodes={codes}
        onApply={onApply}
        initialParentId={preSelectedParentId}
        onCreateAndApply={(l, c, iv, pid) => {
          const newCode = addCode(l, c, iv, pid);
          if (newCode) onApply(newCode);
        }}
        onDeleteCode={deleteCode}
        codeUsageCounts={codeUsage}
      />

      {mergeConfirmation && (
        <ConfirmDialog
          isOpen={!!mergeConfirmation}
          title="Merge Research Concepts?"
          message={`Are you sure you want to merge "${mergeConfirmation.source.label}" into "${mergeConfirmation.target.label}"? All coded segments and sub-concepts will be permanently reassigned to "${mergeConfirmation.target.label}". This operation is irreversible.`}
          confirmText="Merge Concepts"
          onConfirm={finalizeMerge}
          onCancel={() => setMergeConfirmation(null)}
          variant="warning"
        />
      )}

      <ConfirmDialog
        isOpen={showHelp}
        title="Researcher's Manual: Drag & Drop"
        message="HIGHLIGHT: Select text in transcript. HANDLE: Drag selection onto a code to assign. MERGE: Drag the ⠿ handle of one code over another to combine them. SUB-CODE: Drop selection onto the '+' next to a code."
        confirmText="Got it"
        onConfirm={() => setShowHelp(false)}
        onCancel={() => setShowHelp(false)}
        variant="info"
      />
    </div>
  );
};

export default CodingView;

